  function closeEspLessonDetail() {
    if (activeEspLessonMode === "learning-center") {
      const targetView = String(activeLearningCenterLessonReturnTarget?.view || "online-course").trim();
      const returnScrollY = Math.max(0, Number(activeLearningCenterLessonReturnTarget.scrollY || 0) || 0);
      const returnFocusId = String(activeLearningCenterLessonReturnTarget.focusId || "").trim();
      activeEspLessonMode = "role";
      activeLearningCenterLessonId = "";
      activeLearningCenterLessonReturnTarget = { view: "online-course", scrollY: 0, focusId: "" };
      espLessonDetailView?.classList.add("beginner-view-hidden");
      pendingOnlineCourseRestoreFocusId = returnFocusId;
      showOnlineCourseView({
        view: targetView || "online-course",
        role: "",
        scrollY: returnScrollY
      });
      return;
    }
    const returnRole = activeEspLessonRole;
    const returnScrollY = activeEspLessonReturnScrollY;
    activeEspLessonRole = "";
    activeEspLessonReturnScrollY = 0;
    espLessonDetailView?.classList.add("beginner-view-hidden");
    if (returnRole === "remote-viewer") {
      showClairvoyanceViewingView();
    } else {
      showLauncherView();
    }
    if (!returnRole) {
      return;
    }
    window.setTimeout(() => {
      const matchingCard = roleCards.find((card) => String(card.dataset.roleCard || "") === returnRole);
      if (!matchingCard) {
        return;
      }
      ensureCardExpanded(matchingCard, { scrollIntoView: false });
      window.scrollTo({ top: returnScrollY, behavior: "auto" });
    }, 80);
  }

  async function refreshRoleEspLesson(role, options = {}) {
    const normalizedRole = String(role || "").trim();
    if (!normalizedRole) {
      return;
    }
    if (isRoleMessageAreaVisible(normalizedRole)) {
      clearRoleLessonDisplay(normalizedRole);
      return;
    }
    if (!shouldShowEspLessonForRole(normalizedRole)) {
      clearRoleLessonDisplay(normalizedRole);
      return;
    }

    const lessons = getEspLessonsForRole(normalizedRole, readLauncherState());
    if (!lessons.length) {
      clearRoleLessonDisplay(normalizedRole);
      return;
    }

    const ownIdentifier = getRoleIdentifiersForMessaging(normalizedRole).ownIdentifier;
    if (!ownIdentifier) {
      clearRoleLessonDisplay(normalizedRole);
      return;
    }

    const targetSessionId = Number(options.sessionId || getRoleLessonSessionId(normalizedRole) || 0);
    const shouldForceFetch = options.forceFetch === true;
    const shouldAutoAdvanceOnEntry = options.autoAdvanceOnEntry === true;
    const existingRuntime = getCurrentRoleLesson(normalizedRole);
    if (
      !shouldForceFetch &&
      existingRuntime &&
      existingRuntime.identifier === ownIdentifier &&
      Number(existingRuntime.sessionId || 0) === targetSessionId &&
      existingRuntime.lesson
    ) {
      const preview = existingRuntime.preview || buildEspLessonPreview(existingRuntime.lesson.body || "");
      roleLessonRuntimeState[normalizedRole] = {
        ...existingRuntime,
        preview
      };
      await transitionRoleLessonContent(normalizedRole, existingRuntime.lesson.title || "", preview.preview || existingRuntime.lesson.body || "");
      updateRoleLessonBackButton(normalizedRole);
      return;
    }

    if (
      shouldAutoAdvanceOnEntry &&
      !shouldForceFetch &&
      existingRuntime &&
      existingRuntime.identifier === ownIdentifier &&
      Number(existingRuntime.sessionId || 0) !== targetSessionId
    ) {
      const queuedLessonId = String(existingRuntime.lessonState?.current_lesson_id || "").trim();
      const queuedLesson = queuedLessonId ? lessons.find((item) => item.id === queuedLessonId) || null : null;
      if (queuedLesson) {
        const preview = buildEspLessonPreview(queuedLesson.body);
        roleLessonRuntimeState[normalizedRole] = {
          sessionId: targetSessionId,
          identifier: ownIdentifier,
          lessonIds: lessons.map((item) => item.id),
          lessonState: existingRuntime.lessonState,
          lesson: queuedLesson,
          preview,
          history: []
        };
        await transitionRoleLessonContent(normalizedRole, queuedLesson.title || "", preview.preview || queuedLesson.body || "");
        updateRoleLessonBackButton(normalizedRole);
        try {
          const nextState = await advanceEspLessonState(ownIdentifier, lessons.map((item) => item.id), "next", queuedLesson.id);
          const currentRuntime = getCurrentRoleLesson(normalizedRole);
          if (currentRuntime && currentRuntime.identifier === ownIdentifier && Number(currentRuntime.sessionId || 0) === targetSessionId) {
            roleLessonRuntimeState[normalizedRole] = {
              ...currentRuntime,
              lessonState: nextState
            };
          }
        } catch (_) {
          // Keep the displayed lesson stable even if the advance fails.
        }
        return;
      }
    }

    try {
      const lessonState = await fetchEspLessonState(ownIdentifier, lessons.map((lesson) => lesson.id));
      const lessonId = String(lessonState?.current_lesson_id || "").trim();
      const lesson = lessons.find((item) => item.id === lessonId) || null;
      if (!lesson) {
        clearRoleLessonDisplay(normalizedRole);
        return;
      }
      const preview = buildEspLessonPreview(lesson.body);
      const preservedHistory = existingRuntime &&
        existingRuntime.identifier === ownIdentifier &&
        Number(existingRuntime.sessionId || 0) === targetSessionId &&
        Array.isArray(existingRuntime.history)
        ? existingRuntime.history
        : [];
      roleLessonRuntimeState[normalizedRole] = {
        sessionId: targetSessionId,
        identifier: ownIdentifier,
        lessonIds: lessons.map((item) => item.id),
        lessonState,
        lesson,
        preview,
        history: preservedHistory
      };
      await transitionRoleLessonContent(normalizedRole, lesson.title || "", preview.preview || lesson.body || "");
      updateRoleLessonBackButton(normalizedRole);
      if (shouldAutoAdvanceOnEntry) {
        try {
          const nextState = await advanceEspLessonState(ownIdentifier, lessons.map((item) => item.id), "next", lesson.id);
          const currentRuntime = getCurrentRoleLesson(normalizedRole);
          if (currentRuntime && currentRuntime.identifier === ownIdentifier && Number(currentRuntime.sessionId || 0) === targetSessionId) {
            roleLessonRuntimeState[normalizedRole] = {
              ...currentRuntime,
              lessonState: nextState
            };
          }
        } catch (_) {
          // Keep the displayed lesson stable even if the advance fails.
        }
      }
    } catch (error) {
      clearRoleLessonDisplay(normalizedRole);
    }
  }

  async function advanceRoleEspLesson(role, command, options = {}) {
    const lessonRuntime = getCurrentRoleLesson(role);
    if (!lessonRuntime?.identifier || !Array.isArray(lessonRuntime.lessonIds) || !lessonRuntime.lesson?.id) {
      return;
    }

    try {
      const priorLesson = lessonRuntime.lesson
        ? {
            id: String(lessonRuntime.lesson.id || "").trim(),
            title: String(lessonRuntime.lesson.title || "").trim(),
            body: String(lessonRuntime.lesson.body || "")
          }
        : null;
      const nextState = await advanceEspLessonState(
        lessonRuntime.identifier,
        lessonRuntime.lessonIds,
        command,
        lessonRuntime.lesson.id
      );
      roleLessonRuntimeState[role] = {
        ...lessonRuntime,
        lessonState: nextState,
        history: priorLesson?.id
          ? [...(Array.isArray(lessonRuntime.history) ? lessonRuntime.history : []), priorLesson]
          : (Array.isArray(lessonRuntime.history) ? lessonRuntime.history : [])
      };
      await refreshRoleEspLesson(role, {
        forceFetch: true,
        sessionId: Number(lessonRuntime.sessionId || getRoleLessonSessionId(role) || 0)
      });
      if (options.keepDetailOpen) {
        if (getCurrentRoleLesson(role)) {
          renderEspLessonDetail(role);
        } else {
          closeEspLessonDetail();
        }
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unable to update this ESP lesson right now.";
      if (options.keepDetailOpen) {
        setEspLessonDetailStatus(message, { isError: true });
      }
    }
  }

  function clearLauncherStoredLocation(state, permissionValue = state?.locationPermission || "") {
    const next = state && typeof state === "object" ? state : readLauncherState();
    next.deviceLocation = null;
    next.locationFineTuneDismissedForTimestamp = 0;
    next.locationPermission = String(permissionValue || "").trim();
    return next;
  }

  function getLocationForRuntimeState(state = readLauncherState()) {
    const location = getSavedDeviceLocation(state);
    return location ? JSON.stringify(location) : "";
  }

  function clamp(value, min, max) {
    return Math.min(max, Math.max(min, value));
  }

  function normalizeThemeHex(value) {
    const match = String(value || "").trim().match(/^#?([0-9a-f]{6})$/i);
    return match ? `#${match[1].toLowerCase()}` : defaultThemeColor;
  }

  function hexToRgb(hex) {
    const normalized = normalizeThemeHex(hex).slice(1);
    return {
      r: parseInt(normalized.slice(0, 2), 16),
      g: parseInt(normalized.slice(2, 4), 16),
      b: parseInt(normalized.slice(4, 6), 16)
    };
  }

  function rgbToHex(r, g, b) {
    return `#${[r, g, b].map((value) => clamp(Math.round(value), 0, 255).toString(16).padStart(2, "0")).join("")}`;
  }

  function rgbToHsl(r, g, b) {
    const red = r / 255;
    const green = g / 255;
    const blue = b / 255;
    const max = Math.max(red, green, blue);
    const min = Math.min(red, green, blue);
    let h;
    let s;
    const l = (max + min) / 2;

    if (max === min) {
      h = 0;
      s = 0;
    } else {
      const d = max - min;
      s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
      switch (max) {
        case red:
          h = (green - blue) / d + (green < blue ? 6 : 0);
          break;
        case green:
          h = (blue - red) / d + 2;
          break;
        default:
          h = (red - green) / d + 4;
          break;
      }
      h /= 6;
    }

    return { h, s, l };
  }

  function hslToRgb(h, s, l) {
    if (s === 0) {
      const gray = Math.round(l * 255);
      return { r: gray, g: gray, b: gray };
    }

    const hue2rgb = (p, q, t) => {
      let next = t;
      if (next < 0) next += 1;
      if (next > 1) next -= 1;
      if (next < 1 / 6) return p + (q - p) * 6 * next;
      if (next < 1 / 2) return q;
      if (next < 2 / 3) return p + (q - p) * (2 / 3 - next) * 6;
      return p;
    };

    const q = l < 0.5 ? l * (1 + s) : l + s - l * s;
    const p = 2 * l - q;

    return {
      r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
      g: Math.round(hue2rgb(p, q, h) * 255),
      b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255)
    };
  }

  function adjustThemeColor(hex, { hueShift = 0, saturationScale = 1, lightnessDelta = 0, alpha = 1 } = {}) {
    const { r, g, b } = hexToRgb(hex);
    const hsl = rgbToHsl(r, g, b);
    const shiftedHue = (hsl.h + hueShift + 1) % 1;
    const scaledSaturation = clamp(hsl.s * saturationScale, 0, 1);
    const shiftedLightness = clamp(hsl.l + lightnessDelta, 0, 1);
    const rgb = hslToRgb(shiftedHue, scaledSaturation, shiftedLightness);
    return alpha >= 1
      ? rgbToHex(rgb.r, rgb.g, rgb.b)
      : `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${alpha})`;
  }

  function applyThemeColor(themeHex) {
    const rootStyle = document.documentElement.style;
    const color = normalizeThemeHex(themeHex);
    rootStyle.setProperty("--brand-base", color);
    rootStyle.setProperty("--brand-top", adjustThemeColor(color, { lightnessDelta: 0.1 }));
    rootStyle.setProperty("--brand-bottom", adjustThemeColor(color, { lightnessDelta: -0.06 }));
    rootStyle.setProperty("--brand-top-hover", adjustThemeColor(color, { lightnessDelta: 0.16 }));
    rootStyle.setProperty("--brand-bottom-hover", adjustThemeColor(color, { lightnessDelta: -0.01 }));
    rootStyle.setProperty("--brand-border", adjustThemeColor(color, { lightnessDelta: 0.18, alpha: 0.72 }));
    rootStyle.setProperty("--brand-shadow", adjustThemeColor(color, { lightnessDelta: -0.22, alpha: 0.28 }));
    rootStyle.setProperty("--brand-surface-border", adjustThemeColor(color, { lightnessDelta: 0.12, alpha: 0.82 }));
    rootStyle.setProperty("--brand-surface-top", adjustThemeColor(color, { lightnessDelta: -0.01, alpha: 0.9 }));
    rootStyle.setProperty("--brand-surface-bottom", adjustThemeColor(color, { lightnessDelta: -0.17, alpha: 0.92 }));
    rootStyle.setProperty("--brand-surface-base", adjustThemeColor(color, { lightnessDelta: -0.24, alpha: 0.9 }));
    rootStyle.setProperty("--brand-surface-shadow", adjustThemeColor(color, { lightnessDelta: -0.08, alpha: 0.16 }));
    rootStyle.setProperty("--brand-soft", adjustThemeColor(color, { lightnessDelta: 0.05, alpha: 0.22 }));
    rootStyle.setProperty("--brand-ambient", adjustThemeColor(color, { lightnessDelta: 0.18, alpha: 0.11 }));
    rootStyle.setProperty("--brand-track-top", adjustThemeColor(color, { lightnessDelta: 0.22 }));
    rootStyle.setProperty("--brand-track-bottom", adjustThemeColor(color, { lightnessDelta: 0.05 }));
    rootStyle.setProperty("--brand-thumb", adjustThemeColor(color, { lightnessDelta: 0.2 }));
    rootStyle.setProperty("--brand-focus", adjustThemeColor(color, { lightnessDelta: 0.22, alpha: 0.28 }));
  }

  function persistThemeColor(themeHex) {
    const latest = readLauncherState();
    latest.themeColor = normalizeThemeHex(themeHex);
    writeLauncherState(latest);
    applyThemeColor(latest.themeColor);
    return latest.themeColor;
  }

  function normalizeBlinkSecondsValue(value, fallback) {
    const text = String(value ?? "").trim();
    if (!text) {
      return fallback;
    }
    const numeric = Number(text);
    if (!Number.isFinite(numeric)) {
      return fallback;
    }
    const clamped = clamp(numeric, 0.05, 30);
    return clamped.toFixed(2).replace(/0+$/, "").replace(/\.$/, "");
  }

  function cloneJsonValue(value, fallback) {
    try {
      return JSON.parse(JSON.stringify(value ?? fallback));
    } catch (error) {
      return fallback;
    }
  }

  function snapshotDeviceIdentityState(state = readLauncherState()) {
    return {
      strictRecognizedIdentity: true,
      recognizedIdentity: String(state?.recognizedIdentity || "").trim(),
      ownNames: cloneJsonValue(state?.ownNames || {}, {}),
      visitorDisplayNames: cloneJsonValue(state?.visitorDisplayNames || {}, {}),
      visitorLockedName: String(state?.visitorLockedName || "").trim(),
      entryMode: normalizeLauncherEntryMode(state?.entryMode),
      visitorAlias: String(state?.visitorAlias || "").trim(),
      currentPartners: cloneJsonValue(state?.currentPartners || {}, {}),
      partnerHistory: cloneJsonValue(state?.partnerHistory || {}, {}),
      deletedPartners: cloneJsonValue(state?.deletedPartners || {}, {}),
      launcherProfiles: cloneJsonValue(state?.launcherProfiles || {}, {}),
      roleDifficultyLevels: cloneJsonValue(state?.roleDifficultyLevels || {}, {}),
      robotSimulationDifficultyLevels: cloneJsonValue(state?.robotSimulationDifficultyLevels || {}, {}),
      identifierStatusMap: cloneJsonValue(state?.identifierStatusMap || {}, {}),
      resolvedMainUserType: String(state?.resolvedMainUserType || "").trim().toLowerCase() === "pro" ? "pro" : "standard",
      loadedInviteeIdentity: cloneJsonValue(state?.loadedInviteeIdentity || null, null),
      pendingInviteeOnboarding: cloneJsonValue(state?.pendingInviteeOnboarding || null, null),
      exploreTrial: cloneJsonValue(state?.exploreTrial || null, null),
      temporaryIdentity: cloneJsonValue(state?.temporaryIdentity || null, null),
      remoteViewerDisplayDevice: !!state?.remoteViewerDisplayDevice,
      difficultyLevel: normalizeDifficultyLevel(state?.difficultyLevel || "1"),
      includeConfidence: typeof state?.includeConfidence === "boolean" ? state.includeConfidence : defaultConfidenceSettings.include,
      includePositiveReinforcement: typeof state?.includePositiveReinforcement === "boolean"
        ? state.includePositiveReinforcement
        : defaultConfidenceSettings.includePositiveReinforcement,
      runtimeSettings: {
        sender: cloneJsonValue(readRuntimeSettings("sender"), {}),
        receiver: cloneJsonValue(readRuntimeSettings("receiver"), {}),
        "remote-viewer": cloneJsonValue(readRuntimeSettings("remote-viewer"), {})
      }
    };
  }

  function restoreDeviceIdentitySnapshot(snapshot, baseState = readLauncherState()) {
    const source = snapshot && typeof snapshot === "object" ? snapshot : {};
    return {
      ...baseState,
      strictRecognizedIdentity: !!source.strictRecognizedIdentity,
      recognizedIdentity: String(source.recognizedIdentity || "").trim(),
      ownNames: cloneJsonValue(source.ownNames || {}, {}),
      visitorDisplayNames: cloneJsonValue(source.visitorDisplayNames || {}, {}),
      visitorLockedName: String(source.visitorLockedName || "").trim(),
      entryMode: normalizeLauncherEntryMode(source.entryMode),
      visitorAlias: String(source.visitorAlias || "").trim(),
      currentPartners: cloneJsonValue(source.currentPartners || {}, {}),
      partnerHistory: cloneJsonValue(source.partnerHistory || {}, {}),
      deletedPartners: cloneJsonValue(source.deletedPartners || {}, {}),
      launcherProfiles: cloneJsonValue(source.launcherProfiles || {}, {}),
      roleDifficultyLevels: cloneJsonValue(source.roleDifficultyLevels || {}, {}),
      robotSimulationDifficultyLevels: cloneJsonValue(source.robotSimulationDifficultyLevels || {}, {}),
      identifierStatusMap: cloneJsonValue(source.identifierStatusMap || {}, {}),
      resolvedMainUserType: String(source.resolvedMainUserType || "").trim().toLowerCase() === "pro" ? "pro" : "standard",
      loadedInviteeIdentity: cloneJsonValue(source.loadedInviteeIdentity || null, null),
      pendingInviteeOnboarding: cloneJsonValue(source.pendingInviteeOnboarding || null, null),
      exploreTrial: cloneJsonValue(source.exploreTrial || null, null),
      temporaryIdentity: cloneJsonValue(source.temporaryIdentity || null, null),
      remoteViewerDisplayDevice: !!source.remoteViewerDisplayDevice,
      difficultyLevel: normalizeDifficultyLevel(source.difficultyLevel || "1"),
      includeConfidence: typeof source?.includeConfidence === "boolean" ? source.includeConfidence : defaultConfidenceSettings.include,
      includePositiveReinforcement: typeof source?.includePositiveReinforcement === "boolean"
        ? source.includePositiveReinforcement
        : defaultConfidenceSettings.includePositiveReinforcement,
      deviceTestMode: null
    };
  }

  function describeRestoreSnapshotIdentity(snapshot) {
    const source = snapshot && typeof snapshot === "object" ? snapshot : {};
    const loadedInvitee = source.loadedInviteeIdentity && typeof source.loadedInviteeIdentity === "object"
      ? source.loadedInviteeIdentity
      : null;
    const temporaryIdentity = source.temporaryIdentity && typeof source.temporaryIdentity === "object"
      ? source.temporaryIdentity
      : null;
    const recognizedIdentity = String(source.recognizedIdentity || "").trim();

    if (loadedInvitee?.identifier) {
      const inviteeType = String(loadedInvitee.userType || "").trim().toLowerCase() === "pro" ? "PRO" : "STD";
      return `loaded invitee ${String(loadedInvitee.identifier || "").trim()} (${inviteeType})`;
    }
    if (recognizedIdentity) {
      return `recognized user ${recognizedIdentity}`;
    }
    if (temporaryIdentity?.identifier) {
      return `temporary identity ${String(temporaryIdentity.identifier || "").trim()}`;
    }

    const ownNames = source.ownNames && typeof source.ownNames === "object" ? source.ownNames : {};
    const visibleOwnNames = uniqueNames([
      String(ownNames.sender || "").trim(),
      String(ownNames.receiver || "").trim(),
      String(ownNames["remote-viewer"] || "").trim()
    ]);
    if (visibleOwnNames.length === 1) {
      return `typed local identity ${visibleOwnNames[0]}`;
    }

    return "no user identity";
  }

  function finalizeRestoredIdentityState(state) {
    const next = state && typeof state === "object" ? { ...state } : {};
    const strictRecognizedIdentity = !!next.strictRecognizedIdentity;
    const recognizedIdentity = String(next.recognizedIdentity || "").trim()
      || (strictRecognizedIdentity ? "" : inferRecognizedIdentityFromLegacyState(next));
    delete next.strictRecognizedIdentity;
    if (recognizedIdentity) {
      next.recognizedIdentity = recognizedIdentity;
      next.ownNames = buildOwnNamesState(recognizedIdentity);
      next.entryMode = "";
      next.loadedInviteeIdentity = null;
      next.temporaryIdentity = null;
      return next;
    }
    next.recognizedIdentity = "";
    next.ownNames = {};
    next.loadedInviteeIdentity = null;
    next.temporaryIdentity = null;
    if (strictRecognizedIdentity) {
      return next;
    }
    return normalizeLauncherIdentityState(next);
  }

  function hydrateRecognizedIdentityFromCurrentState(state = readLauncherState()) {
    const next = state && typeof state === "object" ? { ...state } : {};
    const recognizedIdentity = String(next.recognizedIdentity || "").trim();
    if (!recognizedIdentity) {
      return normalizeLauncherIdentityState(next);
    }
    next.recognizedIdentity = recognizedIdentity;
    next.ownNames = buildOwnNamesState(recognizedIdentity);
    next.entryMode = "";
    next.loadedInviteeIdentity = null;
    next.temporaryIdentity = null;
    return normalizeLauncherIdentityState(next);
  }

  function promoteRecognizedIdentityFromCandidate(identifier, userType = "standard", state = readLauncherState()) {
    const cleanIdentifier = String(identifier || "").trim();
    if (!cleanIdentifier) {
      return normalizeLauncherIdentityState(state);
    }
    const next = state && typeof state === "object" ? { ...state } : {};
    next.recognizedIdentity = cleanIdentifier;
    next.ownNames = buildOwnNamesState(cleanIdentifier);
    next.entryMode = "";
    next.loadedInviteeIdentity = null;
    next.temporaryIdentity = null;
    next.resolvedMainUserType = String(userType || "").trim().toLowerCase() === "pro" ? "pro" : "standard";
    return normalizeLauncherIdentityState(next);
  }

  function getLoadedInviteeIdentity(state = readLauncherState()) {
    const loaded = state?.loadedInviteeIdentity && typeof state.loadedInviteeIdentity === "object"
      ? state.loadedInviteeIdentity
      : null;
    const identifier = String(loaded?.identifier || "").trim();
    if (!identifier) {
      return null;
    }
    return {
      identifier,
      userType: String(loaded?.userType || "").trim().toLowerCase() === "pro" ? "pro" : "standard",
      source: String(loaded?.source || "").trim(),
      previousIdentitySnapshot: loaded?.previousIdentitySnapshot && typeof loaded.previousIdentitySnapshot === "object"
        ? loaded.previousIdentitySnapshot
        : null
    };
  }

  function getDeviceTestModeState(state = readLauncherState()) {
    const source = state?.deviceTestMode && typeof state.deviceTestMode === "object"
      ? state.deviceTestMode
      : null;
    if (!source) {
      return null;
    }
    const restoreSnapshot = source.restoreSnapshot && typeof source.restoreSnapshot === "object"
      ? source.restoreSnapshot
      : null;
    const startedAt = Number.isFinite(Number(source.startedAt)) ? Number(source.startedAt) : 0;
    const freshStartEpoch = readLocalFreshStartEpoch();
    if (freshStartEpoch && startedAt && startedAt < freshStartEpoch) {
      return null;
    }
    return {
      active: !!source.active && !!restoreSnapshot,
      restoreSnapshot,
      startedAt
    };
  }

  function isDeviceTestModeActive(state = readLauncherState()) {
    return !!getDeviceTestModeState(state)?.active;
  }

  function writeDeviceTestRestoreSnapshot(snapshot) {
    try {
      if (!snapshot || typeof snapshot !== "object") {
        localStorage.removeItem(deviceTestRestoreSnapshotKey);
        return;
      }
      localStorage.setItem(deviceTestRestoreSnapshotKey, JSON.stringify(snapshot));
    } catch (error) {
      // Ignore local persistence failures.
    }
  }

  function readDeviceTestRestoreSnapshot() {
    try {
      const raw = localStorage.getItem(deviceTestRestoreSnapshotKey);
      if (!raw) {
        return null;
      }
      const parsed = JSON.parse(raw);
      return parsed && typeof parsed === "object" ? parsed : null;
    } catch (error) {
      return null;
    }
  }

  function clearDeviceTestRestoreSnapshot() {
    try {
      localStorage.removeItem(deviceTestRestoreSnapshotKey);
    } catch (error) {
      // Ignore local cleanup failures.
    }
  }

  function writeDeviceTestNotice(message) {
    try {
      const text = String(message || "").trim();
      if (!text) {
        sessionStorage.removeItem(deviceTestNoticeKey);
        return;
      }
      sessionStorage.setItem(deviceTestNoticeKey, text);
    } catch (error) {
      // Ignore session persistence failures.
    }
  }

  function readAndClearDeviceTestNotice() {
    try {
      const text = String(sessionStorage.getItem(deviceTestNoticeKey) || "").trim();
      sessionStorage.removeItem(deviceTestNoticeKey);
      return text;
    } catch (error) {
      return "";
    }
  }

  function setLauncherProfileSaveSuppression(active, persistToSession = false) {
    suppressLauncherProfileSaves = !!active;
    if (!persistToSession) {
      return;
    }
    try {
      if (suppressLauncherProfileSaves) {
        sessionStorage.setItem(suppressLauncherProfileSavesKey, "1");
      } else {
        sessionStorage.removeItem(suppressLauncherProfileSavesKey);
      }
    } catch (error) {
      // Ignore session persistence failures.
    }
  }

  function syncLauncherProfileSaveSuppressionFromSession() {
    try {
      suppressLauncherProfileSaves = String(sessionStorage.getItem(suppressLauncherProfileSavesKey) || "").trim() === "1";
    } catch (error) {
      suppressLauncherProfileSaves = false;
    }
  }

  syncLauncherProfileSaveSuppressionFromSession();

  function hasDeviceTestRestoreSnapshot() {
    return !!readDeviceTestRestoreSnapshot();
  }

  function clearStaleDeviceTestModeArtifactsIfNeeded(state = readLauncherState()) {
    const rawDeviceTestMode = state?.deviceTestMode && typeof state.deviceTestMode === "object"
      ? state.deviceTestMode
      : null;
    if (!rawDeviceTestMode) {
      return state;
    }
    const freshStartEpoch = readLocalFreshStartEpoch();
    const startedAt = Number.isFinite(Number(rawDeviceTestMode?.startedAt)) ? Number(rawDeviceTestMode.startedAt) : 0;
    if (!freshStartEpoch || !startedAt || startedAt >= freshStartEpoch) {
      return state;
    }
    const nextState = normalizeLauncherIdentityState({
      ...state,
      deviceTestMode: null
    });
    try {
      localStorage.setItem(launcherKey, JSON.stringify(nextState));
    } catch (error) {
      // Ignore local persistence failures.
    }
    clearDeviceTestRestoreSnapshot();
    writeDeviceTestNotice("");
    logLauncherUserTypeDebug("stale_device_test_mode_cleared", {
      startedAt,
      freshStartEpoch
    });
    return nextState;
  }

  function canRestoreDeviceIdentity(state = readLauncherState()) {
    return !!(
      isDeviceTestModeActive(state) ||
      hasDeviceTestRestoreSnapshot() ||
      getLoadedInviteeIdentity(state)
    );
  }

  function hasAuthoritativeDeviceIdentity(state = readLauncherState()) {
    const recognizedIdentity = String(state?.recognizedIdentity || "").trim();
    if (recognizedIdentity) {
      return true;
    }
    if (getLoadedInviteeIdentity(state)?.identifier) {
      return true;
    }
    if (getTemporaryIdentityState(state)?.identifier) {
      return true;
    }
    return false;
  }

  function getBlinkBehaviorSettings(state = readLauncherState()) {
    return {
      enabled: !!state?.blinkSenderImage,
      onSeconds: normalizeBlinkSecondsValue(state?.blinkImageOnSeconds, defaultBlinkSettings.onSeconds),
      offSeconds: normalizeBlinkSecondsValue(state?.blinkImageOffSeconds, defaultBlinkSettings.offSeconds)
    };
  }

  function renderBlinkBehaviorView() {
    const settings = getBlinkBehaviorSettings();
    if (blinkEnabledCheckbox) {
      blinkEnabledCheckbox.checked = settings.enabled;
    }
    if (blinkOnSecondsInput) {
      blinkOnSecondsInput.value = settings.onSeconds;
    }
    if (blinkOffSecondsInput) {
      blinkOffSecondsInput.value = settings.offSeconds;
    }
    if (blinkStatus) {
      blinkStatus.textContent = "";
    }
  }

  function persistBlinkBehaviorView({ showMessage = true } = {}) {
    const latest = readLauncherState();
    latest.blinkSenderImage = !!blinkEnabledCheckbox?.checked;
    latest.blinkImageOnSeconds = normalizeBlinkSecondsValue(blinkOnSecondsInput?.value, defaultBlinkSettings.onSeconds);
    latest.blinkImageOffSeconds = normalizeBlinkSecondsValue(blinkOffSecondsInput?.value, defaultBlinkSettings.offSeconds);
    writeLauncherState(latest);

    if (blinkOnSecondsInput) {
      blinkOnSecondsInput.value = latest.blinkImageOnSeconds;
    }
    if (blinkOffSecondsInput) {
      blinkOffSecondsInput.value = latest.blinkImageOffSeconds;
    }
    if (blinkStatus && showMessage) {
      blinkStatus.textContent = latest.blinkSenderImage
        ? `Blink behavior saved. ON ${latest.blinkImageOnSeconds}s, OFF ${latest.blinkImageOffSeconds}s.`
        : "Blink behavior saved. Sender image blinking is off.";
    }
  }

  function getConfidenceBehaviorSettings(state = readLauncherState()) {
    return {
      include: state?.includeConfidence === true,
      includePositiveReinforcement: state?.includePositiveReinforcement === true
    };
  }

  function applyConfidencePreferenceFromServer(userPreferences, { render = false } = {}) {
    if (!userPreferences || typeof userPreferences !== "object") {
      return readLauncherState();
    }
    if (!(Number(userPreferences.updated_ms) > 0)) {
      if (render) {
        renderConfidenceBehaviorView();
      }
      return readLauncherState();
    }
    const latest = readLauncherState();
    latest.includeConfidence = !!userPreferences.include_confidence;
    latest.includePositiveReinforcement = !!userPreferences.include_positive_reinforcement;
    writeLauncherState(latest);
    if (render) {
      renderConfidenceBehaviorView();
    }
    return latest;
  }

  async function syncConfidencePreferenceForReceiverContext({ render = false } = {}) {
    if (isVisitorLauncherEntry()) {
      return readLauncherState();
    }
    const receiverContext = getPairContextForRole("receiver");
    const ownerIdentifier = String(receiverContext?.ownName || "").trim();
    if (!ownerIdentifier || isInternalVisitorSimulationName(ownerIdentifier)) {
      return readLauncherState();
    }
    try {
      const userPreferences = await fetchUserPreferences(ownerIdentifier);
      return applyConfidencePreferenceFromServer(userPreferences, { render });
    } catch (_error) {
      return readLauncherState();
    }
  }

  function renderConfidenceBehaviorView() {
    const settings = getConfidenceBehaviorSettings();
    confidenceModeButtons.forEach((button) => {
      const mode = String(button.dataset.confidenceMode || "").trim().toLowerCase();
      const selected =
        (mode === "include" && settings.include)
        || (mode === "exclude" && !settings.include);
      button.classList.toggle("is-selected", selected);
      button.setAttribute("aria-pressed", selected ? "true" : "false");
    });
    reinforcementModeButtons.forEach((button) => {
      const mode = String(button.dataset.reinforcementMode || "").trim().toLowerCase();
      const selected =
        (mode === "include" && settings.includePositiveReinforcement)
        || (mode === "exclude" && !settings.includePositiveReinforcement);
      button.classList.toggle("is-selected", selected);
      button.setAttribute("aria-pressed", selected ? "true" : "false");
    });
    if (confidenceStatus) {
      if (!settings.includePositiveReinforcement) {
        confidenceStatus.textContent = "Positive reinforcement sound does not occur.";
      } else if (settings.include) {
        confidenceStatus.textContent = "Positive reinforcement sound occurs when the target is revealed and the Receiver has correctly selected it.";
      } else {
        confidenceStatus.textContent = "Positive reinforcement sound occurs instantly when the Receiver correctly selects the target.";
      }
    }
  }

  async function persistConfidenceBehavior(includeConfidence, includePositiveReinforcement = null) {
    const latest = readLauncherState();
    latest.includeConfidence = includeConfidence !== false;
    if (typeof includePositiveReinforcement === "boolean") {
      latest.includePositiveReinforcement = includePositiveReinforcement;
    } else if (typeof latest.includePositiveReinforcement !== "boolean") {
      latest.includePositiveReinforcement = defaultConfidenceSettings.includePositiveReinforcement;
    }
    writeLauncherState(latest);
    renderConfidenceBehaviorView();
    if (isVisitorLauncherEntry()) {
      return;
    }
    const receiverContext = getPairContextForRole("receiver");
    const ownerIdentifier = String(receiverContext?.ownName || "").trim();
    if (!ownerIdentifier || isInternalVisitorSimulationName(ownerIdentifier)) {
      return;
    }
    try {
      const storedPreferences = await saveUserPreferences(ownerIdentifier, {
        include_confidence: latest.includeConfidence,
        include_positive_reinforcement: !!latest.includePositiveReinforcement
      });
      applyConfidencePreferenceFromServer(storedPreferences, { render: true });
    } catch (_error) {
      renderConfidenceBehaviorView();
    }
  }

  function buildReportRequestPayload() {
    const payload = {
      action: "report_csv_data"
    };

    const adminSecretCandidate = getLauncherAdminSecretCandidate();
    if (adminSecretCandidate) {
      payload.secret_candidate = adminSecretCandidate;
      payload.include_all = true;
      return payload;
    }

    payload.candidate_pairs = collectReportCandidatePairs().map((pair) => ({
      receiver_name: pair.receiverName,
      sender_name: pair.senderName,
      session_code: pair.sessionCode
    }));
    payload.associated_names = collectReportOwnNames();
    return payload;
  }

  async function fetchReportCsvData() {
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(buildReportRequestPayload())
    });

    if (!response.ok) {
      throw new Error(`Report CSV request failed with status ${response.status}`);
    }

    const data = await response.json();
    const reportCsv = data?.report_csv || {};
    reportCsvPathCache = String(reportCsv?.path || "");
    reportCsvRecordsCache = Array.isArray(reportCsv?.records) ? reportCsv.records : [];
    return {
      available: !!reportCsv?.available,
      message: String(reportCsv?.message || ""),
      path: reportCsvPathCache,
      records: reportCsvRecordsCache
    };
  }

  async function fetchSelectedPairReportCsvData(pairInfo) {
    const selectedPair = sanitizePairInfoForServer(pairInfo);
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action: "report_pair_csv_data",
        selected_pair: selectedPair,
        secret_candidate: getLauncherAdminSecretCandidate()
      })
    });

    const data = await parseApiResponse(response, `Pair report CSV request failed with status ${response.status}`);
    const reportCsv = data?.report_csv || {};
    return {
      available: !!reportCsv?.available,
      message: String(reportCsv?.message || ""),
      path: String(reportCsv?.path || ""),
      records: Array.isArray(reportCsv?.records) ? reportCsv.records : []
    };
  }

  function getCurrentReportPairForGlobe() {
    if (!selectedReportPair?.receiverName || !selectedReportPair?.senderName) {
      return null;
    }

    return {
      key: selectedReportPair.key || buildPairMatchKey(selectedReportPair.receiverName, selectedReportPair.senderName),
      pairKey: selectedReportPair.key || buildPairMatchKey(selectedReportPair.receiverName, selectedReportPair.senderName),
      receiverId: String(selectedReportPair.receiverName || "").trim(),
      senderId: String(selectedReportPair.senderName || "").trim(),
      receiverLabel: getPairInfoReceiverLabel(selectedReportPair),
      senderLabel: getPairInfoSenderLabel(selectedReportPair),
      sessionCode: String(selectedReportPair.sessionCode || "").trim(),
      source: String(selectedReportPair.source || "").trim().toLowerCase() === "simulation" ? "simulation" : "real"
    };
  }

  async function getCurrentGlobeLaunchOptions() {
    const latestState = await syncBrowserLocationPermission();
    return {
      minTrials: 1,
      includeIncomplete: false,
      grouping: "rounded",
      roundingDecimals: 3,
      locationDisabled: isLocationPrivacyDisabled(latestState)
    };
  }

  function isLocationPrivacyDisabled(state = readLauncherState()) {
    return String(state?.locationPermission || "").trim().toLowerCase() === "denied";
  }

  function buildStandaloneModuleUrl(modulePath, params = {}) {
    const search = new URLSearchParams();
    Object.entries(params).forEach(([key, value]) => {
      if (value === null || value === undefined || value === "") {
        return;
      }
      search.set(key, String(value));
    });
    return `${modulePath}?${search.toString()}`;
  }

  function buildAbsoluteModuleUrl(modulePath, params = {}) {
    const baseUrl = new URL(modulePath, window.location.href);
    Object.entries(params).forEach(([key, value]) => {
      if (value === null || value === undefined || value === "") {
        return;
      }
      baseUrl.searchParams.set(key, String(value));
    });
    return baseUrl.toString();
  }

  function buildCanonicalLauncherUrl(params = {}) {
    return buildStandaloneModuleUrl("telepathybeginner.html", {
      v: launcherBuildVersion,
      ...params
    });
  }

  function isLandingPreviewRequested() {
    return readRequestedLauncherView() === "landing-preview";
  }

  function readRequestedLauncherView() {
    try {
      return String(new URLSearchParams(window.location.search).get("open") || "").trim().toLowerCase();
    } catch (error) {
      return "";
    }
  }

  function shouldStartInFreshLauncherMode() {
    const requestedView = readRequestedLauncherView();
    return requestedView === "fresh-launcher" || requestedView === "visitor-launcher";
  }

  function shouldStartInVisitorGuestMode() {
    if (shouldStartInFreshLauncherMode()) {
      return true;
    }
    return isVisitorLauncherEntry();
  }

  function buildGlobeVisualizationUrl(pairState, options = {}) {
    const returnUrl = buildAbsoluteModuleUrl("telepathybeginner.html", {
      v: launcherBuildVersion,
      open: "report-definition",
      report_receiver: pairState?.receiverId || "",
      report_sender: pairState?.senderId || "",
      report_session_code: pairState?.sessionCode || "",
      report_source: pairState?.source || "real"
    });
    return buildStandaloneModuleUrl("globe/index.html", {
      v: launcherBuildVersion,
      return_url: returnUrl,
      pair_key: pairState?.pairKey || pairState?.key || "",
      receiver_id: pairState?.receiverId || "",
      sender_id: pairState?.senderId || "",
      session_code: pairState?.sessionCode || "",
      source: pairState?.source || "real",
      min_trials: Number.isFinite(Number(options.minTrials)) ? Number(options.minTrials) : 1,
      include_incomplete: options.includeIncomplete ? 1 : 0,
      group_by: options.grouping || "exact",
      rounding_decimals: Number.isFinite(Number(options.roundingDecimals)) ? Number(options.roundingDecimals) : 3,
      location_disabled: options.locationDisabled ? 1 : 0
    });
  }

  function openGlobeVisualization(pairState, options = {}) {
    window.location.href = buildGlobeVisualizationUrl(pairState, options);
  }

  async function handleGlobeLaunchClick() {
    if (isProLockedButton(reportGlobeButton)) {
      return;
    }
    const pairState = getCurrentReportPairForGlobe();
    if (!pairState) {
      if (reportDefinitionStatus) {
        reportDefinitionStatus.textContent = "Choose a receiver-sender pair before opening the globe.";
      }
      return;
    }
    openGlobeVisualization(pairState, await getCurrentGlobeLaunchOptions());
  }

