  function uniqueNames(names) {
    const cleaned = names
      .map((name) => String(name || "").trim())
      .filter(Boolean);
    return [...new Set(cleaned)];
  }

  function isValidEmailAddress(value) {
    const text = String(value || "").trim();
    if (!text || text.length > 254) {
      return false;
    }
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(text);
  }

  function isValidUniqueHandle(value) {
    const text = String(value || "").replace(/\s+/g, " ").trim();
    return /^[A-Za-z0-9](?:[A-Za-z0-9._ -]{1,22}[A-Za-z0-9])?$/.test(text);
  }

  function isValidParticipantIdentifier(value) {
    const text = String(value || "").trim();
    if (!text || text.length > 254) {
      return false;
    }
    return isValidEmailAddress(text) || isValidUniqueHandle(text);
  }

  function assertValidEmailIdentifier(value, fieldName, options = {}) {
    const required = options.required !== false;
    const text = String(value || "").trim();
    if (!text) {
      if (required) {
        throw new Error(`${fieldName} is required.`);
      }
      return "";
    }
    if (!isValidEmailAddress(text)) {
      throw new Error(`${fieldName} must be a valid email address.`);
    }
    return text;
  }

  function assertValidParticipantIdentifier(value, fieldName, options = {}) {
    const required = options.required !== false;
    const text = String(value || "").trim();
    if (!text) {
      if (required) {
        throw new Error(`${fieldName} is required.`);
      }
      return "";
    }
    if (text.length > 254) {
      throw new Error(`${fieldName} is too long.`);
    }
    if (!isValidEmailAddress(text) && !isValidUniqueHandle(text)) {
      throw new Error(`${fieldName} must be a valid email address or unique handle.`);
    }
    return isValidEmailAddress(text) ? text : text.replace(/\s+/g, " ").trim();
  }

  function assertValidSessionCode(value, fieldName = "session_code") {
    const text = String(value || "").trim();
    if (!text) {
      return "";
    }
    if (text.length > 200) {
      throw new Error(`${fieldName} is too long.`);
    }
    if (!/^[A-Za-z0-9_-]+$/.test(text)) {
      throw new Error(`${fieldName} contains invalid characters.`);
    }
    return text;
  }

  function assertValidDeviceId(value, fieldName = "device identifier") {
    const text = String(value || "").trim();
    if (!text) {
      throw new Error(`${fieldName} is required.`);
    }
    if (text.length < 8 || text.length > 128 || !/^[A-Za-z0-9._:-]+$/.test(text)) {
      throw new Error(`${fieldName} is invalid.`);
    }
    return text;
  }

  function getOrCreateMessagingDeviceId() {
    const state = readLauncherState();
    const existing = String(state.messagingDeviceId || "").trim();
    if (existing && /^[A-Za-z0-9._:-]{8,128}$/.test(existing)) {
      return existing;
    }
    const generated = window.crypto?.randomUUID
      ? `dev-${window.crypto.randomUUID()}`
      : `dev-${Math.random().toString(36).slice(2)}${Date.now().toString(36)}`;
    state.messagingDeviceId = generated;
    writeLauncherState(state);
    return generated;
  }

  function urlBase64ToUint8Array(base64String) {
    const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
    const base64 = `${base64String}${padding}`.replace(/-/g, "+").replace(/_/g, "/");
    const rawData = window.atob(base64);
    const outputArray = new Uint8Array(rawData.length);
    for (let index = 0; index < rawData.length; index += 1) {
      outputArray[index] = rawData.charCodeAt(index);
    }
    return outputArray;
  }

  function sanitizePairInfoForServer(pairInfo, fieldName = "selected pair") {
    const aliasReceiverNames = Array.isArray(pairInfo?.aliasReceiverNames)
      ? pairInfo.aliasReceiverNames
      : Array.isArray(pairInfo?.alias_receiver_names)
        ? pairInfo.alias_receiver_names
        : [];
    const aliasSenderNames = Array.isArray(pairInfo?.aliasSenderNames)
      ? pairInfo.aliasSenderNames
      : Array.isArray(pairInfo?.alias_sender_names)
        ? pairInfo.alias_sender_names
        : [];
    return {
      receiver_name: assertValidParticipantIdentifier(pairInfo?.receiverName, `${fieldName} receiver identifier`),
      sender_name: assertValidParticipantIdentifier(pairInfo?.senderName, `${fieldName} sender identifier`),
      session_code: assertValidSessionCode(pairInfo?.sessionCode, `${fieldName} session code`),
      source: String(pairInfo?.source || "").trim().toLowerCase() === "simulation" ? "simulation" : "real",
      alias_receiver_names: aliasReceiverNames
        .map((value) => assertValidParticipantIdentifier(value, `${fieldName} alias receiver identifier`))
        .filter(Boolean),
      alias_sender_names: aliasSenderNames
        .map((value) => assertValidParticipantIdentifier(value, `${fieldName} alias sender identifier`))
        .filter(Boolean)
    };
  }

  function sanitizeLauncherProfileForServer(role, ownEmail, profileState) {
    const launcherRole =
      role === "sender"
        ? "sender"
        : role === "receiver"
          ? "receiver"
          : role === "remote-viewer"
            ? "remote-viewer"
            : "";
    if (!launcherRole) {
      throw new Error("launcher_role must be sender, receiver, or remote-viewer.");
    }
    return {
      launcher_role: launcherRole,
      own_email: assertValidParticipantIdentifier(ownEmail, "own_email"),
      launcher_profile: {
        current_partner: assertValidParticipantIdentifier(profileState?.currentPartner, "launcher_profile.current_partner", { required: false }),
        difficulty_level: normalizeDifficultyLevel(profileState?.difficultyLevel || "1"),
        partner_history: uniqueNames(Array.isArray(profileState?.partnerHistory) ? profileState.partnerHistory : []).map((item) =>
          assertValidParticipantIdentifier(item, "launcher_profile.partner_history item")
        ),
        deleted_partners: uniqueNames(Array.isArray(profileState?.deletedPartners) ? profileState.deletedPartners : []).map((item) =>
          assertValidParticipantIdentifier(item, "launcher_profile.deleted_partners item")
        )
      }
    };
  }

  async function parseApiResponse(response, fallbackMessage) {
    let data = null;
    try {
      data = await response.json();
    } catch (error) {
      if (!response.ok) {
        throw new Error(fallbackMessage || `Request failed with status ${response.status}`);
      }
      throw new Error("The server returned invalid JSON.");
    }

    if (!response.ok || data?.ok === false) {
      throw new Error(String(data?.error || fallbackMessage || `Request failed with status ${response.status}`));
    }

    return data;
  }

  function normalizePersonNameForPairMatch(name) {
    return String(name || "")
      .replace(/\s+/g, " ")
      .trim()
      .toLowerCase();
  }

  function buildPairMatchKey(receiverName, senderName) {
    return `${normalizePersonNameForPairMatch(receiverName)}|||${normalizePersonNameForPairMatch(senderName)}`;
  }

  function isDemoReportPair(receiverName, senderName) {
    return demoReportPairKeys.has(buildPairMatchKey(receiverName, senderName));
  }

  function getDemoReportPairSortValue(pairInfo) {
    if (!pairInfo) {
      return Number.POSITIVE_INFINITY;
    }
    const key = String(pairInfo.baseKey || buildPairMatchKey(pairInfo.receiverName, pairInfo.senderName)).trim();
    return demoReportPairOrder.get(key) ?? Number.POSITIVE_INFINITY;
  }

  function escapeHtml(value) {
    return String(value || "")
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;")
      .replaceAll('"', "&quot;")
      .replaceAll("'", "&#39;");
  }

  function sanitizeLearnMorePreviewUrl(value) {
    const url = String(value || "").trim();
    if (!url) {
      return "";
    }
    if (/^https?:\/\//i.test(url)) {
      return url;
    }
    if (/^(\/|\.\/|\.\.\/)/.test(url)) {
      return url;
    }
    if (/^[a-z0-9][a-z0-9._/-]*$/i.test(url) && !/^[a-z]+:/i.test(url)) {
      return url;
    }
    return "";
  }

  function renderLearnMoreInlineMarkup(value) {
    let source = String(value || "");
    const placeholders = [];
    const addPlaceholder = (markup) => {
      const token = `%%LEARN_MORE_${placeholders.length}%%`;
      placeholders.push({ token, markup });
      return token;
    };

    source = source.replace(/!\[([^\]\n]*)\]\(([^)\n]+)\)/g, (match, altText, urlText) => {
      const safeUrl = sanitizeLearnMorePreviewUrl(urlText);
      if (!safeUrl) {
        return match;
      }
      return addPlaceholder(
        `<img class="learn-more-preview-image" src="${escapeHtml(safeUrl)}" alt="${escapeHtml(altText)}">`
      );
    });

    source = source.replace(/\[([^\]\n]+)\]\(([^)\n]+)\)/g, (match, linkText, urlText) => {
      const safeUrl = sanitizeLearnMorePreviewUrl(urlText);
      if (!safeUrl) {
        return match;
      }
      return addPlaceholder(
        `<a class="learn-more-preview-link" href="${escapeHtml(safeUrl)}" target="_blank" rel="noopener noreferrer">${escapeHtml(linkText)}</a>`
      );
    });

    let rendered = escapeHtml(source)
      .replace(/\*\*([^*\n][^]*?)\*\*/g, "<strong>$1</strong>")
      .replace(/(^|[^*])\*([^*\n]+)\*(?!\*)/g, "$1<em>$2</em>")
      .replace(/\n/g, "<br>");

    placeholders.forEach(({ token, markup }) => {
      rendered = rendered.replace(token, markup);
    });
    return rendered;
  }

  function getLearnMoreHeadingDisplayText(value) {
    const headingLine = String(value || "").trim();
    const prefixMatch = headingLine.match(/^\[([A-Za-z*]+)\]\s*(.+)$/);
    return String(prefixMatch ? prefixMatch[2] : headingLine).trim();
  }

  function renderLearnMorePreviewMarkup(value) {
    const normalized = String(value || "").replace(/\r\n?/g, "\n").trim();
    if (!normalized) {
      return "<p></p>";
    }
    const lines = normalized.split("\n");
    const blocks = [];
    let paragraphLines = [];
    const flushParagraph = () => {
      const paragraph = paragraphLines.join("\n").trim();
      paragraphLines = [];
      if (!paragraph) {
        return;
      }
      blocks.push(`<p>${renderLearnMoreInlineMarkup(paragraph)}</p>`);
    };

    for (let index = 0; index < lines.length; index += 1) {
      const currentLine = String(lines[index] || "");
      const trimmedLine = currentLine.trim();
      const nextLine = String(lines[index + 1] || "");
      if (trimmedLine && isDashedUnderlineLine(nextLine)) {
        flushParagraph();
        blocks.push(`<h3 class="learn-more-preview-heading">${renderLearnMoreInlineMarkup(getLearnMoreHeadingDisplayText(trimmedLine))}</h3>`);
        index += 1;
        continue;
      }
      if (!trimmedLine) {
        flushParagraph();
        continue;
      }
      paragraphLines.push(currentLine);
    }

    flushParagraph();
    return blocks.join("") || "<p></p>";
  }

  function updateLearnMorePreview(previewElement, value) {
    if (!previewElement) {
      return;
    }
    previewElement.innerHTML = renderLearnMorePreviewMarkup(value);
  }

  function normalizeUserPreferencesFromServer(record) {
    const source = record && typeof record === "object" ? record : {};
    return {
      include_confidence: !!source.include_confidence,
      include_positive_reinforcement: !!source.include_positive_reinforcement,
      updated_ms: Number.isFinite(Number(source.updated_ms)) ? Number(source.updated_ms) : 0
    };
  }

  async function saveUserPreferences(identifier, preferences = {}) {
    const cleanIdentifier = assertValidParticipantIdentifier(identifier, "identifier");
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action: "save_user_preferences",
        identifier: cleanIdentifier,
        user_preferences: {
          include_confidence: !!preferences?.include_confidence,
          include_positive_reinforcement: !!preferences?.include_positive_reinforcement
        }
      })
    });

    const data = await parseApiResponse(response, `User-preferences save failed with status ${response.status}`);
    return normalizeUserPreferencesFromServer(data?.user_preferences || null);
  }

  async function fetchUserPreferences(identifier) {
    const cleanIdentifier = assertValidParticipantIdentifier(identifier, "identifier");
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action: "get_user_preferences",
        identifier: cleanIdentifier
      })
    });

    const data = await parseApiResponse(response, `User-preferences request failed with status ${response.status}`);
    return normalizeUserPreferencesFromServer(data?.user_preferences || null);
  }

  function normalizeLearningCenterLessonId(value) {
    return String(value || "")
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9-]+/g, "-")
      .replace(/^-+|-+$/g, "");
  }

  function normalizeLearningCenterDisplayNumber(value) {
    return String(value || "").trim();
  }

  function buildLearningCenterLessonContentKey(lessonId) {
    const normalized = normalizeLearningCenterLessonId(lessonId);
    return normalized ? `lesson-id:${normalized}` : "";
  }

  function buildLearningCenterLessonRowId(lessonId) {
    const normalized = normalizeLearningCenterLessonId(lessonId);
    return normalized ? `learningCenterLesson-${normalized}` : "";
  }

  function getLearningCenterLessonRowTitle(row) {
    return String(row?.querySelector(".online-course-lesson-title")?.textContent || "").trim();
  }

  function getLearningCenterLessonRowById(lessonId) {
    const target = normalizeLearningCenterLessonId(lessonId);
    if (!target || !onlineCourseLessonList) {
      return null;
    }
    return onlineCourseLessonList.querySelector(`.online-course-lesson-row[data-lesson-id="${target}"]`);
  }

  function getLearningCenterLessonRecordById(lessonId, sourceIndex = learningCenterLessonIndex) {
    const target = normalizeLearningCenterLessonId(lessonId);
    return (Array.isArray(sourceIndex) ? sourceIndex : []).find((record) => normalizeLearningCenterLessonId(record?.lesson_id) === target) || null;
  }

  function getLearningCenterLessonRecordByDisplayNumber(displayNumber, sourceIndex = learningCenterLessonIndex) {
    const target = normalizeLearningCenterDisplayNumber(displayNumber);
    return (Array.isArray(sourceIndex) ? sourceIndex : []).find((record) => normalizeLearningCenterDisplayNumber(record?.display_number) === target) || null;
  }

  function compareLearningCenterDisplayNumbers(left, right) {
    const leftParts = String(left || "").split(/[^0-9]+/).filter(Boolean).map((value) => Number(value) || 0);
    const rightParts = String(right || "").split(/[^0-9]+/).filter(Boolean).map((value) => Number(value) || 0);
    const maxLength = Math.max(leftParts.length, rightParts.length);
    for (let index = 0; index < maxLength; index += 1) {
      const leftValue = leftParts[index] ?? 0;
      const rightValue = rightParts[index] ?? 0;
      if (leftValue !== rightValue) {
        return leftValue - rightValue;
      }
    }
    return String(left || "").localeCompare(String(right || ""), undefined, { numeric: true, sensitivity: "base" });
  }

  function normalizeLearningCenterLessonRecord(record) {
    const lessonId = normalizeLearningCenterLessonId(record?.lesson_id || record?.id || "");
    const displayNumber = normalizeLearningCenterDisplayNumber(record?.display_number);
    const title = String(record?.title || "").trim();
    const subcopy = String(record?.subcopy || "").trim();
    const type = ["lesson-page", "baseline", "after-first-session"].includes(String(record?.type || "").trim())
      ? String(record.type).trim()
      : "lesson-page";
    const contentKey = type === "lesson-page"
      ? buildLearningCenterLessonContentKey(lessonId)
      : "";
    const available = type !== "lesson-page" || Boolean(record?.available);
    if (!lessonId || !displayNumber || !title) {
      return null;
    }
    return {
      lesson_id: lessonId,
      display_number: displayNumber,
      title,
      subcopy,
      type,
      content_key: contentKey,
      available
    };
  }

  function parseLessonEditorDirective(value) {
    const normalized = String(value || "").replace(/\r\n?/g, "\n");
    const lines = normalized.split("\n");
    const metadata = {};
    let bodyStartIndex = lines.length;
    let bareLessonId = "";
    for (let index = 0; index < lines.length; index += 1) {
      const line = String(lines[index] || "");
      const trimmed = line.trim();
      if (!trimmed) {
        bodyStartIndex = index + 1;
        break;
      }
      const match = trimmed.match(/^([a-z][a-z0-9_-]*)\s*=\s*(.+)\s*$/i);
      if (!match) {
        if (index === 0 && /^[a-z0-9-]{1,80}$/i.test(trimmed)) {
          bareLessonId = trimmed;
          bodyStartIndex = index + 1;
        } else {
          bodyStartIndex = index;
        }
        break;
      }
      metadata[String(match[1] || "").trim().toLowerCase()] = String(match[2] || "").trim();
    }
    const legacyNumber = String(metadata.lesson || "").trim();
    const lessonId = normalizeLearningCenterLessonId(metadata["lesson-id"] || metadata.lesson_id || bareLessonId || "");
    const displayNumber = normalizeLearningCenterDisplayNumber(metadata.number || legacyNumber || "");
    const title = String(metadata.title || "").trim();
    const subcopy = String(metadata.subcopy || "").trim();
    const type = ["lesson-page", "baseline", "after-first-session"].includes(String(metadata.type || "").trim())
      ? String(metadata.type).trim()
      : "lesson-page";
    if (!lessonId && !displayNumber) {
      return null;
    }
    return {
      lessonId,
      displayNumber,
      title,
      subcopy,
      type,
      metadata,
      remainder: lines.slice(bodyStartIndex).join("\n").replace(/^\n+/, "")
    };
  }

  function stripLessonEditorDirective(value) {
    const directive = parseLessonEditorDirective(value);
    return directive ? directive.remainder : String(value || "");
  }

  function buildStarterLessonContent(recordOrLessonId, fallbackDisplayNumber = "", fallbackTitle = "", fallbackSubcopy = "", fallbackType = "lesson-page") {
    const lessonRecord = typeof recordOrLessonId === "object" && recordOrLessonId
      ? recordOrLessonId
      : {
          lesson_id: recordOrLessonId,
          display_number: fallbackDisplayNumber,
          title: fallbackTitle,
          subcopy: fallbackSubcopy,
          type: fallbackType
        };
    const lessonId = normalizeLearningCenterLessonId(lessonRecord?.lesson_id || "");
    const displayNumber = normalizeLearningCenterDisplayNumber(lessonRecord?.display_number || "");
    const title = String(lessonRecord?.title || "").trim();
    const subcopy = String(lessonRecord?.subcopy || "").trim();
    const type = ["lesson-page", "baseline", "after-first-session"].includes(String(lessonRecord?.type || "").trim())
      ? String(lessonRecord.type).trim()
      : "lesson-page";
    return [
      `lesson-id=${lessonId}`,
      `number=${displayNumber}`,
      `title=${title}`,
      subcopy ? `subcopy=${subcopy}` : "",
      `type=${type}`,
      "",
      title ? `TITLE=${title}` : "",
      "",
      ""
    ].filter((line, index, array) => line !== "" || (index > 0 && array[index - 1] !== "")).join("\n");
  }

  function isDirectiveOnlyLessonEditorText(value) {
    const directive = parseLessonEditorDirective(value);
    if (!directive) {
      return false;
    }
    return !String(directive.remainder || "").trim();
  }

  function partnerRole(role) {
    if (role === "sender") {
      return "receiver";
    }
    if (role === "receiver") {
      return "sender";
    }
    return "remote-viewer";
  }

  function buildDisplayName(firstName, lastName) {
    return [String(firstName || "").trim(), String(lastName || "").trim()].filter(Boolean).join(" ").trim();
  }

  function normalizeDifficultyLevel(level) {
    return ["1", "2", "3", "4", "5"].includes(String(level || "")) ? String(level) : "1";
  }

  function normalizeIdentifierForStorage(name) {
    return String(name || "")
      .replace(/\s+/g, " ")
      .trim()
      .toLowerCase();
  }

  function rememberIdentifierStatus(inputIdentifier, status, sourceState = null) {
    const normalizedInput = normalizeIdentifierForStorage(inputIdentifier);
    if (!normalizedInput || !status || typeof status !== "object") {
      return sourceState || readLauncherState();
    }

    const state = sourceState || readLauncherState();
    state.identifierStatusMap = typeof state.identifierStatusMap === "object" && state.identifierStatusMap
      ? state.identifierStatusMap
      : {};

    const normalizedStatus = {
      input_identifier: String(status.input_identifier || inputIdentifier || "").trim(),
      preferred_identifier: String(status.preferred_identifier || "").trim(),
      preferred_handle: String(status.preferred_handle || "").trim(),
      owner_identifier: String(status.owner_identifier || "").trim(),
      uses_handle: !!status.uses_handle,
      is_handle: !!status.is_handle,
      identifier_exists: !!status.identifier_exists,
      updated_at: Date.now()
    };

    const keys = uniqueNames([
      normalizedInput,
      normalizeIdentifierForStorage(normalizedStatus.input_identifier),
      normalizeIdentifierForStorage(normalizedStatus.preferred_identifier),
      normalizeIdentifierForStorage(normalizedStatus.preferred_handle),
      normalizeIdentifierForStorage(normalizedStatus.owner_identifier)
    ]);

    keys.forEach((key) => {
      if (key) {
        state.identifierStatusMap[key] = normalizedStatus;
      }
    });

    writeLauncherState(state);
    return state;
  }

  function getCachedIdentifierStatus(identifier, sourceState = null) {
    const key = normalizeIdentifierForStorage(identifier);
    if (!key) {
      return null;
    }
    const state = sourceState || readLauncherState();
    const map = typeof state.identifierStatusMap === "object" && state.identifierStatusMap
      ? state.identifierStatusMap
      : {};
    return map[key] || null;
  }

  function getPreferredIdentifier(identifier, sourceState = null) {
    const raw = String(identifier || "").trim();
    if (!raw) {
      return "";
    }
    const cached = getCachedIdentifierStatus(raw, sourceState);
    const preferred = String(cached?.preferred_identifier || "").trim();
    return preferred || raw;
  }

  function usesHandlePresentation(identifier, status = null) {
    const raw = String(identifier || "").trim();
    if (!raw) {
      return false;
    }

    if (isValidUniqueHandle(raw) && !isValidEmailAddress(raw)) {
      return true;
    }

    return !!status?.is_handle;
  }

  function isAcceptedUniqueHandleIdentifier(identifier, status = null) {
    const raw = String(identifier || "").trim();
    if (!raw || isValidEmailAddress(raw) || !isValidUniqueHandle(raw)) {
      return false;
    }
    const preferredHandle = String(status?.preferred_handle || "").trim();
    return !!status?.uses_handle && !!preferredHandle;
  }

  function assertAcceptedLauncherIdentifier(identifier, status, fieldName, options = {}) {
    const raw = String(identifier || "").trim();
    const cleanIdentifier = assertValidParticipantIdentifier(raw, fieldName);
    const allowClaimPrompt = options.allowClaimPrompt !== false;
    if (isValidEmailAddress(cleanIdentifier)) {
      return cleanIdentifier;
    }
    if (!isValidUniqueHandle(cleanIdentifier)) {
      throw new Error(`${fieldName} must be a valid email address or accepted unique handle.`);
    }
    if (!status) {
      throw new Error(`Unable to verify whether ${fieldName.toLowerCase()} is an accepted unique handle right now.`);
    }
    if (!isAcceptedUniqueHandleIdentifier(cleanIdentifier, status)) {
      if (allowClaimPrompt) {
        throw new Error(`${fieldName} is not an accepted unique handle. To use it, first choose a unique name and claim that handle.`);
      }
      throw new Error(`${fieldName} is not an accepted unique handle. That person must claim the handle for themselves before you can use it here.`);
    }
    return String(status.preferred_identifier || cleanIdentifier).trim() || cleanIdentifier;
  }

  async function resolveAcceptedPartnerIdentifier(identifier, fieldName) {
    const cleanIdentifier = assertValidParticipantIdentifier(identifier, fieldName, { required: false });
    if (!cleanIdentifier) {
      return "";
    }
    if (isValidEmailAddress(cleanIdentifier)) {
      return cleanIdentifier;
    }

    const status = await fetchIdentifierStatus(cleanIdentifier);
    rememberIdentifierStatus(cleanIdentifier, status);
    return assertAcceptedLauncherIdentifier(cleanIdentifier, status, fieldName, { allowClaimPrompt: false });
  }

  function getRoleIdentifierStatusElement(role) {
    return document.querySelector(`[data-role-identifier-status="${role}"]`);
  }

  function clearRoleIdentifierStatus(role) {
    const element = getRoleIdentifierStatusElement(role);
    if (!element) {
      return;
    }
    element.textContent = "";
    element.hidden = true;
  }

  function showRoleIdentifierStatus(role, message) {
    const element = getRoleIdentifierStatusElement(role);
    if (!element) {
      return;
    }
    element.textContent = String(message || "").trim();
    element.hidden = !element.textContent;
  }

  function replaceIdentifierValue(value, previousIdentifier, nextIdentifier) {
    const current = String(value || "").trim();
    if (!current) {
      return current;
    }
    return normalizeIdentifierForStorage(current) === normalizeIdentifierForStorage(previousIdentifier)
      ? nextIdentifier
      : current;
  }

  function replaceIdentifierList(items, previousIdentifier, nextIdentifier) {
    return uniqueNames(
      (Array.isArray(items) ? items : []).map((item) => replaceIdentifierValue(item, previousIdentifier, nextIdentifier))
    );
  }

  function propagateClaimedHandle(previousIdentifier, acceptedHandle) {
    const prior = String(previousIdentifier || "").trim();
    const next = String(acceptedHandle || "").trim();
    if (!prior || !next) {
      return;
    }

    migrateRuntimeSettingsIdentifier(prior, next);
    const state = readLauncherState();
    state.ownNames = state.ownNames || {};
    state.currentPartners = state.currentPartners || {};
    state.partnerHistory = state.partnerHistory || {};
    state.deletedPartners = state.deletedPartners || {};
    state.launcherProfiles = state.launcherProfiles || {};

    if (!state.recognizedIdentity || normalizeIdentifierForStorage(state.recognizedIdentity) === normalizeIdentifierForStorage(prior)) {
      state.recognizedIdentity = next;
    }

    ["sender", "receiver"].forEach((role) => {
      state.ownNames[role] = replaceIdentifierValue(state.ownNames[role], prior, next);
      state.currentPartners[role] = replaceIdentifierValue(state.currentPartners[role], prior, next);
    });

    Object.keys(state.partnerHistory).forEach((key) => {
      state.partnerHistory[key] = replaceIdentifierList(state.partnerHistory[key], prior, next);
    });

    Object.keys(state.deletedPartners).forEach((key) => {
      state.deletedPartners[key] = uniqueNames([
        ...replaceIdentifierList(state.deletedPartners[key], prior, next),
        prior
      ]);
    });

    Object.keys(state.launcherProfiles).forEach((key) => {
      const profile = state.launcherProfiles[key];
      if (!profile || typeof profile !== "object") {
        return;
      }
      profile.currentPartner = replaceIdentifierValue(profile.currentPartner, prior, next);
      profile.partnerHistory = replaceIdentifierList(profile.partnerHistory, prior, next);
      profile.deletedPartners = uniqueNames([
        ...replaceIdentifierList(profile.deletedPartners, prior, next),
        prior
      ]);
    });

    const temporaryIdentity = getTemporaryIdentityState(state);
    if (temporaryIdentity && normalizeIdentifierForStorage(temporaryIdentity.identifier) === normalizeIdentifierForStorage(prior)) {
      state.temporaryIdentity = null;
    }

    writeLauncherState(state);

    roleCards.forEach((card) => {
      const form = card.querySelector("[data-role-form]");
      if (!form) {
        return;
      }
      const ownInput = form.querySelector('input[name="ownName"]');
      const partnerInput = form.querySelector('input[name="partnerName"]');
      if (ownInput && normalizeIdentifierForStorage(ownInput.value) === normalizeIdentifierForStorage(prior)) {
        ownInput.value = next;
      }
      if (partnerInput && normalizeIdentifierForStorage(partnerInput.value) === normalizeIdentifierForStorage(prior)) {
        partnerInput.value = next;
      }
      applyPartnerHistory(String(card.dataset.roleCard || ""), form, readLauncherState(), String(ownInput?.value || "").trim());
      void syncRoleIdentifierPresentation(String(card.dataset.roleCard || ""), form);
      void persistLauncherProfileForForm(String(card.dataset.roleCard || ""), form, readLauncherState());
    });
  }

  function propagatePartnerIdentifierMigration(previousIdentifier, nextIdentifier) {
    const prior = String(previousIdentifier || "").trim();
    const next = String(nextIdentifier || "").trim();
    if (!prior || !next) {
      return;
    }

    migrateRuntimeSettingsIdentifier(prior, next);
    const state = readLauncherState();
    state.currentPartners = state.currentPartners || {};
    state.partnerHistory = state.partnerHistory || {};
    state.deletedPartners = state.deletedPartners || {};
    state.launcherProfiles = state.launcherProfiles || {};

    ["sender", "receiver"].forEach((role) => {
      state.currentPartners[role] = replaceIdentifierValue(state.currentPartners[role], prior, next);
    });

    Object.keys(state.partnerHistory).forEach((key) => {
      state.partnerHistory[key] = replaceIdentifierList(state.partnerHistory[key], prior, next);
    });

    Object.keys(state.deletedPartners).forEach((key) => {
      state.deletedPartners[key] = uniqueNames([
        ...replaceIdentifierList(state.deletedPartners[key], prior, next),
        prior
      ]);
    });

    Object.keys(state.launcherProfiles).forEach((key) => {
      const profile = state.launcherProfiles[key];
      if (!profile || typeof profile !== "object") {
        return;
      }
      profile.currentPartner = replaceIdentifierValue(profile.currentPartner, prior, next);
      profile.partnerHistory = replaceIdentifierList(profile.partnerHistory, prior, next);
      profile.deletedPartners = uniqueNames([
        ...replaceIdentifierList(profile.deletedPartners, prior, next),
        prior
      ]);
    });

    writeLauncherState(state);

    roleCards.forEach((card) => {
      const role = String(card.dataset.roleCard || "");
      const form = card.querySelector("[data-role-form]");
      if (!role || !form) {
        return;
      }
      const ownInput = form.querySelector('input[name="ownName"]');
      const partnerInput = form.querySelector('input[name="partnerName"]');
      if (partnerInput && normalizeIdentifierForStorage(partnerInput.value) === normalizeIdentifierForStorage(prior)) {
        partnerInput.value = next;
      }
      applyPartnerHistory(role, form, readLauncherState(), String(ownInput?.value || "").trim());
      void syncRoleIdentifierPresentation(role, form);
      void persistLauncherProfileForForm(role, form, readLauncherState());
    });

    return readLauncherState();
  }

  function normalizeNameForSession(name) {
    return String(name || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "");
  }

  function buildSessionCodeFromNames(ownName, partnerName) {
    const state = readLauncherState();
    const pair = [
      normalizeNameForSession(getPreferredIdentifier(ownName, state)),
      normalizeNameForSession(getPreferredIdentifier(partnerName, state))
    ]
      .filter(Boolean)
      .sort();
    return pair.length === 2 ? `${pair[0]}__${pair[1]}` : "";
  }

  function buildLauncherProfileKey(role, ownIdentifier) {
    const normalizedRole =
      role === "sender"
        ? "sender"
        : role === "remote-viewer"
          ? "remote-viewer"
          : "receiver";
    const normalizedIdentifier = normalizeIdentifierForStorage(getPreferredIdentifier(ownIdentifier));
    return normalizedIdentifier ? `${normalizedRole}::${normalizedIdentifier}` : `${normalizedRole}::`;
  }

  function buildRobotSimulationDifficultyKey(role, ownIdentifier) {
    const normalizedRole =
      role === "sender"
        ? "sender"
        : role === "remote-viewer"
          ? "remote-viewer"
          : "receiver";
    const normalizedIdentifier = normalizeIdentifierForStorage(getPreferredIdentifier(ownIdentifier));
    return normalizedIdentifier ? `${normalizedRole}::${normalizedIdentifier}::robot` : `${normalizedRole}::::robot`;
  }

  function getRobotSimulationDifficulty(role, ownIdentifier, state = readLauncherState()) {
    const key = buildRobotSimulationDifficultyKey(role, ownIdentifier);
    return normalizeDifficultyLevel(
      state?.robotSimulationDifficultyLevels?.[key] ||
      state?.roleDifficultyLevels?.[role] ||
      readRoleSettings(role).difficultyLevel ||
      state?.difficultyLevel ||
      "1"
    );
  }

  function persistRobotSimulationDifficulty(role, ownIdentifier, level) {
    const normalizedRole = String(role || "").trim();
    const normalizedOwnIdentifier = String(ownIdentifier || "").trim();
    if (!normalizedRole || !normalizedOwnIdentifier) {
      return;
    }
    const latest = readLauncherState();
    latest.robotSimulationDifficultyLevels = latest.robotSimulationDifficultyLevels || {};
    latest.robotSimulationDifficultyLevels[buildRobotSimulationDifficultyKey(normalizedRole, normalizedOwnIdentifier)] = normalizeDifficultyLevel(level);
    writeLauncherState(latest);
  }

  function readLauncherProfileState(role, ownIdentifier, state = readLauncherState()) {
    const profileKey = buildLauncherProfileKey(role, ownIdentifier);
    const launcherProfiles = typeof state.launcherProfiles === "object" && state.launcherProfiles
      ? state.launcherProfiles
      : {};
    const scoped = launcherProfiles[profileKey];
    const legacyPartnerKey = partnerRole(role);
    return {
      currentPartner: String(scoped?.currentPartner || state.currentPartners?.[role] || "").trim(),
      // Prefer the role-wide difficulty memory over older per-profile snapshots so
      // a freshly changed Sender/Receiver level survives reloads cleanly.
      difficultyLevel: normalizeDifficultyLevel(state.roleDifficultyLevels?.[role] || scoped?.difficultyLevel || state.difficultyLevel || "1"),
      partnerHistory: uniqueNames([
        ...(Array.isArray(scoped?.partnerHistory) ? scoped.partnerHistory : []),
        ...(Array.isArray(state.partnerHistory?.[legacyPartnerKey]) ? state.partnerHistory[legacyPartnerKey] : [])
      ]),
      deletedPartners: uniqueNames([
        ...(Array.isArray(scoped?.deletedPartners) ? scoped.deletedPartners : []),
        ...(Array.isArray(state.deletedPartners?.[legacyPartnerKey]) ? state.deletedPartners[legacyPartnerKey] : [])
      ])
    };
  }

  function writeLauncherProfileState(role, ownIdentifier, profileState) {
    const latest = readLauncherState();
    latest.launcherProfiles = latest.launcherProfiles || {};
    latest.currentPartners = latest.currentPartners || {};
    latest.partnerHistory = latest.partnerHistory || {};
    latest.deletedPartners = latest.deletedPartners || {};
    latest.launcherProfiles[buildLauncherProfileKey(role, ownIdentifier)] = {
      currentPartner: String(profileState?.currentPartner || "").trim(),
      difficultyLevel: normalizeDifficultyLevel(profileState?.difficultyLevel || latest.roleDifficultyLevels?.[role] || latest.difficultyLevel || "1"),
      partnerHistory: uniqueNames(Array.isArray(profileState?.partnerHistory) ? profileState.partnerHistory : []),
      deletedPartners: uniqueNames(Array.isArray(profileState?.deletedPartners) ? profileState.deletedPartners : [])
    };
    latest.currentPartners[role] = String(profileState?.currentPartner || "").trim();
    latest.partnerHistory[partnerRole(role)] = uniqueNames(Array.isArray(profileState?.partnerHistory) ? profileState.partnerHistory : []);
    latest.deletedPartners[partnerRole(role)] = uniqueNames(Array.isArray(profileState?.deletedPartners) ? profileState.deletedPartners : []);
    if (ownIdentifier) {
      latest.ownNames = latest.ownNames || {};
      latest.ownNames[role] = ownIdentifier;
    }
    writeLauncherState(latest);
    return latest;
  }

  function readRoleSettings(role) {
    try {
      const raw = localStorage.getItem(`cones-settings-v2-${role}`);
      const parsed = raw ? JSON.parse(raw) : {};
      return {
        ownName: String(parsed?.own_email || "").trim(),
        partnerName: String(parsed?.partner_email || "").trim(),
        difficultyLevel: normalizeDifficultyLevel(parsed?.difficulty_level || "1")
      };
    } catch (error) {
      return {
        ownName: "",
        partnerName: "",
        difficultyLevel: "1"
      };
    }
  }

  function readRuntimeSettings(role) {
    try {
      const raw = localStorage.getItem(`cones-settings-v2-${role}`);
      const parsed = raw ? JSON.parse(raw) : {};
      return {
        ...parsed,
        allow_second_choice: typeof parsed?.allow_second_choice === "boolean" ? parsed.allow_second_choice : false,
        import_csv_filename: typeof parsed?.import_csv_filename === "string" ? parsed.import_csv_filename : ""
      };
    } catch (error) {
      return {
        allow_second_choice: false,
        import_csv_filename: ""
      };
    }
  }

  function writeRuntimeSettings(role, updates) {
    const next = {
      ...readRuntimeSettings(role),
      ...updates
    };
    localStorage.setItem(`cones-settings-v2-${role}`, JSON.stringify(next));
    return next;
  }

  function clearRuntimeSettings(role) {
    try {
      localStorage.removeItem(`cones-settings-v2-${role}`);
    } catch (error) {
      // Ignore local cleanup failures.
    }
  }

  function persistLauncherRuntimeIdentity(role, ownIdentifier, partnerIdentifier, extraUpdates = {}) {
    const cleanOwn = String(ownIdentifier || "").trim();
    const cleanPartner = String(partnerIdentifier || "").trim();
    if (!cleanOwn && !cleanPartner && !Object.keys(extraUpdates || {}).length) {
      return;
    }
    writeRuntimeSettings(role, {
      own_email: cleanOwn,
      partner_email: cleanPartner,
      ...extraUpdates
    });
  }

  function migrateRuntimeSettingsIdentifier(previousIdentifier, nextIdentifier) {
    const prior = String(previousIdentifier || "").trim();
    const next = String(nextIdentifier || "").trim();
    if (!prior || !next) {
      return;
    }

    ["sender", "receiver"].forEach((role) => {
      const current = readRuntimeSettings(role);
      const updates = {};
      let changed = false;

      if (normalizeIdentifierForStorage(current.own_email) === normalizeIdentifierForStorage(prior)) {
        updates.own_email = next;
        changed = true;
      }
      if (normalizeIdentifierForStorage(current.partner_email) === normalizeIdentifierForStorage(prior)) {
        updates.partner_email = next;
        changed = true;
      }

      if (changed) {
        writeRuntimeSettings(role, updates);
      }
    });
  }

  async function checkAdminSecret(secretCandidate) {
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action: "check_admin_secret",
        secret_candidate: String(secretCandidate || "")
      })
    });

    if (!response.ok) {
      throw new Error(`Admin secret check failed with status ${response.status}`);
    }

    const data = await response.json();
    return !!data?.admin_secret_match;
  }

  async function fetchAdminAccessMode() {
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action: "get_admin_access_mode"
      })
    });

    return parseApiResponse(response, `Admin access mode request failed with status ${response.status}`);
  }

  function getLauncherAdminSecretCandidate() {
    const explicitSecret = String(launcherAdminSecret || "").trim();
    if (explicitSecret) {
      return explicitSecret;
    }
    return String(launcherAdminDevicePrefs.cached_secret || "").trim();
  }

  function hasLauncherAdminAccess() {
    return !!getLauncherAdminSecretCandidate() || !!launcherAdminState.easy_admin_enabled;
  }

  function hasExplicitLauncherAdminSecret() {
    return !!String(launcherAdminSecret || "").trim();
  }

  async function launcherAdminApi(action, payload = {}) {
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action,
        secret_candidate: getLauncherAdminSecretCandidate(),
        ...payload
      })
    });

    if (!response.ok) {
      throw new Error(`Admin request failed with status ${response.status}`);
    }

    return response.json();
  }

  async function recordLauncherVisit() {
    try {
      await fetch("api.php", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          action: "record_launcher_visit",
          frontend_build_version: launcherBuildVersion
        })
      });
    } catch (error) {
      // Ignore visit-count failures so the launcher remains unaffected.
    }
  }

  function snapshotUserTypeAdminState() {
    return {
      input_value: String(userTypeHandleInput?.value || "").trim(),
      current_handle: currentUserTypeAdminHandle,
      pending_selection: pendingUserTypeSelection,
      status_text: String(userTypeStatus?.textContent || "").trim(),
      wrap_hidden: !!userTypeOptionsWrap?.hidden,
      save_hidden: !!userTypeSaveButton?.hidden,
      choices: userTypeChoiceButtons.map((button) => ({
        value: String(button.dataset.userTypeChoiceButton || ""),
        selected: button.classList.contains("is-selected"),
        aria_pressed: button.getAttribute("aria-pressed"),
        disabled: !!button.disabled
      }))
    };
  }

  function logUserTypeAdminDebug(label, extraDetails = []) {
    if (!hasLauncherAdminAccess()) {
      return;
    }
    const details = Array.isArray(extraDetails) ? extraDetails.slice(0) : [];
    details.unshift(snapshotUserTypeAdminState());
    void launcherAdminApi("log_debug", {
      label: `user_type_admin:${label}`,
      details,
      device_debug_enabled: !!launcherAdminState.debug_enabled
    }).catch(() => {
      // Ignore debug logging failures.
    });
  }

  function logLauncherDirectOpenDebug(label, details = {}) {
    if (!hasLauncherAdminAccess() || !launcherAdminState.debug_enabled) {
      return;
    }
    void launcherAdminApi("log_debug", {
      label: `launcher_direct_open:${label}`,
      details: [{
        page_instance_id: launcherPageInstanceId,
        ...(details && typeof details === "object" ? details : {})
      }],
      device_debug_enabled: !!launcherAdminState.debug_enabled
    }).catch(() => {
      // Ignore debug logging failures.
    });
  }

  function logLauncherUserTypeDebug(label, details = {}) {
    if (!hasLauncherAdminAccess() || !launcherAdminState.debug_enabled) {
      return;
    }
    void launcherAdminApi("log_debug", {
      label: `launcher_user_type:${label}`,
      details: [details],
      device_debug_enabled: !!launcherAdminState.debug_enabled
    }).catch(() => {
      // Ignore debug logging failures.
    });
  }

  function appendGuidedReturnTrace(label, details = {}) {
    try {
      const raw = localStorage.getItem(guidedReturnTraceKey);
      const entries = Array.isArray(raw ? JSON.parse(raw) : null) ? JSON.parse(raw) : [];
      entries.push({
        label: String(label || "").trim(),
        timestamp: new Date().toISOString(),
        pageInstanceId: launcherPageInstanceId,
        href: String(window.location.href || "").trim(),
        details: details && typeof details === "object" ? details : {}
      });
      while (entries.length > 40) {
        entries.shift();
      }
      localStorage.setItem(guidedReturnTraceKey, JSON.stringify(entries));
    } catch (error) {
      // Ignore local trace write failures.
    }
  }

  function logGoProCheckoutDebug(label, details = {}) {
    const payload = {
      ...(details && typeof details === "object" ? details : {}),
      href: String(window.location.href || "").trim(),
      recognizedIdentity: String(getCanonicalRecognizedIdentity(readLauncherState()) || "").trim(),
      currentIdentifier: String(getCurrentTelepathyProIdentifier() || "").trim(),
      stripeCheckoutInFlight: !!stripeCheckoutInFlight
    };
    logLauncherUserTypeDebug(`go_pro_checkout:${label}`, payload);
    traceLauncherClient(`go_pro_checkout:${label}`, payload);
  }

  function traceLauncherClient(label, details = {}) {
    void fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action: "trace_client",
        label,
        details: [details]
      })
    }).catch(() => {
      // Ignore trace failures.
    });
  }

  function readRoleFormValues(role) {
    const form = document.querySelector(`[data-role-form="${role}"]`);
    if (!form) {
      return {
        ownName: "",
        partnerName: ""
      };
    }

    return {
      ownName: String(form.elements.ownName?.value || "").trim(),
      partnerName: String(form.elements.partnerName?.value || "").trim()
    };
  }

  function getRoleLabelElements(role) {
    const form = document.querySelector(`[data-role-form="${role}"]`);
    return {
      form,
      ownLabel: document.querySelector(`[data-own-identifier-label="${role}"]`),
      partnerLabel: document.querySelector(`[data-partner-identifier-label="${role}"]`),
      note: document.querySelector(`[data-role-identifier-note="${role}"]`)
    };
  }

  function getRoleHandleWrap(role) {
    return document.querySelector(`[data-role-handle-wrap="${role}"]`);
  }

  function getRoleVisitorProWrap(role) {
    return document.querySelector(`[data-role-visitor-pro-wrap="${role}"]`);
  }

  function getRoleHandleButton(role) {
    return document.querySelector(`[data-open-handle-control="${role}"]`);
  }

  function isRobotSimulationIdentifier(value) {
    return String(value || "").replace(/\s+/g, " ").trim().toLowerCase() === "robot";
  }

  function getPartnerIdentifierDisplayLabel(role) {
    if (role === "sender") {
      return `Receiver - Enter "Robot" to experience a simulation of telepathy practice at this level.`;
    }
    if (role === "receiver") {
      return `Sender - Enter "Robot" to experience a simulation of telepathy practice at this level.`;
    }
    return "Partner";
  }

  function getPartnerIdentifierShortLabel(role) {
    if (role === "sender") {
      return "Receiver";
    }
    if (role === "receiver") {
      return "Sender";
    }
    return "Partner";
  }

  function shouldHideHandleLink(role) {
    const normalizedRole = String(role || "").trim();
    if (!normalizedRole) {
      return false;
    }
    if (isVisitorLauncherEntry() && (normalizedRole === "sender" || normalizedRole === "receiver")) {
      return true;
    }
    let ownValue = "";
    if (normalizedRole === "remote-viewer") {
      ownValue = String(remoteViewerOwnInput?.value || "").trim();
    } else {
      ownValue = String(readRoleFormValues(normalizedRole).ownName || "").trim();
    }
    if (!ownValue) {
      return false;
    }
    if (isLandingExploreTemporaryIdentity(ownValue)) {
      return false;
    }
    const ownStatus = getCachedIdentifierStatus(ownValue);
    return usesHandlePresentation(ownValue, ownStatus);
  }

  function isLocationFeatureReady(state = readLauncherState()) {
    const permission = String(state?.locationPermission || "").trim().toLowerCase();
    const savedLocation = getSavedDeviceLocation(state);
    return !!savedLocation && (permission === "granted" || permission === "manual");
  }

  function shouldShowFeatureSetupPromptForIdentifier(identifier, identifierStatus = null) {
    const cleanIdentifier = String(identifier || "").trim();
    if (!cleanIdentifier || isLandingExploreTemporaryIdentity(cleanIdentifier)) {
      return false;
    }
    const status = identifierStatus || getCachedIdentifierStatus(cleanIdentifier);
    const acceptedHandle = (status && isAcceptedUniqueHandleIdentifier(cleanIdentifier, status))
      || (isValidUniqueHandle(cleanIdentifier) && !isValidEmailAddress(cleanIdentifier));
    if (!acceptedHandle) {
      return false;
    }
    if (!isRunningAsInstalledApp()) {
      return true;
    }
    if (!isLocationFeatureReady()) {
      return true;
    }
    if (!isEffectiveLauncherUserPro()) {
      return false;
    }
    const notificationPermission = syncNotificationPermissionSnapshot();
    if (notificationPermission !== "granted") {
      return true;
    }
    return false;
  }

  function setRoleFeatureSetupPrompt(role, visible) {
    const setupWrap = getRoleSetupWrap(role);
    if (!setupWrap) {
      return;
    }
    const setupButton = setupWrap.querySelector("[data-open-feature-setup]");
    if (setupButton) {
      setupButton.textContent = getDisplayedLauncherUserType() === "pro"
        ? "Click here to set up optional features for ESP PRO"
        : "Click here to set up optional features for Telepathy Beginner";
    }
    setupWrap.dataset.available = visible ? "true" : "false";
    setupWrap.hidden = !visible;
  }

  function applyRoleIdentifierPresentation(role, options = {}) {
    const { ownUsesHandle = false, partnerUsesHandle = false } = options;
    const { ownLabel, partnerLabel } = getRoleLabelElements(role);
    const handleWrap = getRoleHandleWrap(role);
    const handleButton = getRoleHandleButton(role);
    const isVisitorRole = isVisitorLauncherEntry() && (role === "sender" || role === "receiver");
    const temporaryIdentity = getTemporaryIdentityState();
    const formValues = readRoleFormValues(role);
    const ownIdentifier = String(formValues?.ownName || "").trim();
    const usesTemporaryIdentity = !!temporaryIdentity
      && temporaryIdentity.source === "landing-explore-pro"
      && normalizeIdentifierForStorage(ownIdentifier) === normalizeIdentifierForStorage(temporaryIdentity.identifier);
    const setupPromptVisible = shouldShowFeatureSetupPromptForIdentifier(ownIdentifier);
    if (ownLabel) {
      ownLabel.textContent = "You";
    }
    if (partnerLabel) {
      partnerLabel.textContent = getPartnerIdentifierDisplayLabel(role);
    }
    setRoleMessagePresentation(role, "default");
    if (usesTemporaryIdentity) {
      setRoleDefaultNoteText(role, buildTemporaryIdentityNote(temporaryIdentity.identifier));
    } else if (isVisitorRole) {
      setRoleDefaultNoteHtml(role, buildVisitorRoleNoteHtml(role), buildVisitorRoleNote(role));
    } else if (ownUsesHandle) {
      setRoleDefaultNoteText(role, "");
    } else {
      setRoleDefaultNoteHtml(role, buildDefaultEmailIdentityNoteHtml(role), buildDefaultEmailIdentityNote(role));
    }
    if (handleWrap) {
      handleWrap.hidden = usesTemporaryIdentity ? false : (isVisitorRole ? true : ownUsesHandle);
    }
    if (handleButton) {
      handleButton.textContent = isVisitorRole
        ? "here"
        : usesTemporaryIdentity
        ? getTemporaryIdentityLinkText(temporaryIdentity.identifier)
        : "Choose unique name instead of email address";
    }
    setRoleVisitorProPrompt(role, false);
    setRoleFeatureSetupPrompt(role, !usesTemporaryIdentity && ownUsesHandle && setupPromptVisible);
    if (shouldShowEspLessonForRole(role)) {
      void refreshRoleEspLesson(role);
    } else {
      clearRoleLessonDisplay(role);
    }
  }

  async function syncRoleIdentifierPresentation(role, form, options = {}) {
    const ownInput = form.querySelector('input[name="ownName"]');
    const partnerInput = form.querySelector('input[name="partnerName"]');
    let migratedPartnerIdentifier = null;
    let ownUsesHandle = false;
    let partnerUsesHandle = false;

    const ownValue = String(ownInput?.value || "").trim();
    if (ownValue) {
      try {
        const ownStatus = await fetchIdentifierStatus(ownValue);
        rememberIdentifierStatus(ownValue, ownStatus);
        const preferredOwn = String(ownStatus?.preferred_identifier || "").trim();
        if (preferredOwn && preferredOwn !== ownValue && normalizeIdentifierForStorage(preferredOwn) === normalizeIdentifierForStorage(ownValue)) {
          ownInput.value = preferredOwn;
        }
        ownUsesHandle = usesHandlePresentation(ownValue, ownStatus);
      } catch (error) {
        ownUsesHandle = isValidUniqueHandle(ownValue) && !isValidEmailAddress(ownValue);
      }
    }

    const partnerValue = String(partnerInput?.value || "").trim();
    if (partnerValue) {
      try {
        const partnerStatus = await fetchIdentifierStatus(partnerValue);
        rememberIdentifierStatus(partnerValue, partnerStatus);
        const preferredPartner = String(partnerStatus?.preferred_identifier || "").trim();
        if (preferredPartner && normalizeIdentifierForStorage(preferredPartner) !== normalizeIdentifierForStorage(partnerValue)) {
          migratedPartnerIdentifier = {
            previous: partnerValue,
            next: preferredPartner
          };
          if (partnerInput) {
            partnerInput.value = preferredPartner;
          }
          propagatePartnerIdentifierMigration(partnerValue, preferredPartner);
        } else if (preferredPartner && preferredPartner !== partnerValue) {
          if (partnerInput) {
            partnerInput.value = preferredPartner;
          }
        }
        partnerUsesHandle = usesHandlePresentation(preferredPartner || partnerValue, partnerStatus);
      } catch (error) {
        partnerUsesHandle = isValidUniqueHandle(partnerValue) && !isValidEmailAddress(partnerValue);
      }
    }

    applyRoleIdentifierPresentation(role, { ownUsesHandle, partnerUsesHandle, ...options });

    if (migratedPartnerIdentifier) {
      showRoleIdentifierStatus(role, `Your partner now uses unique handle: ${migratedPartnerIdentifier.next}.`);
      void persistLauncherProfileForForm(role, form);
    } else {
      clearRoleIdentifierStatus(role);
    }
    void refreshRoleMessaging(role);
  }

  function openHandleOverlay(role) {
    activeHandleRole = role === "sender" || role === "receiver" || role === "remote-viewer" ? role : "";
    if (!activeHandleRole) {
      return;
    }
    handleOverlayReturnRole = activeHandleRole;
    if (handleStatus) {
      handleStatus.textContent = "";
    }
    if (handleInput) {
      handleInput.value = "";
    }
    setFeatureSetupBackButtonTemporarilyHidden(true);
    handleOverlay?.classList.remove("beginner-view-hidden");
    handleInput?.focus();
  }

  function closeHandleOverlay() {
    const returnRole = handleOverlayReturnRole;
    activeHandleRole = "";
    handleOverlayReturnRole = "";
    featureSetupPendingHandleFlow = "";
    handleOverlay?.classList.add("beginner-view-hidden");
    if (handleStatus) {
      handleStatus.textContent = "";
    }
    setFeatureSetupBackButtonTemporarilyHidden(false);
    if (returnRole) {
      const matchingCard = roleCards.find((card) => card.dataset.roleCard === returnRole);
      if (matchingCard) {
        ensureCardExpanded(matchingCard);
      }
    }
  }

  async function submitUniqueHandle() {
    if (!activeHandleRole) {
      closeHandleOverlay();
      return;
    }
    const isRemoteViewerRole = activeHandleRole === "remote-viewer";
    const form = isRemoteViewerRole ? null : document.querySelector(`[data-role-form="${activeHandleRole}"]`);
    if (!isRemoteViewerRole && !form) {
      closeHandleOverlay();
      return;
    }
    const ownInput = isRemoteViewerRole ? remoteViewerOwnInput : form.querySelector('input[name="ownName"]');
    const partnerInput = isRemoteViewerRole ? null : form.querySelector('input[name="partnerName"]');
    const visitorMode = isVisitorLauncherEntry();
    const currentIdentifier = visitorMode
      ? String(readLauncherState().visitorAlias || getOrCreateVisitorSimulationIdentifier()).trim()
      : String(ownInput?.value || "").trim();
    const proposedHandle = String(handleInput?.value || "").trim();

    if (handleStatus) {
      handleStatus.textContent = "Checking unique handle...";
    }

    try {
      const completedRole = activeHandleRole;
      const returnRole = handleOverlayReturnRole || completedRole;
      const returnScrollY = Math.max(0, Number(window.scrollY ?? window.pageYOffset ?? 0) || 0);
      const postClaimFlow = featureSetupPendingHandleFlow;
      if (visitorMode) {
        let proposedStatus = null;
        try {
          proposedStatus = await fetchIdentifierStatus(proposedHandle);
        } catch (_) {
          proposedStatus = null;
        }
        if (proposedStatus?.formal_identity_exists) {
          if (!proposedStatus.auth_email_on_file) {
            throw new Error("Your email address cannot be validated. Please contact ESP Gym.");
          }
          activeHandleRole = "";
          handleOverlayReturnRole = "";
          featureSetupPendingHandleFlow = "";
          handleOverlay?.classList.add("beginner-view-hidden");
          if (handleStatus) {
            handleStatus.textContent = "";
          }
          if (handleInput) {
            handleInput.value = "";
          }
          openExploreProOverlay({
            mode: "recovery",
            identifier: String(proposedStatus.preferred_identifier || proposedHandle).trim()
          });
          return;
        }
        activeHandleRole = "";
        handleOverlayReturnRole = "";
        featureSetupPendingHandleFlow = "";
        handleOverlay?.classList.add("beginner-view-hidden");
        if (handleStatus) {
          handleStatus.textContent = "";
        }
        if (handleInput) {
          handleInput.value = "";
        }
        openExploreProOverlay({
          mode: "claim",
          identifier: proposedHandle,
          role: completedRole,
          returnRole,
          returnScrollY,
          postClaimFlow,
          currentIdentifier
        });
        return;
      }
      const result = await claimUniqueHandle(currentIdentifier, proposedHandle);
      const acceptedHandle = String(result?.claim?.handle || proposedHandle).trim();
      if (result?.status) {
        rememberIdentifierStatus(currentIdentifier || acceptedHandle, result.status);
      }
      if (currentIdentifier && acceptedHandle) {
        propagateClaimedHandle(currentIdentifier, acceptedHandle);
      }
      if (ownInput && acceptedHandle) {
        ownInput.value = acceptedHandle;
      }
      if (isRemoteViewerRole) {
        persistRemoteViewerCardState();
        await hydrateRemoteViewerLauncherProfile();
      } else {
        await syncRoleIdentifierPresentation(activeHandleRole, form);
        if (partnerInput?.value.trim()) {
          await syncRoleIdentifierPresentation(activeHandleRole, form);
        }
        void persistLauncherProfileForForm(activeHandleRole, form);
      }
      if (isVisitorLauncherEntry() && acceptedHandle) {
        const latestState = readLauncherState();
        const normalizedUserType = String(result?.status?.user_type || "").trim().toLowerCase() === "pro" ? "pro" : "standard";
        const nextIdentityState = buildLauncherIdentityState(latestState, acceptedHandle, normalizedUserType, {
          recognizedIdentity: acceptedHandle,
          entryMode: ""
        });
        writeLauncherState(nextIdentityState);
        setLauncherProfileSaveSuppression(false, true);
        setLauncherGuestEntryActive(false);
        applyIdentityStateToLauncherInputs();
      }
      void refreshMainUserType();
      if (handleStatus) {
        handleStatus.textContent = acceptedHandle
          ? `Unique name accepted: ${acceptedHandle}`
          : "Unique name accepted.";
      }
      submitHandleButton && (submitHandleButton.disabled = true);
      await new Promise((resolve) => window.setTimeout(resolve, 2600));
      activeHandleRole = "";
      handleOverlayReturnRole = "";
      featureSetupPendingHandleFlow = "";
      handleOverlay?.classList.add("beginner-view-hidden");
      if (handleStatus) {
        handleStatus.textContent = "";
      }
      if (handleInput) {
        handleInput.value = "";
      }
      if (submitHandleButton) {
        submitHandleButton.disabled = false;
      }
      if (acceptedHandle && completedRole) {
        if (postClaimFlow === "install-gate") {
          showInstallGuideView({ returnView: "feature-setup" });
          return;
        }
        showFeatureSetupView({
          role: completedRole,
          returnView: featureSetupReturnView || (completedRole === "remote-viewer" ? "remote-viewer" : "card"),
          scrollY: featureSetupReturnView === "help" || featureSetupReturnView === "options"
            ? featureSetupReturnScrollY
            : returnScrollY
        });
        if ((featureSetupReturnView || "card") === "card" || completedRole === "remote-viewer") {
          const matchingCard = roleCards.find((card) => card.dataset.roleCard === returnRole);
          if (matchingCard) {
            ensureCardExpanded(matchingCard, { scrollIntoView: false });
          }
        }
      }
    } catch (error) {
      if (submitHandleButton) {
        submitHandleButton.disabled = false;
      }
      if (handleStatus) {
        handleStatus.textContent = error instanceof Error ? error.message : "Unable to accept that unique handle right now.";
      }
    }
  }

  function getNotificationPermissionSnapshot() {
    if (!("Notification" in window)) {
      return "unsupported";
    }
    return String(Notification.permission || "default").trim().toLowerCase() || "default";
  }

  function syncNotificationPermissionSnapshot() {
    const state = readLauncherState();
    state.notificationPermission = getNotificationPermissionSnapshot();
    writeLauncherState(state);
    return state.notificationPermission;
  }

  async function subscribeCurrentDeviceForIdentifier(identifier) {
    if (!("serviceWorker" in navigator) || !("PushManager" in window) || !("Notification" in window)) {
      throw new Error("This browser does not support app notifications.");
    }

    const cleanIdentifier = assertValidParticipantIdentifier(identifier, "your identifier");
    const permission = syncNotificationPermissionSnapshot();
    if (permission !== "granted") {
      throw new Error("Notifications are not currently allowed for this app.");
    }

    const registration = await navigator.serviceWorker.ready;
    const deviceId = getOrCreateMessagingDeviceId();
    const setupData = await fetchPushSetup(cleanIdentifier, deviceId);
    if (setupData?.identifier_status) {
      rememberIdentifierStatus(cleanIdentifier, setupData.identifier_status);
    }
    const publicKey = String(setupData?.web_push?.public_key || "").trim();
    if (!publicKey) {
      throw new Error(String(setupData?.web_push?.message || "Web Push is not configured right now."));
    }

    let subscription = await registration.pushManager.getSubscription();
    if (!subscription) {
      subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(publicKey)
      });
    }

    return savePushSubscription(cleanIdentifier, deviceId, subscription);
  }

  function getRoleIdentifiersForMessaging(role) {
    if (role === "remote-viewer") {
      return {
        ownIdentifier: String(remoteViewerOwnInput?.value || "").trim(),
        partnerIdentifier: String(remoteViewerPartnerInput?.value || "").trim()
      };
    }

    const form = document.querySelector(`[data-role-form="${role}"]`);
    return {
      ownIdentifier: String(form?.elements?.ownName?.value || "").trim(),
      partnerIdentifier: String(form?.elements?.partnerName?.value || "").trim()
    };
  }

  function getMessagingRecipientRole(role) {
    return role === "sender"
      ? "receiver"
      : role === "receiver"
        ? "sender"
        : "remote-viewer";
  }

  function getRoleMessageLaunchButton(role) {
    return openRoleMessagesButtons.find((item) => item.dataset.openRoleMessages === role) || null;
  }

  function getRoleMessageAvailabilityReason(role) {
    const normalizedRole = String(role || "").trim();
    if (!["sender", "receiver"].includes(normalizedRole)) {
      return "";
    }
    const { partnerIdentifier } = getRoleIdentifiersForMessaging(normalizedRole);
    if (isRobotSimulationIdentifier(partnerIdentifier)) {
      return 'Messaging is unavailable when your partner is "Robot".';
    }
    return "";
  }

  function applyRoleMessageAvailabilityState(role) {
    const normalizedRole = String(role || "").trim();
    const button = getRoleMessageLaunchButton(normalizedRole);
    const launchWrap = document.querySelector(`[data-role-messaging-launch="${normalizedRole}"]`);
    const reason = getRoleMessageAvailabilityReason(normalizedRole);
    const disabledForRobot = !!reason;

    if (launchWrap) {
      launchWrap.classList.toggle("is-role-message-disabled", disabledForRobot);
      if (disabledForRobot) {
        launchWrap.setAttribute("title", reason);
      } else {
        launchWrap.removeAttribute("title");
      }
    }

    if (!button) {
      return disabledForRobot;
    }

    button.disabled = disabledForRobot;
    if (disabledForRobot) {
      button.setAttribute("aria-disabled", "true");
      button.setAttribute("title", reason);
    } else if (!isProLockedButton(button)) {
      button.removeAttribute("aria-disabled");
      button.removeAttribute("title");
    } else {
      button.removeAttribute("title");
    }
    return disabledForRobot;
  }

  function getRoleMessageBadge(role) {
    return roleMessageBadges.find((item) => item.dataset.roleMessageBadge === role) || null;
  }

  function setRoleMessageBadge(role, unreadCount) {
    const badge = getRoleMessageBadge(role);
    if (!badge) {
      return;
    }
    const count = Math.max(0, Number(unreadCount) || 0);
    badge.hidden = false;
    if (count <= 0) {
      badge.textContent = "0";
      badge.classList.add("is-empty");
      badge.setAttribute("aria-hidden", "true");
      return;
    }
    badge.classList.remove("is-empty");
    badge.setAttribute("aria-hidden", "false");
    badge.textContent = count > 9 ? "9+" : String(count);
  }

  function setMessagesStatus(message = "", options = {}) {
    if (!messagesStatus) {
      return;
    }
    const text = String(message || "").trim();
    messagesStatus.textContent = text;
    messagesStatus.hidden = !text;
    messagesStatus.style.color = options.isError ? "rgba(255, 196, 196, 0.96)" : "rgba(255, 230, 176, 0.94)";
  }

  function formatConversationOptionLabel(partnerIdentifier, unreadCount = 0) {
    const base = String(partnerIdentifier || "").trim() || "Conversation";
    const count = Math.max(0, Number(unreadCount) || 0);
    return count > 0 ? `${base} (${count})` : base;
  }

  function getLastReadMsForPartner(inbox, partnerIdentifier) {
    const normalizedPartner = normalizeIdentifierForStorage(partnerIdentifier);
    if (!normalizedPartner) {
      return 0;
    }
    const conversations = Array.isArray(inbox?.conversations) ? inbox.conversations : [];
    const matchingConversation = conversations.find((conversation) => {
      return normalizeIdentifierForStorage(conversation?.partner_identifier) === normalizedPartner;
    });
    return Math.max(0, Number(matchingConversation?.last_read_ms || 0));
  }

  function getReadMessageIdsForPartner(inbox, partnerIdentifier) {
    const normalizedPartner = normalizeIdentifierForStorage(partnerIdentifier);
    if (!normalizedPartner) {
      return [];
    }
    const conversations = Array.isArray(inbox?.conversations) ? inbox.conversations : [];
    const matchingConversation = conversations.find((conversation) => {
      return normalizeIdentifierForStorage(conversation?.partner_identifier) === normalizedPartner;
    });
    return Array.isArray(matchingConversation?.read_message_ids)
      ? matchingConversation.read_message_ids.map((messageId) => String(messageId || "").trim()).filter(Boolean)
      : [];
  }

  function getUnreadConversationCountForPartner(inbox, partnerIdentifier) {
    const normalizedPartner = normalizeIdentifierForStorage(partnerIdentifier);
    if (!normalizedPartner) {
      return 0;
    }
    const conversations = Array.isArray(inbox?.conversations) ? inbox.conversations : [];
    const matchingConversation = conversations.find((conversation) => {
      return normalizeIdentifierForStorage(conversation?.partner_identifier) === normalizedPartner;
    });
    return Math.max(0, Number(matchingConversation?.unread_count || 0));
  }

  function clearUnreadConversationCountForPartner(inbox, partnerIdentifier) {
    if (!inbox || typeof inbox !== "object") {
      return inbox;
    }
    const normalizedPartner = normalizeIdentifierForStorage(partnerIdentifier);
    if (!normalizedPartner) {
      return inbox;
    }
    const conversations = Array.isArray(inbox.conversations) ? inbox.conversations : [];
    let totalUnread = 0;
    const nextConversations = conversations.map((conversation) => {
      const nextConversation = { ...conversation };
      if (normalizeIdentifierForStorage(conversation?.partner_identifier) === normalizedPartner) {
        nextConversation.unread_count = 0;
      }
      totalUnread += Math.max(0, Number(nextConversation?.unread_count || 0));
      return nextConversation;
    });
    return {
      ...inbox,
      conversations: nextConversations,
      total_unread: totalUnread
    };
  }

  function buildMessagingConversationList(inbox, preferredPartnerIdentifier = "") {
    const list = [];
    const seen = new Set();
    const conversations = Array.isArray(inbox?.conversations) ? inbox.conversations : [];

    conversations.forEach((conversation) => {
      const partnerIdentifier = String(conversation?.partner_identifier || "").trim();
      if (!partnerIdentifier) {
        return;
      }
      const key = normalizeIdentifierForStorage(partnerIdentifier);
      if (seen.has(key)) {
        return;
      }
      seen.add(key);
      list.push({
        partner_identifier: partnerIdentifier,
        unread_count: Number(conversation?.unread_count || 0),
        updated_ms: Number(conversation?.updated_ms || 0)
      });
    });

    const preferred = String(preferredPartnerIdentifier || "").trim();
    if (preferred && !seen.has(normalizeIdentifierForStorage(preferred))) {
      list.unshift({
        partner_identifier: preferred,
        unread_count: 0,
        updated_ms: 0
      });
    }

    return list;
  }

  function renderMessagesThread(thread, ownIdentifier, partnerIdentifier = "") {
    if (!messagesThread) {
      return;
    }
    const previousLastMessageId = String(messagesThread.dataset.lastMessageId || "").trim();
    const previousMessageCount = Number(messagesThread.dataset.messageCount || 0);
    const shouldFollowNewMessages = isRoleMessageThreadNearBottom(messagesThread);
    const ownKey = normalizeIdentifierForStorage(ownIdentifier);
    const lastReadMs = getLastReadMsForPartner(activeMessagesThreadInbox, partnerIdentifier);
    const readMessageIds = new Set(Array.isArray(activeMessagesReadMessageIds) ? activeMessagesReadMessageIds : []);
    const messages = Array.isArray(thread?.messages) ? thread.messages : [];
    if (!messages.length) {
      const emptyText = partnerIdentifier
        ? "Messaging is ready. Short notes between you and your partner will appear here."
        : "Choose a conversation to view messages.";
      messagesThread.innerHTML = `<div class="role-message-empty">${escapeHtml(emptyText)}</div>`;
      messagesThread.dataset.lastMessageId = "";
      messagesThread.dataset.messageCount = "0";
      return;
    }

    const nextLastMessageId = String(messages[messages.length - 1]?.id || "").trim();
    const hasNewMessage = nextLastMessageId !== "" && (nextLastMessageId !== previousLastMessageId || messages.length > previousMessageCount);
    messagesThread.innerHTML = messages.map((message) => {
      const messageId = String(message?.id || "").trim();
      const senderIdentifier = String(message?.sender_identifier || "").trim();
      const isOwn = normalizeIdentifierForStorage(senderIdentifier) === ownKey;
      const createdMs = Number(message?.created_ms || 0);
      const createdLabel = createdMs > 0 ? new Date(createdMs).toLocaleString() : "";
      const isUnread = !isOwn && createdMs > lastReadMs && !readMessageIds.has(messageId);
      const recipientSeen = !!message?.recipient_seen;
      return `
        <div class="role-message-bubble ${isOwn ? "is-own" : "is-partner"} ${isUnread ? "is-unread" : ""}" data-message-id="${escapeHtml(messageId)}">
          <div class="role-message-meta-row">
            <span class="role-message-meta">${isUnread ? `<span class="role-message-unread-dot" aria-hidden="true"></span>` : isOwn && recipientSeen ? `<span class="role-message-seen-dot" aria-hidden="true"></span>` : ""}${escapeHtml(isOwn ? "You" : senderIdentifier || "Partner")}${createdLabel ? ` - ${escapeHtml(createdLabel)}` : ""}</span>
            <button class="role-message-trash" type="button" data-messages-delete="${escapeHtml(messageId)}" aria-label="Delete this message" title="Delete this message">&#128465;</button>
          </div>
          <div>${escapeHtml(String(message?.text || ""))}</div>
        </div>
      `;
    }).join("");
    messagesThread.dataset.lastMessageId = nextLastMessageId;
    messagesThread.dataset.messageCount = String(messages.length);
    if (hasNewMessage && shouldFollowNewMessages) {
      messagesThread.scrollTop = messagesThread.scrollHeight;
    }
  }

  async function refreshRoleMessageButton(role) {
    if (applyRoleMessageAvailabilityState(role)) {
      setRoleMessageBadge(role, 0);
      return;
    }
    const inboxState = await fetchRoleMessageInboxState(role);
    if (!inboxState) {
      return;
    }
    setRoleMessageBadge(inboxState.role, inboxState.totalUnread);
  }

  async function fetchRoleMessageInboxState(role) {
    const normalizedRole = String(role || "").trim();
    if (!["sender", "receiver"].includes(normalizedRole)) {
      return null;
    }

    const button = getRoleMessageLaunchButton(normalizedRole);
    if (!button) {
      return null;
    }
    const { ownIdentifier } = getRoleIdentifiersForMessaging(normalizedRole);
    const ownIdentifierRaw = String(ownIdentifier || "").trim();
    if (!ownIdentifierRaw) {
      setRoleMessageBadge(normalizedRole, 0);
      return {
        role: normalizedRole,
        ownIdentifier: "",
        inbox: null,
        totalUnread: 0
      };
    }

    let ownStatus = getCachedIdentifierStatus(ownIdentifierRaw);
    if (!ownStatus) {
      try {
        ownStatus = await fetchIdentifierStatus(ownIdentifierRaw);
        rememberIdentifierStatus(ownIdentifierRaw, ownStatus);
      } catch (_) {
        return null;
      }
    }

    const ownPreferredIdentifier = String(ownStatus?.preferred_identifier || ownIdentifierRaw).trim() || ownIdentifierRaw;
    const ownAcceptedHandle = isAcceptedUniqueHandleIdentifier(ownPreferredIdentifier, ownStatus) || !!ownStatus?.uses_handle;
    if (!ownAcceptedHandle) {
      setRoleMessageBadge(normalizedRole, 0);
      return {
        role: normalizedRole,
        ownIdentifier: ownPreferredIdentifier,
        inbox: null,
        totalUnread: 0
      };
    }

    try {
      const inboxData = await fetchPartnerMessageInbox(ownPreferredIdentifier, getOrCreateMessagingDeviceId());
      if (inboxData?.identifier_status) {
        rememberIdentifierStatus(ownPreferredIdentifier, inboxData.identifier_status);
      }
      return {
        role: normalizedRole,
        ownIdentifier: ownPreferredIdentifier,
        inbox: inboxData?.inbox || null,
        totalUnread: Math.max(0, Number(inboxData?.inbox?.total_unread || 0))
      };
    } catch (_) {
      return null;
    }
  }

  function openPushSetupOverlay(role, ownIdentifier, options = {}) {
    pushSetupReturnRole = role === "sender" || role === "receiver" || role === "remote-viewer" ? role : "";
    pushSetupReturnView = options.returnView === "feature-setup"
      ? "feature-setup"
      : options.returnView === "help"
        ? "help"
        : "card";
    pushSetupOwnIdentifier = String(ownIdentifier || "").trim();
    if (!pushSetupReturnRole || !pushSetupOwnIdentifier) {
      return;
    }
    if (pushSetupStatus) {
      pushSetupStatus.textContent = "Checking this device...";
    }
    if (pushSetupReturnView === "feature-setup") {
      setFeatureSetupBackButtonTemporarilyHidden(true);
    }
    pushSetupOverlay?.classList.remove("beginner-view-hidden");
    void refreshPushSetupOverlay();
  }

  async function openMessagingSetupFromHelp(options = {}) {
    const requestedReturnView = String(options.returnView || "").trim().toLowerCase();
    const returnView = requestedReturnView === "feature-setup"
      ? "feature-setup"
      : requestedReturnView === "help"
        ? "help"
        : "card";
    const candidates = [
      {
        role: "sender",
        ownIdentifier: readRoleFormValues("sender").ownName
      },
      {
        role: "receiver",
        ownIdentifier: readRoleFormValues("receiver").ownName
      },
      {
        role: "remote-viewer",
        ownIdentifier: String(remoteViewerOwnInput?.value || "").trim()
      }
    ];

    for (const candidate of candidates) {
      const rawIdentifier = String(candidate.ownIdentifier || "").trim();
      if (!rawIdentifier) {
        continue;
      }
      try {
        const status = await fetchIdentifierStatus(rawIdentifier);
        rememberIdentifierStatus(rawIdentifier, status);
        const preferredIdentifier = String(status?.preferred_identifier || rawIdentifier).trim() || rawIdentifier;
        if (!isAcceptedUniqueHandleIdentifier(preferredIdentifier, status)) {
          continue;
        }

        if (returnView === "card") {
          showLauncherView();
          if (candidate.role === "remote-viewer") {
            showClairvoyanceViewingView();
            const matchingCard = findRoleCard("remote-viewer");
            if (matchingCard) {
              ensureCardExpanded(matchingCard, { scrollIntoView: false });
            }
          } else {
            const matchingCard = findRoleCard(candidate.role);
            if (matchingCard) {
              ensureCardExpanded(matchingCard, { scrollIntoView: false });
            }
          }
        }
        openPushSetupOverlay(candidate.role, preferredIdentifier, { returnView });
        return;
      } catch (_) {
        // Try the next candidate.
      }
    }

    window.alert("First claim a unique handle on one of the role cards, then return here to enable partner messaging.");
  }

  async function resolveFeatureSetupContext(preferredRole = "") {
    const launcherState = readLauncherState();
    const roles = [];
    const normalizedPreferredRole = String(preferredRole || "").trim();
    if (normalizedPreferredRole) {
      roles.push(normalizedPreferredRole);
    }
    ["sender", "receiver", "remote-viewer"].forEach((role) => {
      if (!roles.includes(role)) {
        roles.push(role);
      }
    });

    const authoritativeCandidates = [
      {
        identifier: String(getLoadedInviteeIdentity(launcherState)?.identifier || "").trim(),
        role: normalizedPreferredRole || activeLauncherRole || "sender"
      },
      {
        identifier: String(getTemporaryIdentityState(launcherState)?.identifier || "").trim(),
        role: normalizedPreferredRole || activeLauncherRole || "sender"
      },
      {
        identifier: String(getCanonicalRecognizedIdentity(launcherState) || "").trim(),
        role: normalizedPreferredRole || activeLauncherRole || "sender"
      }
    ];

    for (const candidate of authoritativeCandidates) {
      const rawIdentifier = String(candidate.identifier || "").trim();
      if (!rawIdentifier) {
        continue;
      }
      try {
        const status = await fetchIdentifierStatus(rawIdentifier);
        rememberIdentifierStatus(rawIdentifier, status);
        const preferredIdentifier = String(status?.preferred_identifier || rawIdentifier).trim() || rawIdentifier;
        if (isAcceptedUniqueHandleIdentifier(preferredIdentifier, status)) {
          return {
            role: candidate.role,
            identifier: preferredIdentifier,
            status
          };
        }
      } catch (_) {
        const cachedStatus = getCachedIdentifierStatus(rawIdentifier);
        const preferredIdentifier = String(cachedStatus?.preferred_identifier || rawIdentifier).trim() || rawIdentifier;
        if (isAcceptedUniqueHandleIdentifier(preferredIdentifier, cachedStatus)) {
          return {
            role: candidate.role,
            identifier: preferredIdentifier,
            status: cachedStatus
          };
        }
      }
    }

    return {
      role: normalizedPreferredRole || activeLauncherRole || "sender",
      identifier: "",
      status: null
    };
  }

  function getLocationFeatureSummary(state = readLauncherState()) {
    const permission = String(state?.locationPermission || "").trim().toLowerCase();
    const savedLocation = getSavedDeviceLocation(state);
    if (permission === "denied") {
      return {
        ready: false,
        statusText: "Blocked in the browser or PWA settings.",
        actionLabel: "REVIEW LOCATION"
      };
    }
    if (savedLocation?.source === "manual-map" && (permission === "granted" || permission === "manual")) {
      return {
        ready: true,
        statusText: "A manually adjusted location is set on this device.",
        actionLabel: "REVIEW LOCATION"
      };
    }
    if (savedLocation) {
      return {
        ready: true,
        statusText: "A browser-estimated location is available on this device.",
        actionLabel: "REVIEW LOCATION"
      };
    }
    if (permission === "granted" || permission === "manual") {
      return {
        ready: false,
        statusText: "Location permission is available, but no device location has been stored yet.",
        actionLabel: "REVIEW LOCATION"
      };
    }
    if (permission === "error") {
      return {
        ready: false,
        statusText: "Browser location was not available yet. You can still review location options manually.",
        actionLabel: "REVIEW LOCATION"
      };
    }
    return {
      ready: false,
      statusText: "Location is not set up yet.",
      actionLabel: "REVIEW LOCATION"
    };
  }

  function getFeatureSetupHandleRole() {
    const preferred = String(featureSetupReturnRole || activeLauncherRole || "sender").trim();
    if (preferred === "sender" || preferred === "receiver" || preferred === "remote-viewer") {
      return preferred;
    }
    return "sender";
  }

  function setFeatureSetupBackButtonTemporarilyHidden(hidden) {
    if (!closeFeatureSetupButton) {
      return;
    }
    const shouldHide = !!hidden && !!featureSetupView && !featureSetupView.classList.contains("beginner-view-hidden");
    closeFeatureSetupButton.hidden = shouldHide;
    closeFeatureSetupButton.disabled = shouldHide;
  }

  function openFeatureSetupHandleFlow(flow = "claim") {
    featureSetupPendingHandleFlow = String(flow || "claim").trim().toLowerCase() === "install-gate"
      ? "install-gate"
      : "claim";
    openHandleOverlay(getFeatureSetupHandleRole());
  }

  async function refreshFeatureSetupView() {
    if (!featureSetupView || featureSetupView.classList.contains("beginner-view-hidden")) {
      return;
    }

    const context = await resolveFeatureSetupContext(featureSetupReturnRole || activeLauncherRole || "sender");
    featureSetupReturnRole = String(context.role || featureSetupReturnRole || "sender").trim();
    featureSetupOwnIdentifier = String(context.identifier || "").trim();

    if (featureSetupIdentifier) {
      featureSetupIdentifier.textContent = featureSetupOwnIdentifier
        ? `Current Unique Name: ${featureSetupOwnIdentifier}`
        : "Current Unique Name: no unique name currently exists for this user.";
    }

    const recognizedUser = !!featureSetupOwnIdentifier;
    const visitorMode = isVisitorLauncherEntry();
    if (featureSetupClaimStatus) {
      featureSetupClaimStatus.textContent = recognizedUser
        ? `Current unique name: ${featureSetupOwnIdentifier}`
        : "No unique name exists for this user yet.";
    }
    if (featureSetupClaimActionButton) {
      featureSetupClaimActionButton.textContent = recognizedUser ? "CHANGE UNIQUE NAME" : "CLAIM UNIQUE NAME";
      featureSetupClaimActionButton.disabled = false;
    }

    const installConfirmationState = getInstallConfirmationState();
    const installed = installConfirmationState === "confirmed-installed";
    if (featureSetupInstallStatus) {
      featureSetupInstallStatus.textContent = installed
        ? "Installed as an app on this device."
        : visitorMode && !recognizedUser
          ? "You must first claim a unique name before installing the app for full Telepathy Beginner use."
          : installConfirmationState === "temporary-shell"
            ? "ESP GYM is open in app mode temporarily, but it is not yet confirmed as permanently installed on this device."
            : "Not installed as an app on this device yet.";
    }
    if (featureSetupInstallActionButton) {
      featureSetupInstallActionButton.textContent = installed ? "UNINSTALL HELP" : "INSTALL APP";
      featureSetupInstallActionButton.disabled = false;
    }

    const locationSummary = getLocationFeatureSummary();
    if (featureSetupLocationStatus) {
      featureSetupLocationStatus.textContent = locationSummary.statusText;
    }
    if (featureSetupLocationActionButton) {
      featureSetupLocationActionButton.textContent = locationSummary.actionLabel;
      featureSetupLocationActionButton.disabled = false;
    }

    let messagingReady = false;
    let messagingStatusText = "First choose or load an accepted unique name before setting up partner messaging.";
    let messagingActionLabel = "ENABLE PARTNER MESSAGING";
    let messagingActionDisabled = !featureSetupOwnIdentifier;
    if (!isEffectiveLauncherUserPro()) {
      messagingStatusText = "Instant messaging with notifications is a PRO feature";
      messagingActionLabel = "PRO FEATURE";
      messagingActionDisabled = true;
    } else if (featureSetupOwnIdentifier) {
      const installedForMessaging = installed;
      const permission = syncNotificationPermissionSnapshot();
      if (!installedForMessaging) {
        messagingStatusText = "Install app before enabling partner notifications for the app.";
        messagingActionLabel = "INSTALL APP FIRST";
        messagingActionDisabled = true;
      } else if (permission === "denied") {
        messagingStatusText = "Notifications are blocked in the browser for this app on this device.";
        messagingActionLabel = "ENABLE PARTNER MESSAGING";
      } else if (permission === "unsupported") {
        messagingStatusText = "This browser does not support app notifications.";
        messagingActionDisabled = true;
      } else {
        try {
          const setupData = await fetchPushSetup(featureSetupOwnIdentifier, getOrCreateMessagingDeviceId());
          if (setupData?.identifier_status) {
            rememberIdentifierStatus(featureSetupOwnIdentifier, setupData.identifier_status);
          }
          messagingReady = !!setupData?.push_status?.notification_ready && permission === "granted" && installedForMessaging;
          messagingStatusText = messagingReady
            ? "Partner messaging is ready on this device."
            : permission === "granted"
              ? "Notifications are enabled in the browser for this app on this device."
              : permission === "denied"
                ? "Notifications are blocked in the browser for this app on this device."
                : "Notifications are not yet enabled in the browser for this app on this device.";
          messagingActionLabel = messagingReady
            ? "DISABLE PARTNER MESSAGING"
            : "ENABLE PARTNER MESSAGING";
        } catch (error) {
          messagingStatusText = error instanceof Error ? error.message : "Unable to check partner messaging right now.";
        }
      }
    }
    if (featureSetupMessagingStatus) {
      featureSetupMessagingStatus.textContent = messagingStatusText;
    }
    if (featureSetupMessagingActionButton) {
      featureSetupMessagingActionButton.textContent = messagingActionLabel;
      featureSetupMessagingActionButton.disabled = messagingActionDisabled;
    }

    if (featureSetupSummary) {
      featureSetupSummary.textContent = "";
      featureSetupSummary.hidden = true;
    }

    renderProOnlyLockedControls();
    refreshAllRoleFeatureSetupPrompts();
  }

