    function renderAdminSubscriptionsView() {
      const rows = getFilteredAdminSubscriptionRows();
      const meta = launcherAdminState.subscription_summary_meta || {};
      const reportDate = String(meta.report_date || "").trim() || "unknown";
      const totalRecords = Number.isFinite(Number(meta.total_records)) ? Number(meta.total_records) : rows.length;
      const activeProCount = rows.filter((row) => {
        const status = String(row?.stripe_status || "").trim().toLowerCase();
        return status === "active" || status === "trialing";
      }).length;
      const monthlyCount = rows.filter((row) => String(row?.plan_key || "").trim().toLowerCase() === "monthly").length;
      const annualCount = rows.filter((row) => String(row?.plan_key || "").trim().toLowerCase() === "annual").length;
      const giftCount = rows.filter((row) => String(row?.gift_mode || "").trim().toLowerCase() === "gift").length;
      const cancelAtPeriodEndCount = rows.filter((row) => !!row?.cancel_at_period_end).length;
      const mismatchCount = rows.filter((row) => String(row?.sync_state || "").trim().toLowerCase() === "mismatch").length;
      if (adminSubscriptionsSummary) {
        adminSubscriptionsSummary.textContent = [
          `Report Date: ${reportDate}`,
          `Total: ${totalRecords}`,
          `Active PRO: ${activeProCount}`,
          `Monthly: ${monthlyCount}`,
          `Annual: ${annualCount}`,
          `Gift: ${giftCount}`,
          `Cancel At Period End: ${cancelAtPeriodEndCount}`,
          `Mismatches: ${mismatchCount}`
        ].join("   ");
      }
      if (adminSubscriptionsStatus) {
        adminSubscriptionsStatus.textContent = rows.length ? "" : "No subscription records are available right now.";
      }
      setAdminFilterButtonState(adminSubscriptionsStatusFilterButtons, activeAdminSubscriptionsStatusFilter);
      setAdminFilterButtonState(adminSubscriptionsEnvironmentFilterButtons, activeAdminSubscriptionsEnvironmentFilter);
      setAdminFilterButtonState(adminSubscriptionsPlanFilterButtons, activeAdminSubscriptionsPlanFilter);
      setAdminFilterButtonState(adminSubscriptionsGiftFilterButtons, activeAdminSubscriptionsGiftFilter);
      setAdminFilterButtonState(adminSubscriptionsMismatchFilterButtons, activeAdminSubscriptionsMismatchFilter);
      if (adminSubscriptionsSearchInput && adminSubscriptionsSearchInput.value !== String(activeAdminSubscriptionsSearch || "")) {
        adminSubscriptionsSearchInput.value = String(activeAdminSubscriptionsSearch || "");
      }
      const selectedKeyInFilteredRows = rows.some((row) => String(row?.storage_key || "").trim() === String(launcherAdminState.subscription_summary_selected_key || "").trim());
      const currentSelected = getSelectedAdminSubscriptionRow();
      if ((!currentSelected || !selectedKeyInFilteredRows) && rows.length) {
        setSelectedAdminSubscriptionRow(String(rows[0]?.storage_key || ""));
      }
      const selectedKey = String(launcherAdminState.subscription_summary_selected_key || "").trim();
      if (adminSubscriptionsBody) {
        adminSubscriptionsBody.replaceChildren();
        rows.forEach((row) => {
          const tr = document.createElement("tr");
          tr.className = "admin-report-row-clickable";
          tr.dataset.subscriptionStorageKey = String(row?.storage_key || "");
          if (String(row?.storage_key || "") === selectedKey) {
            tr.classList.add("is-selected");
          }
          [
            row?.identifier || "",
            row?.stripe_environment_label || "",
            row?.subscriber_email || "",
            row?.plan_label || "",
            row?.stripe_status_label || "",
            row?.gift_label || "",
            row?.current_period_end_utc || "",
            row?.local_type || "",
            row?.sync_label || ""
          ].forEach((value) => {
            const td = document.createElement("td");
            td.textContent = String(value || "");
            tr.appendChild(td);
          });
          adminSubscriptionsBody.appendChild(tr);
        });
      }
      const selectedRow = rows.find((row) => String(row?.storage_key || "").trim() === String(launcherAdminState.subscription_summary_selected_key || "").trim()) || null;
      populateAdminSubscriptionsDetail(selectedRow);
    }

    function renderLessonIndexAdminView() {
      const rows = Array.isArray(launcherAdminState.lesson_index) ? launcherAdminState.lesson_index : [];

      if (lessonIndexAdminSummary) {
        lessonIndexAdminSummary.textContent = `${rows.length} lesson row${rows.length === 1 ? "" : "s"} found. Lesson ids, numbers, titles, and subcopy can be edited here.`;
      }
      if (lessonIndexAdminStatus && !String(lessonIndexAdminStatus.textContent || "").trim()) {
        lessonIndexAdminStatus.textContent = rows.length ? "" : "No lesson-index rows are available right now.";
      }
      if (!lessonIndexAdminBody) {
        return;
      }

      if (!rows.length) {
        lessonIndexAdminBody.innerHTML = `<tr><td colspan="6">No lesson-index rows are available right now.</td></tr>`;
        return;
      }

      lessonIndexAdminBody.innerHTML = rows.map((row) => {
        const lessonId = String(row?.lesson_id || "").trim();
        const displayNumber = String(row?.display_number || "").trim();
        const title = String(row?.title || "").trim();
        const subcopy = String(row?.subcopy || "").trim();
        const type = String(row?.type || "").trim();
        const available = !!row?.available;
        const lessonIdReadonly = type !== "lesson-page" ? "readonly" : "";
        return `
          <tr data-lesson-index-row="${escapeHtml(lessonId)}" data-lesson-index-original-id="${escapeHtml(lessonId)}">
            <td><input class="lesson-index-admin-cell-input" type="text" value="${escapeHtml(lessonId)}" data-lesson-index-field="lesson_id" ${lessonIdReadonly}></td>
            <td><input class="lesson-index-admin-cell-input" type="text" value="${escapeHtml(displayNumber)}" data-lesson-index-field="display_number"></td>
            <td><input class="lesson-index-admin-cell-input" type="text" value="${escapeHtml(title)}" data-lesson-index-field="title"></td>
            <td><textarea class="lesson-index-admin-cell-textarea" data-lesson-index-field="subcopy">${escapeHtml(subcopy)}</textarea></td>
            <td><span class="lesson-index-admin-cell-pill">${escapeHtml(type)}</span></td>
            <td><span class="lesson-index-admin-cell-pill ${available ? "lesson-index-admin-cell-yes" : "lesson-index-admin-cell-no"}">${available ? "Yes" : "No"}</span></td>
            <td><button class="lesson-index-admin-delete-button" type="button" data-lesson-index-delete="${escapeHtml(lessonId)}" ${type === "lesson-page" ? "" : "disabled"}>${type === "lesson-page" ? "Delete" : "Protected"}</button></td>
          </tr>
        `;
      }).join("");
    }

    function collectLessonIndexAdminRows() {
      if (!lessonIndexAdminBody) {
        return [];
      }
      return Array.from(lessonIndexAdminBody.querySelectorAll("[data-lesson-index-row]")).map((rowElement) => {
        const originalLessonId = String(rowElement.getAttribute("data-lesson-index-original-id") || rowElement.getAttribute("data-lesson-index-row") || "").trim();
        const lessonId = String(rowElement.querySelector('[data-lesson-index-field="lesson_id"]')?.value || originalLessonId).trim();
        const normalizedOriginalLessonId = normalizeLearningCenterLessonId(originalLessonId);
        const existingRecord = getLearningCenterLessonRecordById(normalizedOriginalLessonId, launcherAdminState.lesson_index || learningCenterLessonIndex) || {};
        const displayNumber = String(rowElement.querySelector('[data-lesson-index-field="display_number"]')?.value || "").trim();
        const title = String(rowElement.querySelector('[data-lesson-index-field="title"]')?.value || "").trim();
        const subcopy = String(rowElement.querySelector('[data-lesson-index-field="subcopy"]')?.value || "").trim();
        return {
          original_lesson_id: normalizedOriginalLessonId,
          lesson_id: lessonId,
          display_number: displayNumber,
          title,
          subcopy,
          type: String(existingRecord.type || "lesson-page").trim() || "lesson-page",
          available: existingRecord.type !== "lesson-page" ? true : !!existingRecord.available
        };
      });
    }

    async function applyLearningCenterLessonIdChanges(rows) {
      const normalizedRows = (Array.isArray(rows) ? rows : [])
        .map((record) => {
          const normalizedLessonId = normalizeLearningCenterLessonId(record?.lesson_id || "");
          const normalizedOriginalLessonId = normalizeLearningCenterLessonId(record?.original_lesson_id || record?.lesson_id || "");
          return normalizedLessonId ? {
            ...record,
            lesson_id: normalizedLessonId,
            original_lesson_id: normalizedOriginalLessonId
          } : null;
        })
        .filter(Boolean);
      const renameRows = normalizedRows.filter((row) => row.type === "lesson-page" && row.original_lesson_id && row.lesson_id && row.original_lesson_id !== row.lesson_id);
      if (!renameRows.length) {
        return normalizedRows;
      }
      const contentByOldKey = new Map();
      for (const row of renameRows) {
        const oldKey = buildLearningCenterLessonContentKey(row.original_lesson_id);
        if (!oldKey || contentByOldKey.has(oldKey)) {
          continue;
        }
        const existing = await fetchEditableContentFromServer(oldKey);
        contentByOldKey.set(oldKey, typeof existing?.content === "string" ? existing.content : "");
      }
      for (const row of renameRows) {
        const oldKey = buildLearningCenterLessonContentKey(row.original_lesson_id);
        const newKey = buildLearningCenterLessonContentKey(row.lesson_id);
        if (!oldKey || !newKey || oldKey === newKey) {
          continue;
        }
        await saveEditableContentToServer(newKey, contentByOldKey.get(oldKey) || "");
      }
      return normalizedRows;
    }

    async function cleanupRenamedLearningCenterLessonContent(rows) {
      const normalizedRows = (Array.isArray(rows) ? rows : [])
        .map((record) => ({
          original_lesson_id: normalizeLearningCenterLessonId(record?.original_lesson_id || record?.lesson_id || ""),
          lesson_id: normalizeLearningCenterLessonId(record?.lesson_id || ""),
          type: String(record?.type || "").trim()
        }))
        .filter((record) => record.type === "lesson-page" && record.original_lesson_id && record.lesson_id && record.original_lesson_id !== record.lesson_id);
      if (!normalizedRows.length) {
        return;
      }
      const finalKeys = new Set(
        normalizedRows
          .map((row) => buildLearningCenterLessonContentKey(row.lesson_id))
          .filter(Boolean)
      );
      for (const row of normalizedRows) {
        const oldKey = buildLearningCenterLessonContentKey(row.original_lesson_id);
        if (!oldKey || finalKeys.has(oldKey)) {
          continue;
        }
        await deleteEditableContentFromServer(oldKey);
      }
    }

    function renderAdminView() {
      if (adminDebugEnabledCheckbox) {
        adminDebugEnabledCheckbox.checked = !!launcherAdminState.debug_enabled;
      }
      if (adminSubscriptionEmailsEnabledCheckbox) {
        adminSubscriptionEmailsEnabledCheckbox.checked = !!launcherAdminState.subscription_emails_enabled;
      }
      if (adminSubscriptionRemindersEnabledCheckbox) {
        adminSubscriptionRemindersEnabledCheckbox.checked = !!launcherAdminState.subscription_reminders_enabled;
      }
      if (adminEasyAdminEnabledCheckbox) {
        adminEasyAdminEnabledCheckbox.checked = !!launcherAdminState.easy_admin_enabled;
      }
      if (adminLearnMoreSaveEnabledCheckbox) {
        adminLearnMoreSaveEnabledCheckbox.checked = !!launcherAdminState.learn_more_save_enabled;
      }
      if (adminExploreProTestDurationInput) {
        const seconds = Math.max(0, Number(launcherAdminState.explore_pro_test_duration_seconds || 0) || 0);
        adminExploreProTestDurationInput.value = seconds > 0 ? String(seconds) : "";
      }
      if (adminTrialModePublicEnabledCheckbox) {
        adminTrialModePublicEnabledCheckbox.checked = !!launcherAdminState.trial_mode_public_enabled;
      }
      applyMessagingLimitsUi(launcherAdminState.messaging_limits);
      if (adminClearDebugLogButton) {
        const debugLog = launcherAdminState.debug_log;
        const sizeLabel = debugLog?.size_formatted ? debugLog.size_formatted : "0 B";
        adminClearDebugLogButton.innerHTML = `Clear debug log<span class="admin-button-subline">Current size: ${escapeHtml(sizeLabel)}</span>`;
      }
      if (adminStorageInfo) {
        const storage = launcherAdminState.storage;
        adminStorageInfo.innerHTML = storage?.available
        ? `Storage path: ${escapeHtml(storage.path)}<br>Free space: ${escapeHtml(storage.free_formatted)}&nbsp;&nbsp;&nbsp;Used space: ${escapeHtml(storage.used_formatted)}&nbsp;&nbsp;&nbsp;Total space: ${escapeHtml(storage.total_formatted)}`
          : "Storage information is not available right now.";
      }
      if (adminDiskUsage) {
        const diskUsage = launcherAdminState.disk_usage_analysis;
      if (diskUsage) {
        adminDiskUsage.hidden = false;
        adminDiskUsage.textContent = formatAdminDiskUsageAnalysis(diskUsage);
      } else {
        adminDiskUsage.hidden = true;
        adminDiskUsage.textContent = "";
      }
    }
  }

  async function refreshAdminView() {
    if (!hasLauncherAdminAccess()) {
      if (adminStatus) {
        adminStatus.textContent = "Admin access is not active.";
      }
      return;
    }
    if (adminStatus) {
      adminStatus.textContent = "Loading admin data...";
    }
    try {
      const data = await launcherAdminApi("heartbeat");
        launcherAdminState = {
          debug_enabled: !!launcherAdminDevicePrefs.debug_enabled,
          subscription_emails_enabled: !!data?.subscription_emails_enabled,
          subscription_reminders_enabled: !!data?.subscription_reminders_enabled,
          easy_admin_enabled: !!launcherAdminDevicePrefs.easy_admin_enabled,
          learn_more_save_enabled: !!launcherAdminDevicePrefs.learn_more_save_enabled,
          explore_pro_test_duration_seconds: Math.max(0, Number(data?.explore_pro_test_duration_seconds || 0) || 0),
          trial_mode_public_enabled: !!data?.trial_mode_public_enabled,
          storage: data?.storage || null,
          debug_log: data?.debug_log || null,
          subscription_email_log: data?.subscription_email_log || null,
          subscription_email_templates: data?.subscription_email_templates || null,
          pair_summary: data?.pair_summary || null,
          pair_summary_meta: data?.pair_summary_meta || null,
          identity_summary: data?.identity_summary || null,
          identity_summary_meta: data?.identity_summary_meta || null,
          email_list: data?.email_list || null,
          email_list_meta: data?.email_list_meta || null,
          subscription_summary: Array.isArray(data?.subscription_summary) ? data.subscription_summary : launcherAdminState.subscription_summary,
          subscription_summary_meta: data?.subscription_summary_meta || launcherAdminState.subscription_summary_meta,
          subscription_summary_selected_key: String(launcherAdminState.subscription_summary_selected_key || ""),
          disk_usage_analysis: data?.disk_usage_analysis || null,
          messaging_limits: normalizeMessagingLimits(data?.messaging_limits || defaultMessagingLimits)
        };
      if (adminStatus) {
        adminStatus.textContent = "Admin access active.";
      }
      renderAdminView();
      if (!adminUserListView?.classList.contains("beginner-view-hidden")) {
        renderAdminUserListView();
      }
      if (!adminIdentityListView?.classList.contains("beginner-view-hidden")) {
        renderAdminIdentityListView();
      }
      if (!adminEmailListView?.classList.contains("beginner-view-hidden")) {
        renderAdminEmailListView();
      }
      if (!subscriptionsAdminView?.classList.contains("beginner-view-hidden")) {
        renderAdminSubscriptionsView();
      }
    } catch (error) {
      if (adminStatus) {
        adminStatus.textContent = "Unable to load admin data right now.";
      }
    }
  }

  function deleteIndexedDbDatabase(name) {
    return new Promise((resolve) => {
      try {
        if (!("indexedDB" in window) || !name) {
          resolve();
          return;
        }
        const request = window.indexedDB.deleteDatabase(name);
        request.onsuccess = () => resolve();
        request.onerror = () => resolve();
        request.onblocked = () => resolve();
      } catch (error) {
        resolve();
      }
    });
  }

  function clearAppCacheArtifacts() {
    return new Promise((resolve) => {
      try {
        if (!("caches" in window)) {
          resolve();
          return;
        }
        caches.keys()
          .then((keys) => Promise.all(
            keys
              .filter((key) => String(key || "").indexOf("telepathybeginner-") === 0)
              .map((key) => caches.delete(key).catch(() => false))
          ))
          .then(() => resolve())
          .catch(() => resolve());
      } catch (error) {
        resolve();
      }
    });
  }

  function getFreshStartPreserveSelections() {
    return {
      preserve_users: adminFreshStartPreserveUsersCheckbox?.checked !== false,
      preserve_invitees: adminFreshStartPreserveInviteesCheckbox?.checked !== false,
      preserve_pairs: adminFreshStartPreservePairsCheckbox?.checked !== false,
      preserve_simulation_pairs: adminFreshStartPreserveSimulationPairsCheckbox?.checked !== false,
      preserve_questionnaires: adminFreshStartPreserveQuestionnairesCheckbox?.checked !== false,
      preserve_messaging_history: adminFreshStartPreserveMessagingHistoryCheckbox?.checked !== false,
      preserve_analytics_counters: adminFreshStartPreserveAnalyticsCountersCheckbox?.checked !== false
    };
  }

  async function clearLocalFreshStartState(options = {}) {
    const preserveUsers = options?.preserve_users !== false;
    const preservePairs = options?.preserve_pairs !== false;
    const preserveInvitees = options?.preserve_invitees !== false;
    const preserveQuestionnaires = options?.preserve_questionnaires !== false;
    const preservedAdminDevicePrefs = {
      ...launcherAdminDevicePrefs
    };
    logLauncherUserTypeDebug("fresh_start_local_clear_begin", {
      preserveUsers,
      preservePairs,
      preserveInvitees,
      preserveQuestionnaires,
      deviceTestModeBefore: cloneJsonValue(readLauncherState()?.deviceTestMode || null, null),
      hasRestoreSnapshotKeyBefore: hasDeviceTestRestoreSnapshot()
    });
    try {
      writeDeviceTestNotice("");
      clearDeviceTestRestoreSnapshot();
      setLauncherProfileSaveSuppression(!preserveUsers, true);
      localStorage.removeItem(analysisStorageKey);
      localStorage.removeItem("cones-local-trials-receiver");
      localStorage.removeItem("cones-local-trials-v2-sender");
      localStorage.removeItem("cones-local-trials-v2-receiver");
      localStorage.removeItem("conesArrangementHistory");
      localStorage.removeItem("conesArrangementHistory-v2");
      localStorage.removeItem("cones-receiver-skip-two-choice-instructions");
      if (!preserveUsers) {
        roleCards.forEach((card) => {
          const form = card.querySelector("[data-role-form]");
          const ownInput = form?.querySelector('input[name="ownName"]');
          const partnerInput = form?.querySelector('input[name="partnerName"]');
          if (ownInput) {
            ownInput.value = "";
          }
          if (partnerInput) {
            partnerInput.value = "";
          }
        });
        clearLauncherIdentityArtifacts();
        try {
          const anonymousState = buildVisitorLauncherState(normalizeLauncherIdentityState({}));
          anonymousState.deviceTestMode = null;
          anonymousState.loadedInviteeIdentity = null;
          anonymousState.pendingInviteeOnboarding = null;
          localStorage.setItem(launcherKey, JSON.stringify(normalizeLauncherIdentityState(anonymousState)));
          sessionStorage.removeItem(launcherKey);
        } catch (error) {
          // Ignore last-ditch launcher reset failures.
        }
        writeLocalFreshStartEpoch(Date.now());
        setPendingFreshStartAnonymousReset(true);
      }
      if (!preservePairs) {
        localStorage.removeItem("cones-settings-v2-sender");
        localStorage.removeItem("cones-settings-v2-receiver");
        localStorage.removeItem("cones-settings-v2-remote-viewer");
      }
      if (!preserveInvitees) {
        inviteeRecordsCache = [];
        currentInviteeIdentifier = "";
      }
      const questionnairePrefixes = [
        "cones-baseline-questions-v1-",
        "cones-after-first-session-questions-v1-"
      ];
      if (!preserveQuestionnaires) {
        const keysToRemove = [];
        for (let index = 0; index < localStorage.length; index += 1) {
          const key = String(localStorage.key(index) || "");
          if (questionnairePrefixes.some((prefix) => key.startsWith(prefix))) {
            keysToRemove.push(key);
          }
        }
        keysToRemove.forEach((key) => localStorage.removeItem(key));
      }
      if (preserveUsers) {
        const latest = readLauncherState();
        if (latest?.deviceTestMode || latest?.loadedInviteeIdentity) {
          latest.deviceTestMode = null;
          latest.loadedInviteeIdentity = null;
          latest.pendingInviteeOnboarding = null;
          writeLauncherState(latest);
        }
      }
    } catch (error) {
      // Ignore local cleanup failures.
    }
    logLauncherUserTypeDebug("fresh_start_local_clear_end", {
      preserveUsers,
      deviceTestModeAfter: cloneJsonValue(readLauncherState()?.deviceTestMode || null, null),
      hasRestoreSnapshotKeyAfter: hasDeviceTestRestoreSnapshot(),
      recognizedIdentityAfter: String(readLauncherState()?.recognizedIdentity || "").trim(),
      entryModeAfter: String(readLauncherState()?.entryMode || "").trim()
    });
    writeLauncherAdminDevicePrefs(preservedAdminDevicePrefs);
    syncLauncherAdminStateFromDevicePrefs();
    if (!preserveUsers) {
      await deleteIndexedDbDatabase("cones-folder-handles");
    }
  }

  async function clearAppLocalStorageArtifacts() {
    await clearLocalFreshStartState({
      preserve_users: false,
      preserve_pairs: false,
      preserve_questionnaires: false
    });
    try {
      sessionStorage.removeItem(launcherKey);
      sessionStorage.removeItem("cones-client-id-sender");
      sessionStorage.removeItem("cones-client-id-receiver");
      sessionStorage.removeItem("cones-client-id-remote-viewer");
    } catch (error) {
      // Ignore session cleanup failures.
    }
    await clearAppCacheArtifacts();
  }

