  async function refreshLessonIndexAdminView(options = {}) {
    const preserveStatus = !!options.preserveStatus;
    if (lessonIndexAdminStatus && !preserveStatus) {
      lessonIndexAdminStatus.textContent = "Loading lesson index...";
    }
    const rows = await fetchLearningCenterLessonIndex();
    launcherAdminState.lesson_index = Array.isArray(rows) ? rows : [];
    learningCenterLessonIndex = Array.isArray(rows) ? rows : learningCenterLessonIndex;
    renderLessonIndexAdminView();
    if (lessonIndexAdminStatus) {
      lessonIndexAdminStatus.textContent = rows.length ? "" : "No lesson-index rows are available right now.";
    }
  }

  function renderUserTypeAdminState(options = {}) {
    const statusText = String(options.statusText || "").trim();
    const showChoices = !!options.showChoices;
    const showInviteeButton = !!options.showInviteeButton;
    const showEmailUpdate = !!options.showEmailUpdate;
    const currentType = String(options.currentType || "standard").trim().toLowerCase() === "pro" ? "pro" : "standard";
    const authEmail = String(options.authEmail || "").trim();
    pendingUserTypeSelection = currentType;

    if (userTypeStatus) {
      userTypeStatus.textContent = statusText;
    }
    if (userTypeOptionsWrap) {
      userTypeOptionsWrap.classList.toggle("beginner-view-hidden", !showChoices);
      userTypeOptionsWrap.hidden = !showChoices;
    }
    if (userTypeSaveButton) {
      userTypeSaveButton.classList.toggle("beginner-view-hidden", !showChoices);
      userTypeSaveButton.hidden = !showChoices;
    }
    if (userTypeEmailWrap) {
      userTypeEmailWrap.classList.toggle("beginner-view-hidden", !showEmailUpdate);
      userTypeEmailWrap.hidden = !showEmailUpdate;
    }
    if (userTypeEmailInput) {
      userTypeEmailInput.value = authEmail;
    }
    if (userTypeUpdateEmailButton) {
      userTypeUpdateEmailButton.classList.toggle("beginner-view-hidden", !showEmailUpdate);
      userTypeUpdateEmailButton.hidden = !showEmailUpdate;
    }
    if (openInviteeAdminButton) {
      openInviteeAdminButton.classList.toggle("beginner-view-hidden", !showInviteeButton);
      openInviteeAdminButton.hidden = !showInviteeButton;
    }
    userTypeChoiceButtons.forEach((button) => {
      const isSelected = String(button.dataset.userTypeChoiceButton || "").trim().toLowerCase() === currentType;
      button.classList.toggle("is-selected", isSelected);
      button.setAttribute("aria-pressed", isSelected ? "true" : "false");
    });
    logUserTypeAdminDebug("render_state", [{
      requested_show_choices: showChoices,
      requested_show_invitee_button: showInviteeButton,
      requested_show_email_update: showEmailUpdate,
      requested_current_type: currentType,
      requested_auth_email: authEmail,
      requested_status_text: statusText
    }]);
  }

  function applyPendingUserTypeSelection(selection) {
    const normalizedSelection = String(selection || "").trim().toLowerCase() === "pro" ? "pro" : "standard";
    pendingUserTypeSelection = normalizedSelection;
    userTypeChoiceButtons.forEach((button) => {
      const isSelected = String(button.dataset.userTypeChoiceButton || "").trim().toLowerCase() === normalizedSelection;
      button.classList.toggle("is-selected", isSelected);
      button.setAttribute("aria-pressed", isSelected ? "true" : "false");
    });
    logUserTypeAdminDebug("apply_selection", [{ selected_value: normalizedSelection }]);
  }

  function resetUserTypeAdminView() {
    if (userTypeLookupTimer) {
      clearTimeout(userTypeLookupTimer);
      userTypeLookupTimer = null;
    }
    pendingUserTypeLookupToken += 1;
    currentUserTypeAdminHandle = "";
    if (userTypeHandleInput) {
      userTypeHandleInput.value = "";
    }
    if (userTypeEmailInput) {
      userTypeEmailInput.value = "";
    }
    renderUserTypeAdminState({
      statusText: "",
      showChoices: false,
      showInviteeButton: false,
      showEmailUpdate: false,
      authEmail: "",
      currentType: "standard"
    });
    logUserTypeAdminDebug("reset_view");
  }

  function normalizeInviteeIdentifierValue(value) {
    return String(value || "").replace(/\s+/g, " ").trim();
  }

  function resetInviteeAdminView(options = {}) {
    if (inviteeLookupTimer) {
      clearTimeout(inviteeLookupTimer);
      inviteeLookupTimer = null;
    }
    pendingInviteeLookupToken += 1;
    const identifier = normalizeInviteeIdentifierValue(options.identifier || "");
    currentInviteeIdentifier = identifier;
    if (inviteeIdentifierInput) {
      inviteeIdentifierInput.value = identifier;
    }
    if (inviteeFullNameInput) {
      inviteeFullNameInput.value = "";
    }
    if (inviteeEmailInput) {
      inviteeEmailInput.value = "";
    }
    if (inviteeNoteInput) {
      inviteeNoteInput.value = "";
    }
    if (inviteeStatus) {
      inviteeStatus.textContent = "";
    }
    setInviteeAdminActionState({
      canSave: !!identifier && isValidUniqueHandle(identifier),
      canDelete: false,
      canTestNewDevice: !isDeviceTestModeActive(),
      canRestoreMyDevice: canRestoreDeviceIdentity()
    });
  }

  function getCurrentLoadedInviteeIdentifier() {
    return normalizeInviteeIdentifierValue(getLoadedInviteeIdentity()?.identifier || "");
  }

  function getInviteeRecordByIdentifier(identifier) {
    const cleanIdentifier = normalizeInviteeIdentifierValue(identifier);
    if (!cleanIdentifier) {
      return null;
    }
    return inviteeRecordsCache.find((entry) => normalizeInviteeIdentifierValue(entry?.identifier || "") === cleanIdentifier) || null;
  }

  function setInviteeAdminActionState(options = {}) {
    if (inviteeSaveButton) {
      inviteeSaveButton.disabled = !options.canSave;
    }
    if (inviteeDeleteButton) {
      inviteeDeleteButton.disabled = !options.canDelete;
    }
    if (testNewDeviceButton) {
      testNewDeviceButton.disabled = false;
      testNewDeviceButton.setAttribute("aria-disabled", options.canTestNewDevice ? "false" : "true");
    }
    if (restoreMyDeviceButton) {
      restoreMyDeviceButton.disabled = false;
      restoreMyDeviceButton.setAttribute("aria-disabled", options.canRestoreMyDevice ? "false" : "true");
    }
  }

  function renderInviteeAdminList(invitees = []) {
    inviteeRecordsCache = Array.isArray(invitees) ? invitees.slice(0) : [];
    if (!inviteeListBody) {
      return;
    }
    inviteeListBody.innerHTML = "";

    if (!inviteeRecordsCache.length) {
      const emptyRow = document.createElement("tr");
      const cell = document.createElement("td");
      cell.colSpan = 4;
      cell.textContent = "No invitees saved yet.";
      emptyRow.appendChild(cell);
      inviteeListBody.appendChild(emptyRow);
      return;
    }

    inviteeRecordsCache.forEach((invitee) => {
      const row = document.createElement("tr");
      row.dataset.inviteeIdentifier = String(invitee?.identifier || "");
      const values = [
        String(invitee?.identifier || ""),
        String(invitee?.full_name || ""),
        String(invitee?.email || ""),
        String(invitee?.private_note || "")
      ];
      values.forEach((value, index) => {
        const cell = document.createElement("td");
        if (index === 0) {
          const button = document.createElement("button");
          button.type = "button";
          button.className = "invitee-admin-row-button";
          button.textContent = value || "Unnamed";
          button.addEventListener("click", () => {
            loadInviteeIntoForm(String(invitee?.identifier || ""));
          });
          cell.appendChild(button);
        } else {
          cell.textContent = value || "\u2014";
        }
        row.appendChild(cell);
      });
      inviteeListBody.appendChild(row);
    });
  }

  function loadInviteeIntoForm(identifier) {
    const cleanIdentifier = normalizeInviteeIdentifierValue(identifier);
    const match = getInviteeRecordByIdentifier(cleanIdentifier);
    currentInviteeIdentifier = cleanIdentifier;
    if (inviteeIdentifierInput) {
      inviteeIdentifierInput.value = String(match?.identifier || cleanIdentifier);
    }
    if (inviteeFullNameInput) {
      inviteeFullNameInput.value = String(match?.full_name || "");
    }
    if (inviteeEmailInput) {
      inviteeEmailInput.value = String(match?.email || "");
    }
    if (inviteeNoteInput) {
      inviteeNoteInput.value = String(match?.private_note || "");
    }
    if (inviteeStatus) {
      const testModeActive = isDeviceTestModeActive();
      inviteeStatus.textContent = cleanIdentifier
        ? testModeActive
          ? `Invitee ${String(match?.identifier || cleanIdentifier)} is loaded into the form. Test mode is active, so enter this code on the Landing page to test the public invitee flow.`
          : `Invitee ${String(match?.identifier || cleanIdentifier)} is loaded into the form. Save or delete it here, then use Test As New Device to try the Landing-page flow.`
        : "";
    }
    setInviteeAdminActionState({
      canSave: !!match,
      canDelete: !!match,
      canTestNewDevice: !isDeviceTestModeActive(),
      canRestoreMyDevice: canRestoreDeviceIdentity()
    });
  }

  async function evaluateInviteeIdentifier() {
    const typedIdentifier = normalizeInviteeIdentifierValue(inviteeIdentifierInput?.value || currentInviteeIdentifier);
    currentInviteeIdentifier = typedIdentifier;
    const lookupToken = ++pendingInviteeLookupToken;

    if (!typedIdentifier) {
      if (inviteeStatus) {
        inviteeStatus.textContent = "";
      }
      setInviteeAdminActionState({
        canSave: false,
        canDelete: false,
        canTestNewDevice: !isDeviceTestModeActive(),
        canRestoreMyDevice: canRestoreDeviceIdentity()
      });
      return;
    }

    if (!isValidUniqueHandle(typedIdentifier)) {
      if (inviteeStatus) {
        inviteeStatus.textContent = "Invitee unique name is invalid.";
      }
      setInviteeAdminActionState({
        canSave: false,
        canDelete: false,
        canTestNewDevice: !isDeviceTestModeActive(),
        canRestoreMyDevice: canRestoreDeviceIdentity()
      });
      return;
    }

    const savedInvitee = getInviteeRecordByIdentifier(typedIdentifier);
    if (savedInvitee) {
      loadInviteeIntoForm(String(savedInvitee.identifier || typedIdentifier));
      return;
    }

    if (inviteeStatus) {
      inviteeStatus.textContent = "Checking unique name...";
    }
    setInviteeAdminActionState({
      canSave: false,
      canDelete: false,
      canTestNewDevice: !isDeviceTestModeActive(),
      canRestoreMyDevice: canRestoreDeviceIdentity()
    });

    try {
      const lookup = await fetchLandingInvitationIdentity(typedIdentifier);
      if (lookupToken !== pendingInviteeLookupToken) {
        return;
      }

      if (lookup.identifierExists) {
        if (inviteeStatus) {
          inviteeStatus.textContent = "That unique name already exists and cannot be saved as an invitee.";
        }
        setInviteeAdminActionState({
          canSave: false,
          canDelete: false,
          canTestNewDevice: !isDeviceTestModeActive(),
          canRestoreMyDevice: canRestoreDeviceIdentity()
        });
        return;
      }

      if (inviteeStatus) {
        inviteeStatus.textContent = `Unique name ${typedIdentifier} is available to save as an invitee.`;
      }
      setInviteeAdminActionState({
        canSave: true,
        canDelete: false,
        canTestNewDevice: !isDeviceTestModeActive(),
        canRestoreMyDevice: canRestoreDeviceIdentity()
      });
    } catch (error) {
      if (lookupToken !== pendingInviteeLookupToken) {
        return;
      }
      if (inviteeStatus) {
        inviteeStatus.textContent = error instanceof Error ? error.message : "Unable to validate that unique name right now.";
      }
      setInviteeAdminActionState({
        canSave: false,
        canDelete: false,
        canTestNewDevice: !isDeviceTestModeActive(),
        canRestoreMyDevice: canRestoreDeviceIdentity()
      });
    }
  }

  function setTemporaryHomeInvitationStatus(message = "", options = {}) {
    if (!temporaryHomePageInvitationStatus) {
      return;
    }
    const text = String(message || "").trim();
    temporaryHomePageInvitationStatus.textContent = text;
    temporaryHomePageInvitationStatus.style.color = options.isError
      ? "rgba(255, 201, 201, 0.96)"
      : "rgba(255, 234, 190, 0.92)";
  }

  function renderTemporaryHomeReturnState() {
    const state = readLauncherState();
    const deviceTestNotice = readAndClearDeviceTestNotice();
    const temporaryIdentity = getTemporaryIdentityState(state);
    const exploreTrial = state?.exploreTrial && typeof state.exploreTrial === "object" ? state.exploreTrial : null;
    const hasMatchingActiveExploreTrial =
      temporaryIdentity &&
      temporaryIdentity.source === "landing-explore-pro" &&
      exploreTrial &&
      String(exploreTrial.status || "").trim().toLowerCase() !== "expired" &&
      normalizeIdentifierForStorage(String(exploreTrial.identifier || "")) === normalizeIdentifierForStorage(temporaryIdentity.identifier);

    if (temporaryHomePageContinueButton) {
      temporaryHomePageContinueButton.textContent = hasMatchingActiveExploreTrial
        ? "CONTINUE into your active ESP PRO exploration"
        : "CONTINUE into the ESP GYM";
    }

    if (hasMatchingActiveExploreTrial) {
      setTemporaryHomeInvitationStatus(
        `This device already has an active ESP PRO exploration for ${temporaryIdentity.identifier}. Press CONTINUE to return to it.`
      );
      return;
    }

    if (deviceTestNotice) {
      setTemporaryHomeInvitationStatus(deviceTestNotice);
      return;
    }

    setTemporaryHomeInvitationStatus("");
  }

  function setExploreProStatus(message = "", options = {}) {
    if (!exploreProStatus) {
      return;
    }
    const text = String(message || "").trim();
    exploreProStatus.textContent = text;
    exploreProStatus.style.color = options.isError
      ? "rgba(255, 201, 201, 0.96)"
      : "rgba(255, 234, 190, 0.92)";
  }

  function setUpdatesStatus(message = "", options = {}) {
    if (!updatesStatus) {
      return;
    }
    const text = String(message || "").trim();
    updatesStatus.textContent = text;
    updatesStatus.style.color = options.isError
      ? "rgba(255, 201, 201, 0.96)"
      : "rgba(255, 234, 190, 0.92)";
  }

  function openUpdatesOverlay() {
    const state = readLauncherState();
    if (updatesEmailInput) {
      updatesEmailInput.value = String(state.updatesInterestEmail || "").trim();
    }
    setUpdatesStatus("");
    updatesOverlay?.classList.remove("beginner-view-hidden");
    updatesEmailInput?.focus();
    updatesEmailInput?.select?.();
  }

  function getPreferredUpdatesSignupName(state = readLauncherState()) {
    const temporaryIdentity = getTemporaryIdentityState(state);
    const loadedInvitee = getLoadedInviteeIdentity(state);
    const ownNames = state?.ownNames && typeof state.ownNames === "object" ? state.ownNames : {};
    return String(
      temporaryIdentity?.identifier ||
      loadedInvitee?.identifier ||
      ownNames.sender ||
      ownNames.receiver ||
      ownNames["remote-viewer"] ||
      ""
    ).trim();
  }

  function closeUpdatesOverlay() {
    updatesOverlay?.classList.add("beginner-view-hidden");
  }

  async function saveUpdatesInterest() {
    const email = String(updatesEmailInput?.value || "").trim();
    if (!isValidEmailAddress(email)) {
      setUpdatesStatus("Please enter a valid email address.", { isError: true });
      return;
    }
    const latest = readLauncherState();
    const optionalName = getPreferredUpdatesSignupName(latest);
    setUpdatesStatus("Saving email address...");
    try {
      await saveEmailListSignup(email, "updates", optionalName);
      latest.updatesInterestEmail = email;
      writeLauncherState(latest);
      setUpdatesStatus("Email address saved for ESP GYM updates.");
      window.setTimeout(() => {
        closeUpdatesOverlay();
      }, 700);
    } catch (error) {
      setUpdatesStatus(error instanceof Error ? error.message : "Unable to save that email address right now.", { isError: true });
    }
  }

  function resetExploreProOverlay() {
    exploreProOverlayMode = "trial";
    pendingRecoveryIdentifier = "";
    pendingUniqueNameClaim = null;
    if (exploreProTitle) {
      exploreProTitle.textContent = "Explore ESP PRO";
    }
    if (exploreProIntro) {
      exploreProIntro.textContent = "Start your free 14-day ESP PRO exploration.";
    }
    if (exploreProAuthCopy) {
      exploreProAuthCopy.textContent = "Your email address is used for authentication. Please enter your email address below. We will send you a 5-character verification code.";
    }
    if (exploreProEmailInput) {
      exploreProEmailInput.value = "";
    }
    if (exploreProCodeInput) {
      exploreProCodeInput.value = "";
      exploreProCodeInput.setAttribute("maxlength", "5");
    }
    setExploreProStatus("");
    if (exploreProResendCodeButton) {
      exploreProResendCodeButton.hidden = true;
    }
    if (exploreProSubscribeButton) {
      exploreProSubscribeButton.hidden = true;
    }
    if (exploreProSendCodeButton) {
      exploreProSendCodeButton.disabled = false;
    }
    if (exploreProResendCodeButton) {
      exploreProResendCodeButton.disabled = false;
    }
    if (exploreProStartButton) {
      exploreProStartButton.disabled = false;
      exploreProStartButton.textContent = "START FREE 14-DAY EXPLORATION";
    }
    if (exploreProCloseButton) {
      exploreProCloseButton.disabled = false;
      exploreProCloseButton.textContent = "CANCEL";
    }
  }

  function openExploreProOverlay(options = {}) {
    resetExploreProOverlay();
    const requestedMode = String(options.mode || "trial").trim().toLowerCase();
    const mode = requestedMode === "recovery"
      ? "recovery"
      : requestedMode === "claim"
        ? "claim"
        : "trial";
    exploreProOverlayMode = mode;
    pendingRecoveryIdentifier = String(options.identifier || "").trim();
    if (mode === "claim") {
      pendingUniqueNameClaim = options && typeof options === "object"
        ? {
            role: String(options.role || "").trim(),
            returnRole: String(options.returnRole || "").trim(),
            returnScrollY: Math.max(0, Number(options.returnScrollY || 0) || 0),
            postClaimFlow: String(options.postClaimFlow || "").trim(),
            currentIdentifier: String(options.currentIdentifier || "").trim(),
            proposedHandle: String(options.identifier || "").trim()
          }
        : null;
    }
    if (mode === "recovery") {
      if (exploreProTitle) {
        exploreProTitle.textContent = "Verify Existing Unique Name";
      }
      if (exploreProIntro) {
        exploreProIntro.textContent = pendingRecoveryIdentifier
          ? `Verify that you are ${pendingRecoveryIdentifier} on this device.`
          : "Verify your existing unique name on this device.";
      }
      if (exploreProAuthCopy) {
        exploreProAuthCopy.textContent = "Your email address is used for authentication. Please enter the authentication email for this unique name below. We will send you a 5-character verification code.";
      }
      if (exploreProStartButton) {
        exploreProStartButton.textContent = "VERIFY UNIQUE NAME";
      }
    } else if (mode === "claim") {
      const proposedHandle = String(options.identifier || "").trim();
      if (exploreProTitle) {
        exploreProTitle.textContent = "Verify New Unique Name";
      }
      if (exploreProIntro) {
        exploreProIntro.textContent = proposedHandle
          ? `Verify your email to claim ${proposedHandle} as your unique name in ESP GYM.`
          : "Verify your email to claim your unique name in ESP GYM.";
      }
      if (exploreProAuthCopy) {
        exploreProAuthCopy.textContent = "Your email address is used for authentication. Please enter your email address below. We will send you a 5-character verification code. Your unique name will be claimed only after verification succeeds.";
      }
      if (exploreProStartButton) {
        exploreProStartButton.textContent = "CLAIM UNIQUE NAME";
      }
    }
    setFeatureSetupBackButtonTemporarilyHidden(true);
    exploreProOverlay?.classList.remove("beginner-view-hidden");
    exploreProEmailInput?.focus();
    exploreProEmailInput?.select?.();
  }

  function closeExploreProOverlay() {
    exploreProOverlay?.classList.add("beginner-view-hidden");
    setFeatureSetupBackButtonTemporarilyHidden(false);
  }

  async function requestExploreProCode(resend = false) {
    const email = String(exploreProEmailInput?.value || "").trim();
    setExploreProStatus(resend ? "Sending a new verification code..." : "Sending verification code...");
    if (exploreProSendCodeButton) {
      exploreProSendCodeButton.disabled = true;
    }
    if (exploreProResendCodeButton) {
      exploreProResendCodeButton.disabled = true;
    }
    try {
      const verification = exploreProOverlayMode === "recovery"
        ? await sendIdentifierRecoveryCode(pendingRecoveryIdentifier, email)
        : exploreProOverlayMode === "claim"
          ? await sendUniqueNameClaimCode(
              String(pendingUniqueNameClaim?.currentIdentifier || "").trim(),
              String(pendingUniqueNameClaim?.proposedHandle || "").trim(),
              email
            )
        : await sendExploreProVerificationCode(email);
      if (exploreProResendCodeButton) {
        exploreProResendCodeButton.hidden = false;
      }
      if (exploreProSubscribeButton) {
        exploreProSubscribeButton.hidden = true;
      }
      setExploreProStatus(`Verification code sent to ${verification?.email || email}.`);
      exploreProCodeInput?.focus();
      exploreProCodeInput?.select?.();
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unable to send a verification code right now.";
      setExploreProStatus(message, { isError: true });
      if (/exploration period has ended/i.test(message) && exploreProSubscribeButton) {
        exploreProSubscribeButton.hidden = false;
      }
    } finally {
      if (exploreProSendCodeButton) {
        exploreProSendCodeButton.disabled = false;
      }
      if (exploreProResendCodeButton) {
        exploreProResendCodeButton.disabled = false;
      }
    }
  }

  async function startExploreProTrial() {
    const email = String(exploreProEmailInput?.value || "").trim();
    const code = String(exploreProCodeInput?.value || "").trim().toUpperCase();
    setExploreProStatus("Verifying code...");
    if (exploreProStartButton) {
      exploreProStartButton.disabled = true;
    }
    try {
      if (exploreProOverlayMode === "recovery") {
        const data = await verifyIdentifierRecoveryCode(pendingRecoveryIdentifier, email, code);
        const recoveredIdentifier = String(data?.identifier || pendingRecoveryIdentifier).trim();
        const userType = String(data?.user_type || "").trim().toLowerCase() === "pro" ? "pro" : "standard";
        const latestState = readLauncherState();
        const nextIdentityState = buildLauncherIdentityState(latestState, recoveredIdentifier, userType, {
          recognizedIdentity: recoveredIdentifier,
          entryMode: ""
        });
        if (data?.identifier_status && recoveredIdentifier) {
          nextIdentityState.identifierStatusMap = nextIdentityState.identifierStatusMap || {};
          nextIdentityState.identifierStatusMap[normalizeIdentifierForStorage(recoveredIdentifier)] = data.identifier_status;
        }
        writeLauncherState(nextIdentityState);
        setLauncherProfileSaveSuppression(false, true);
        ["sender", "receiver", "remote-viewer"].forEach((role) => {
          const currentRuntime = readRuntimeSettings(role);
          persistLauncherRuntimeIdentity(
            role,
            recoveredIdentifier,
            String(currentRuntime?.partner_email || "").trim(),
            currentRuntime
          );
        });
        setLauncherGuestEntryActive(false);
        applyIdentityStateToLauncherInputs();
        closeExploreProOverlay();
        window.location.href = buildCanonicalLauncherUrl({ open: "launcher" });
        return;
      }
      if (exploreProOverlayMode === "claim") {
        const claimContext = pendingUniqueNameClaim && typeof pendingUniqueNameClaim === "object"
          ? pendingUniqueNameClaim
          : null;
        const data = await verifyUniqueNameClaimCode(
          String(claimContext?.currentIdentifier || "").trim(),
          String(claimContext?.proposedHandle || "").trim(),
          email,
          code
        );
        const acceptedHandle = String(data?.identifier || claimContext?.proposedHandle || "").trim();
        const currentIdentifier = String(claimContext?.currentIdentifier || "").trim();
        if (currentIdentifier && acceptedHandle) {
          propagateClaimedHandle(currentIdentifier, acceptedHandle);
        }
        const migratedState = readLauncherState();
        const nextIdentityState = {
          ...migratedState,
          recognizedIdentity: acceptedHandle,
          ownNames: acceptedHandle ? {
            sender: acceptedHandle,
            receiver: acceptedHandle,
            "remote-viewer": acceptedHandle
          } : {},
          visitorDisplayNames: {},
          visitorLockedName: "",
          entryMode: "",
          resolvedMainUserType: "standard",
          temporaryIdentity: null
        };
        if (data?.identifier_status && acceptedHandle) {
          nextIdentityState.identifierStatusMap = nextIdentityState.identifierStatusMap || {};
          nextIdentityState.identifierStatusMap[normalizeIdentifierForStorage(acceptedHandle)] = data.identifier_status;
        }
        writeLauncherState(nextIdentityState);
        ["sender", "receiver", "remote-viewer"].forEach((role) => {
          const currentRuntime = readRuntimeSettings(role);
          persistLauncherRuntimeIdentity(
            role,
            acceptedHandle,
            String(currentRuntime?.partner_email || "").trim(),
            currentRuntime
          );
        });
        setLauncherGuestEntryActive(false);
        applyIdentityStateToLauncherInputs();
        closeExploreProOverlay();
        if (String(claimContext?.postClaimFlow || "").trim() === "install-gate") {
          showInstallGuideView({ returnView: "feature-setup" });
          return;
        }
        showFeatureSetupView({
          role: String(claimContext?.role || featureSetupReturnRole || activeLauncherRole || "sender").trim() || "sender",
          returnView: featureSetupReturnView || "card",
          scrollY: Number.isFinite(Number(claimContext?.returnScrollY)) ? Number(claimContext.returnScrollY) : 0
        });
        return;
      }
      const data = await verifyExploreProCode(email, code);
      const temporaryIdentity = String(data?.temporary_identity?.identifier || "").trim();
      const userType = String(data?.temporary_identity?.user_type || "").trim().toLowerCase() === "pro" ? "pro" : "standard";
      const baseState = readLauncherState();
      const exploreTrial = normalizeExploreTrialData(data?.explore_trial || data?.trial_activation || null, temporaryIdentity);
      const nextState = buildLauncherIdentityState(baseState, temporaryIdentity, userType, {
        recognizedIdentity: getCanonicalRecognizedIdentity(baseState),
        temporaryIdentity: {
          source: "landing-explore-pro"
        },
        exploreTrial: exploreTrial
          ? {
              email: exploreTrial.email,
              status: exploreTrial.status,
              startedAt: exploreTrial.startedAt,
              expiresAt: exploreTrial.expiresAt,
              noticeShown: false
            }
          : null
      });
      if (data?.identifier_status && temporaryIdentity) {
        nextState.identifierStatusMap = nextState.identifierStatusMap || {};
        nextState.identifierStatusMap[normalizeIdentifierForStorage(temporaryIdentity)] = data.identifier_status;
      }
      await clearLocalFreshStartState();
      writeLauncherState(nextState);
      closeExploreProOverlay();
      window.location.href = buildCanonicalLauncherUrl({ open: "launcher" });
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unable to verify that code right now.";
      setExploreProStatus(message, { isError: true });
      if (/exploration period has ended/i.test(message) && exploreProSubscribeButton) {
        exploreProSubscribeButton.hidden = false;
      }
    } finally {
      if (exploreProStartButton) {
        exploreProStartButton.disabled = false;
      }
    }
  }

  function resetTemporaryHomeExploreButton() {
    if (!temporaryHomePageExploreButton) {
      return;
    }
    temporaryHomePageExploreButton.disabled = false;
    temporaryHomePageExploreButton.textContent = "Explore";
  }

  function shouldResumeRecognizedLandingIdentity(state = readLauncherState()) {
    if (isDeviceTestModeActive(state) || hasDeviceTestRestoreSnapshot()) {
      return false;
    }
    return hasKnownLauncherIdentity(state) && !isVisitorLauncherEntry(state);
  }

  function startVisitorLandingEntry() {
    const baseState = readLauncherState();
    if (shouldResumeRecognizedLandingIdentity(baseState)) {
      window.location.href = buildCanonicalLauncherUrl({ open: "launcher" });
      return;
    }
    const nextState = buildVisitorLauncherState(baseState);
    writeLauncherState(nextState);
    window.location.href = buildCanonicalLauncherUrl({ open: "visitor-launcher" });
  }

  async function handleLandingExploreClick() {
    if (!temporaryHomePageExploreButton) {
      return;
    }
    if (shouldResumeRecognizedLandingIdentity()) {
      window.location.href = buildCanonicalLauncherUrl({ open: "launcher" });
      return;
    }
    temporaryHomePageExploreButton.disabled = true;
    temporaryHomePageExploreButton.textContent = "Preparing...";
    try {
      const data = await fetchPublicTrialModeState();
      if (!!data?.trial_mode_public_enabled) {
        resetTemporaryHomeExploreButton();
        openExploreProOverlay();
        return;
      }
      startVisitorLandingEntry();
    } catch (error) {
      resetTemporaryHomeExploreButton();
      setTemporaryHomeInvitationStatus(error instanceof Error ? error.message : "Unable to open that experience right now.", { isError: true });
    }
  }

  async function resolveLandingExploreEntry() {
    try {
      const data = await fetchPublicTrialModeState();
      if (!!data?.trial_mode_public_enabled) {
        showTemporaryHomePageView();
        openExploreProOverlay();
        return;
      }
      startVisitorLandingEntry();
    } catch (error) {
      showTemporaryHomePageView();
      resetTemporaryHomeExploreButton();
      setTemporaryHomeInvitationStatus(error instanceof Error ? error.message : "Unable to open that experience right now.", { isError: true });
    }
  }

  function applyIdentityStateToLauncherInputs() {
    const state = readLauncherState();
    const visitorMode = isVisitorLauncherEntry(state);
    ["sender", "receiver"].forEach((role) => {
      const form = document.querySelector(`[data-role-form="${role}"]`);
      if (!form) {
        return;
      }
      const ownInput = form.querySelector('input[name="ownName"]');
      const partnerInput = form.querySelector('input[name="partnerName"]');
      if (!ownInput || !partnerInput) {
        return;
      }
      const roleSettings = readRoleSettings(role);
      const savedOwn = visitorMode
        ? String(getPreferredVisitorDisplayNameForRole(role, state) || "").trim()
        : String(state.ownNames?.[role] || "").trim() || roleSettings.ownName || "";
      const profileState = visitorMode ? null : (savedOwn ? readLauncherProfileState(role, savedOwn, state) : null);
      const savedPartner = visitorMode
        ? "Robot"
        : profileState?.currentPartner || String(state.currentPartners?.[role] || "").trim() || roleSettings.partnerName || "";
      ownInput.value = savedOwn;
      ownInput.placeholder = visitorMode ? "" : (role === "sender"
        ? "Enter unique name of sender"
        : "Enter unique name of receiver");
      applyVisitorOwnInputLock(ownInput, visitorMode ? getVisitorLockedName(state) : "", visitorMode);
      partnerInput.value = savedPartner;
      partnerInput.placeholder = role === "sender"
        ? "Enter unique name of receiver"
        : "Enter unique name of sender";
      applyVisitorPartnerInputLock(partnerInput, visitorMode);
      applyPartnerHistory(role, form, state, savedOwn);
      applyRoleIdentifierPresentation(role, {
        ownUsesHandle: isValidUniqueHandle(savedOwn) && !isValidEmailAddress(savedOwn),
        partnerUsesHandle: isValidUniqueHandle(savedPartner) && !isValidEmailAddress(savedPartner)
      });
    });
    renderRemoteViewerCard();
    renderMainTitle(resolvedMainUserType === "pro" ? "pro" : "standard");
    void refreshDifficultyLabels();
  }

  async function maybePromptInviteeLocationPermission() {
    const state = await syncBrowserLocationPermission();
    if (!navigator.geolocation) {
      return;
    }
    if (state.locationPermission === "granted" || state.locationPermission === "manual" || state.locationPermission === "denied") {
      renderLocationStatus();
      return;
    }
    await requestDeviceLocationIfNeeded(true);
  }

  async function maybePromptInviteeNotificationPermission(identifier) {
    if (!("Notification" in window)) {
      return;
    }
    let permission = getNotificationPermissionSnapshot();
    if (permission === "default") {
      permission = String(await Notification.requestPermission()).trim().toLowerCase() || "default";
      syncNotificationPermissionSnapshot();
    }
    if (permission === "granted") {
      try {
        await subscribeCurrentDeviceForIdentifier(identifier);
      } catch (_) {
        // Keep launcher entry flowing even if notification registration is not ready yet.
      }
    }
  }

  function loadInvitationIdentityOntoDevice(identifier, userType, identifierStatus, options = {}) {
    const cleanIdentifier = String(identifier || "").trim();
    const normalizedUserType = userType === "pro" ? "pro" : "standard";
    const baseState = readLauncherState();
    const existingLoaded = getLoadedInviteeIdentity(baseState);
    const previousIdentitySnapshot = existingLoaded?.previousIdentitySnapshot || snapshotDeviceIdentityState(baseState);
    const nextState = buildLauncherIdentityState(baseState, cleanIdentifier, normalizedUserType, {
      recognizedIdentity: getCanonicalRecognizedIdentity(baseState)
    });
    nextState.loadedInviteeIdentity = {
      identifier: cleanIdentifier,
      userType: normalizedUserType,
      source: String(options.source || "landing-invitation").trim() || "landing-invitation",
      previousIdentitySnapshot
    };
    nextState.pendingInviteeOnboarding = normalizedUserType === "pro"
      ? {
          identifier: cleanIdentifier,
          userType: normalizedUserType,
          requestLocation: true,
          requestNotifications: true
        }
      : null;
    writeLauncherState(nextState);
    setLauncherProfileSaveSuppression(false, true);
    if (identifierStatus) {
      rememberIdentifierStatus(cleanIdentifier, identifierStatus);
    }
    persistLauncherRuntimeIdentity("sender", cleanIdentifier, "");
    persistLauncherRuntimeIdentity("receiver", cleanIdentifier, "");
    persistLauncherRuntimeIdentity("remote-viewer", cleanIdentifier, "");
    setLauncherGuestEntryActive(false);
  }

  function clearLoadedInviteeIdentityFromDevice() {
    const latest = readLauncherState();
    const loaded = getLoadedInviteeIdentity(latest);
    if (!loaded) {
      return null;
    }
    const restored = finalizeRestoredIdentityState(restoreDeviceIdentitySnapshot(loaded.previousIdentitySnapshot || {}, latest));
    writeLauncherState(restored);
    const runtimeSettings = loaded.previousIdentitySnapshot?.runtimeSettings && typeof loaded.previousIdentitySnapshot.runtimeSettings === "object"
      ? loaded.previousIdentitySnapshot.runtimeSettings
      : {};
    ["sender", "receiver", "remote-viewer"].forEach((role) => {
      const nextRuntime = runtimeSettings[role] && typeof runtimeSettings[role] === "object" ? runtimeSettings[role] : {};
      writeRuntimeSettings(role, nextRuntime);
    });
    writeLauncherState(hydrateRecognizedIdentityFromCurrentState());
    setLauncherGuestEntryActive(false);
    applyIdentityStateToLauncherInputs();
    return loaded;
  }

  async function continueFromLandingPage() {
    const invitationCode = String(temporaryHomePageInvitationCodeInput?.value || "").trim();
    if (!invitationCode) {
      const launcherState = readLauncherState();
      if (hasKnownLauncherIdentity(launcherState) && !isVisitorLauncherEntry(launcherState)) {
        window.location.href = buildCanonicalLauncherUrl({ open: "launcher" });
        return;
      }
      startVisitorLandingEntry();
      return;
    }

    setTemporaryHomeInvitationStatus("Checking invitation code...");

    try {
      const lookup = await fetchLandingInvitationIdentity(invitationCode);
      const identifierStatus = lookup.identifierStatus || null;
      const preferredIdentifier = String(identifierStatus?.preferred_identifier || lookup.identifier || "").trim() || lookup.identifier;
      const recognizedHandle = isValidUniqueHandle(preferredIdentifier) && isAcceptedUniqueHandleIdentifier(preferredIdentifier, identifierStatus);
      const recognizedEmail = isValidEmailAddress(preferredIdentifier) && !!lookup.identifierExists;
      if (!lookup.identifierExists || (!recognizedHandle && !recognizedEmail)) {
        throw new Error("That invitation code is not recognized.");
      }

      setTemporaryHomeInvitationStatus(lookup.userType === "pro" ? "Preparing ESP PRO..." : "Preparing Telepathy Beginner...");
      loadInvitationIdentityOntoDevice(preferredIdentifier, lookup.userType, identifierStatus, {
        source: "landing-invitation"
      });
      window.location.href = buildCanonicalLauncherUrl({ open: "launcher" });
    } catch (error) {
      setTemporaryHomeInvitationStatus(error instanceof Error ? error.message : "Unable to continue from that invitation code right now.", { isError: true });
    }
  }

  function startInviteeDeviceTestMode() {
    let latest = clearStaleDeviceTestModeArtifactsIfNeeded(readLauncherState());
    logLauncherUserTypeDebug("invitee_test_mode_start_attempt", {
      deviceTestModeActive: isDeviceTestModeActive(latest),
      rawDeviceTestMode: cloneJsonValue(latest?.deviceTestMode || null, null),
      hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot(),
      recognizedIdentity: String(latest?.recognizedIdentity || "").trim(),
      entryMode: String(latest?.entryMode || "").trim(),
      loadedInviteeIdentifier: String(getLoadedInviteeIdentity(latest)?.identifier || "").trim()
    });
    if (isDeviceTestModeActive(latest)) {
      if (!hasAuthoritativeDeviceIdentity(latest)) {
        logLauncherUserTypeDebug("invitee_test_mode_restart_from_anonymous_state", {
          rawDeviceTestMode: cloneJsonValue(latest?.deviceTestMode || null, null),
          hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot(),
          recognizedIdentity: String(latest?.recognizedIdentity || "").trim(),
          entryMode: String(latest?.entryMode || "").trim()
        });
        clearDeviceTestRestoreSnapshot();
        writeDeviceTestNotice("");
        latest = normalizeLauncherIdentityState({
          ...latest,
          deviceTestMode: null
        });
        writeLauncherState(latest);
      } else {
      logLauncherUserTypeDebug("invitee_test_mode_already_active_branch", {
        rawDeviceTestMode: cloneJsonValue(latest?.deviceTestMode || null, null),
        hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot(),
        recognizedIdentity: String(latest?.recognizedIdentity || "").trim(),
        entryMode: String(latest?.entryMode || "").trim()
      });
      if (inviteeStatus) {
        inviteeStatus.textContent = "Test mode is already active on this device.";
      }
      setInviteeAdminActionState({
        canSave: !!currentInviteeIdentifier && isValidUniqueHandle(currentInviteeIdentifier),
        canDelete: !!getInviteeRecordByIdentifier(currentInviteeIdentifier),
        canTestNewDevice: false,
        canRestoreMyDevice: true
      });
      return;
      }
    }

    const restoreSnapshot = snapshotDeviceIdentityState(latest);
    const restoreDescription = describeRestoreSnapshotIdentity(restoreSnapshot);
    writeDeviceTestRestoreSnapshot(restoreSnapshot);
    const nextState = buildVisitorLauncherState(latest);
    nextState.deviceTestMode = {
      active: true,
      restoreSnapshot,
      startedAt: Date.now()
    };
    ["sender", "receiver", "remote-viewer"].forEach((role) => {
      clearRuntimeSettings(role);
    });
    writeLauncherState(nextState);
    writeDeviceTestNotice(
      `Test As New Device is active. Restore My Device will restore ${restoreDescription}.`
    );
    logLauncherUserTypeDebug("invitee_test_mode_started", {
      hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot(),
      recognizedIdentity: String(nextState?.recognizedIdentity || "").trim(),
      entryMode: String(nextState?.entryMode || "").trim()
    });
    setLauncherGuestEntryActive(false);
    if (inviteeStatus) {
      inviteeStatus.textContent = "Test mode started. This device is now behaving like a new device.";
    }
    window.alert(`Test As New Device is active.\n\nRestore My Device will restore ${restoreDescription}.`);
    window.location.href = buildCanonicalLauncherUrl({ open: "landing" });
  }

  function restoreInviteeDeviceTestMode() {
    const latest = clearStaleDeviceTestModeArtifactsIfNeeded(readLauncherState());
    const testMode = getDeviceTestModeState(latest);
    const loadedInvitee = getLoadedInviteeIdentity(latest);
    const restoreSnapshot = testMode?.restoreSnapshot || readDeviceTestRestoreSnapshot();
    const snapshotIdentity = String(restoreSnapshot?.recognizedIdentity || "").trim();
    logLauncherUserTypeDebug("invitee_test_mode_restore_attempt", {
      deviceTestModeActive: !!testMode?.active,
      hasInlineRestoreSnapshot: !!testMode?.restoreSnapshot,
      hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot(),
      recognizedIdentity: String(latest?.recognizedIdentity || "").trim(),
      loadedInviteeIdentifier: String(loadedInvitee?.identifier || "").trim()
    });
    if (!restoreSnapshot && loadedInvitee) {
      clearLoadedInviteeIdentityFromDevice();
      clearDeviceTestRestoreSnapshot();
      setLauncherProfileSaveSuppression(false, true);
      logLauncherUserTypeDebug("invitee_loaded_identity_restored", {
        recognizedIdentity: String(readLauncherState()?.recognizedIdentity || "").trim(),
        restoredInviteeIdentifier: String(loadedInvitee?.identifier || "").trim(),
        hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot()
      });
      setLauncherGuestEntryActive(false);
      applyIdentityStateToLauncherInputs();
      if (inviteeStatus) {
        inviteeStatus.textContent = snapshotIdentity
          ? `Your original device state has been restored: ${snapshotIdentity}.`
          : "Your original device state has been restored.";
      }
      setInviteeAdminActionState({
        canSave: !!currentInviteeIdentifier && isValidUniqueHandle(currentInviteeIdentifier),
        canDelete: !!getInviteeRecordByIdentifier(currentInviteeIdentifier),
        canTestNewDevice: true,
        canRestoreMyDevice: false
      });
      return;
    }
    if (!restoreSnapshot) {
      if (inviteeStatus) {
        inviteeStatus.textContent = "No saved device snapshot is available to restore.";
      }
      setInviteeAdminActionState({
        canSave: !!currentInviteeIdentifier && isValidUniqueHandle(currentInviteeIdentifier),
        canDelete: !!getInviteeRecordByIdentifier(currentInviteeIdentifier),
        canTestNewDevice: true,
        canRestoreMyDevice: false
      });
      return;
    }

    const restored = finalizeRestoredIdentityState(restoreDeviceIdentitySnapshot(restoreSnapshot, latest));
    writeLauncherState(restored);
    const runtimeSettings = restoreSnapshot.runtimeSettings && typeof restoreSnapshot.runtimeSettings === "object"
      ? restoreSnapshot.runtimeSettings
      : {};
    ["sender", "receiver", "remote-viewer"].forEach((role) => {
      const nextRuntime = runtimeSettings[role] && typeof runtimeSettings[role] === "object" ? runtimeSettings[role] : {};
      writeRuntimeSettings(role, nextRuntime);
    });
    writeLauncherState(hydrateRecognizedIdentityFromCurrentState());
    clearDeviceTestRestoreSnapshot();
    setLauncherProfileSaveSuppression(false, true);
    logLauncherUserTypeDebug("invitee_test_mode_restored", {
      recognizedIdentity: String(readLauncherState()?.recognizedIdentity || "").trim(),
      loadedInviteeIdentifier: String(getLoadedInviteeIdentity(readLauncherState())?.identifier || "").trim(),
      hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot()
    });
    setLauncherGuestEntryActive(false);
    applyIdentityStateToLauncherInputs();
    if (inviteeStatus) {
      inviteeStatus.textContent = snapshotIdentity
        ? `Your original device state has been restored: ${snapshotIdentity}.`
        : "Your original device state has been restored.";
    }
    setInviteeAdminActionState({
      canSave: !!currentInviteeIdentifier && isValidUniqueHandle(currentInviteeIdentifier),
      canDelete: !!getInviteeRecordByIdentifier(currentInviteeIdentifier),
      canTestNewDevice: true,
      canRestoreMyDevice: false
    });
  }

  async function deleteInviteeRecord() {
    const identifier = normalizeInviteeIdentifierValue(inviteeIdentifierInput?.value || currentInviteeIdentifier);
    if (!identifier) {
      if (inviteeStatus) {
        inviteeStatus.textContent = "Enter or load an invitee before deleting.";
      }
      return;
    }

    if (!window.confirm(`Delete invitee ${identifier}?`)) {
      return;
    }

    if (inviteeStatus) {
      inviteeStatus.textContent = "Deleting invitee...";
    }

    try {
      const data = await launcherAdminApi("delete_invitee", {
        identifier
      });
      const loadedIdentifier = getCurrentLoadedInviteeIdentifier();
      if (loadedIdentifier && normalizeInviteeIdentifierValue(loadedIdentifier) === identifier) {
        clearLoadedInviteeIdentityFromDevice();
      }
      currentInviteeIdentifier = "";
      resetInviteeAdminView();
      renderInviteeAdminList(Array.isArray(data?.invitees) ? data.invitees : []);
      if (inviteeStatus) {
        inviteeStatus.textContent = String(data?.message || `Invitee ${identifier} deleted.`);
      }
      void refreshAdminView();
    } catch (error) {
      if (inviteeStatus) {
        inviteeStatus.textContent = error instanceof Error ? error.message : "Unable to delete that invitee right now.";
      }
    }
  }

  async function refreshInviteeAdminList(options = {}) {
    try {
      const data = await launcherAdminApi("list_invitees");
      const invitees = Array.isArray(data?.invitees) ? data.invitees : [];
      renderInviteeAdminList(invitees);
      if (currentInviteeIdentifier) {
        const stillExists = invitees.some((entry) => normalizeInviteeIdentifierValue(entry?.identifier || "") === currentInviteeIdentifier);
        if (stillExists) {
          loadInviteeIntoForm(currentInviteeIdentifier);
        } else if (options.preserveSelection) {
          void evaluateInviteeIdentifier();
        }
      } else {
        setInviteeAdminActionState({
          canSave: false,
          canDelete: false,
          canTestNewDevice: !isDeviceTestModeActive(),
          canRestoreMyDevice: canRestoreDeviceIdentity()
        });
      }
      return invitees;
    } catch (error) {
      renderInviteeAdminList([]);
      if (inviteeStatus) {
        inviteeStatus.textContent = error instanceof Error ? error.message : "Unable to load invitees right now.";
      }
      return [];
    }
  }

  async function saveInviteeRecord() {
    const identifier = normalizeInviteeIdentifierValue(inviteeIdentifierInput?.value || currentInviteeIdentifier);
    const fullName = String(inviteeFullNameInput?.value || "").replace(/\s+/g, " ").trim();
    const email = String(inviteeEmailInput?.value || "").trim();
    const privateNote = String(inviteeNoteInput?.value || "").trim();

    if (!isValidUniqueHandle(identifier)) {
      if (inviteeStatus) {
        inviteeStatus.textContent = "Invitee unique name is invalid.";
      }
      return;
    }

    if (inviteeStatus) {
      inviteeStatus.textContent = "Saving invitee...";
    }

    try {
      const data = await launcherAdminApi("save_invitee", {
        identifier,
        full_name: fullName,
        email,
        private_note: privateNote
      });
      const authoritativeInvitees = Array.isArray(data?.invitees) ? data.invitees : [];
      const authoritativeMatch = authoritativeInvitees.find(
        (entry) => normalizeInviteeIdentifierValue(entry?.identifier || "") === normalizeInviteeIdentifierValue(data?.invitee?.identifier || identifier)
      );
      if (!authoritativeMatch) {
        throw new Error("The server did not confirm that invitee save. Please try again.");
      }
      currentInviteeIdentifier = String(data?.invitee?.identifier || identifier);
      await refreshInviteeAdminList({ preserveSelection: true });
      if (inviteeStatus) {
        const countLabel = Number.isFinite(Number(data?.invitee_count)) ? ` Saved invitees on server: ${Number(data.invitee_count)}.` : "";
        inviteeStatus.textContent = `${String(data?.message || `Invitee ${currentInviteeIdentifier} saved.`)}${countLabel}`;
      }
      setInviteeAdminActionState({
        canSave: true,
        canDelete: true,
        canTestNewDevice: !isDeviceTestModeActive(),
        canRestoreMyDevice: canRestoreDeviceIdentity()
      });
      void refreshAdminView();
    } catch (error) {
      if (inviteeStatus) {
        inviteeStatus.textContent = error instanceof Error ? error.message : "Unable to save that invitee right now.";
      }
    }
  }

  function resetHandleUpdateAdminView() {
    if (handleUpdateLookupTimer) {
      clearTimeout(handleUpdateLookupTimer);
      handleUpdateLookupTimer = null;
    }
    pendingHandleUpdateLookupToken += 1;
    if (handleUpdateOldInput) {
      handleUpdateOldInput.value = "";
    }
    if (handleUpdateNewInput) {
      handleUpdateNewInput.value = "";
    }
    if (handleUpdateSummary) {
      handleUpdateSummary.hidden = true;
      handleUpdateSummary.textContent = "";
    }
    if (handleUpdateStatus) {
      handleUpdateStatus.textContent = "";
    }
  }

  function renderHandleUpdateSummary(summary) {
    if (!handleUpdateSummary) {
      return;
    }

    if (!summary) {
      handleUpdateSummary.hidden = true;
      handleUpdateSummary.textContent = "";
      return;
    }

    const history = Array.isArray(summary?.handle_history) ? summary.handle_history.filter(Boolean) : [];
    const currentHandle = String(summary?.current_handle || "").trim() || "unknown";
    const userType = String(summary?.user_type || "").trim() || "STD";
    const ownerEmail = String(summary?.owner_email || "").trim();
    const ownerLine = ownerEmail ? ownerEmail : "not available";
    const stateLabel = summary?.is_active ? "Active" : (summary?.is_retired ? "Retired" : "Unknown");
    const historyLine = history.length ? history.join(" -> ") : currentHandle;

    handleUpdateSummary.textContent =
      `Current handle: ${currentHandle}\n` +
      `Status: ${userType}\n` +
      `Email: ${ownerLine}\n` +
      `Handle state: ${stateLabel}\n` +
      `Handle history: ${historyLine}`;
    handleUpdateSummary.hidden = false;
  }

  async function lookupHandleUpdateSummary() {
    if (handleUpdateLookupTimer) {
      clearTimeout(handleUpdateLookupTimer);
      handleUpdateLookupTimer = null;
    }

    const handle = String(handleUpdateOldInput?.value || "").replace(/\s+/g, " ").trim();
    const lookupToken = pendingHandleUpdateLookupToken + 1;
    pendingHandleUpdateLookupToken = lookupToken;

    if (!handle) {
      renderHandleUpdateSummary(null);
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = "";
      }
      return;
    }

    if (!isValidUniqueHandle(handle)) {
      renderHandleUpdateSummary(null);
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = "Current handle is invalid.";
      }
      return;
    }

    if (handleUpdateStatus) {
      handleUpdateStatus.textContent = "Checking handle history...";
    }

    try {
      const summary = await fetchHandleAdminSummary(handle);
      if (lookupToken !== pendingHandleUpdateLookupToken) {
        return;
      }
      renderHandleUpdateSummary(summary);
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = "";
      }
    } catch (error) {
      if (lookupToken !== pendingHandleUpdateLookupToken) {
        return;
      }
      renderHandleUpdateSummary(null);
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = error instanceof Error ? error.message : "Unable to look up that handle right now.";
      }
    }
  }

  function scheduleHandleUpdateSummaryLookup(delayMs = 300) {
    if (handleUpdateLookupTimer) {
      clearTimeout(handleUpdateLookupTimer);
      handleUpdateLookupTimer = null;
    }
    handleUpdateLookupTimer = setTimeout(() => {
      handleUpdateLookupTimer = null;
      void lookupHandleUpdateSummary();
    }, delayMs);
  }

  async function lookupUserTypeForAdminHandle() {
    if (userTypeLookupTimer) {
      clearTimeout(userTypeLookupTimer);
      userTypeLookupTimer = null;
    }
    const handle = String(userTypeHandleInput?.value || "").trim();
    const lookupToken = pendingUserTypeLookupToken + 1;
    pendingUserTypeLookupToken = lookupToken;
    currentUserTypeAdminHandle = "";

    if (!handle) {
      renderUserTypeAdminState({
        statusText: "",
        showChoices: false,
        showInviteeButton: false,
        showEmailUpdate: false,
        authEmail: "",
        currentType: "standard"
      });
      logUserTypeAdminDebug("lookup_empty");
      return;
    }

    if (!isValidParticipantIdentifier(handle)) {
      renderUserTypeAdminState({
        statusText: "That identifier is invalid.",
        showChoices: false,
        showInviteeButton: false,
        showEmailUpdate: false,
        authEmail: "",
        currentType: "standard"
      });
      logUserTypeAdminDebug("lookup_invalid_identifier", [{ attempted_identifier: handle }]);
      return;
    }

    logUserTypeAdminDebug("lookup_start", [{ attempted_identifier: handle, lookup_token: lookupToken }]);
    renderUserTypeAdminState({
      statusText: "Checking user identifier...",
      showChoices: false,
      showInviteeButton: false,
      showEmailUpdate: false,
      authEmail: "",
      currentType: "standard"
    });

    try {
      const response = await fetch("api.php", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          action: "get_user_type",
          identifier: handle
        })
      });

      const data = await parseApiResponse(response, `User-type lookup failed with status ${response.status}`);
      if (lookupToken !== pendingUserTypeLookupToken) {
        logUserTypeAdminDebug("lookup_stale_ignored", [{ attempted_identifier: handle, lookup_token: lookupToken }]);
        return;
      }
      const identifierStatus = data?.identifier_status || null;
      if (!data?.identifier_exists) {
        const canInvite = isValidUniqueHandle(handle);
        renderUserTypeAdminState({
          statusText: "That user identifier does not exist.",
          showChoices: false,
          showInviteeButton: canInvite,
          showEmailUpdate: false,
          authEmail: "",
          currentType: "standard"
        });
        logUserTypeAdminDebug("lookup_missing_identifier", [{ attempted_identifier: handle }]);
        return;
      }

      currentUserTypeAdminHandle = handle;
      renderUserTypeAdminState({
        statusText: `Current status for ${handle}: ${String(data?.user_type || "standard").toUpperCase()}`,
        showChoices: true,
        showInviteeButton: false,
        showEmailUpdate: true,
        authEmail: String(data?.auth_email || "").trim(),
        currentType: String(data?.user_type || "standard")
      });
      logUserTypeAdminDebug("lookup_success", [{
        attempted_identifier: handle,
        returned_user_type: String(data?.user_type || "standard"),
        identifier_status: {
          input_identifier: identifierStatus?.input_identifier || "",
          preferred_identifier: identifierStatus?.preferred_identifier || "",
          preferred_handle: identifierStatus?.preferred_handle || "",
          owner_identifier: identifierStatus?.owner_identifier || "",
          uses_handle: !!identifierStatus?.uses_handle,
          is_handle: !!identifierStatus?.is_handle
        }
      }]);
    } catch (error) {
      if (lookupToken !== pendingUserTypeLookupToken) {
        logUserTypeAdminDebug("lookup_error_stale_ignored", [{ attempted_identifier: handle, lookup_token: lookupToken }]);
        return;
      }
      renderUserTypeAdminState({
        statusText: error instanceof Error ? error.message : "Unable to look up that user right now.",
        showChoices: false,
        showInviteeButton: false,
        showEmailUpdate: false,
        authEmail: "",
        currentType: "standard"
      });
      logUserTypeAdminDebug("lookup_error", [{
        attempted_identifier: handle,
        error: error instanceof Error ? error.message : String(error)
      }]);
    }
  }

  function scheduleUserTypeLookup(delayMs = 350) {
    if (userTypeLookupTimer) {
      clearTimeout(userTypeLookupTimer);
      userTypeLookupTimer = null;
    }

    const handle = String(userTypeHandleInput?.value || "").trim();
    currentUserTypeAdminHandle = "";

    if (!handle) {
      renderUserTypeAdminState({
        statusText: "",
        showChoices: false,
        showInviteeButton: false,
        showEmailUpdate: false,
        authEmail: "",
        currentType: "standard"
      });
      logUserTypeAdminDebug("schedule_empty");
      return;
    }

    if (!isValidParticipantIdentifier(handle)) {
      renderUserTypeAdminState({
        statusText: "That identifier is invalid.",
        showChoices: false,
        showInviteeButton: false,
        showEmailUpdate: false,
        authEmail: "",
        currentType: "standard"
      });
      logUserTypeAdminDebug("schedule_invalid_identifier", [{ attempted_identifier: handle }]);
      return;
    }

    renderUserTypeAdminState({
      statusText: "",
      showChoices: false,
      showInviteeButton: false,
      showEmailUpdate: false,
      authEmail: "",
      currentType: "standard"
    });
    logUserTypeAdminDebug("schedule_lookup", [{ attempted_identifier: handle, delay_ms: delayMs }]);

    userTypeLookupTimer = setTimeout(() => {
      userTypeLookupTimer = null;
      void lookupUserTypeForAdminHandle();
    }, delayMs);
  }

  async function saveUserTypeAssignment() {
    const selectedType = pendingUserTypeSelection || "standard";
    const handle = currentUserTypeAdminHandle || String(userTypeHandleInput?.value || "").trim();
    logUserTypeAdminDebug("save_start", [{ attempted_identifier: handle, selected_type: selectedType }]);

    if (!isValidParticipantIdentifier(handle)) {
      renderUserTypeAdminState({
        statusText: "That identifier is invalid.",
        showChoices: false,
        showEmailUpdate: false,
        authEmail: "",
        currentType: "standard"
      });
      logUserTypeAdminDebug("save_invalid_identifier", [{ attempted_identifier: handle, selected_type: selectedType }]);
      return;
    }

    renderUserTypeAdminState({
      statusText: "Saving user status...",
      showChoices: true,
      showEmailUpdate: true,
      authEmail: String(userTypeEmailInput?.value || "").trim(),
      currentType: selectedType
    });

    try {
      const savedType = await assignUserType(handle, selectedType);
      currentUserTypeAdminHandle = handle;
      renderUserTypeAdminState({
        statusText: `Current status for ${handle}: ${savedType.toUpperCase()}.`,
        showChoices: true,
        showInviteeButton: false,
        showEmailUpdate: true,
        authEmail: String(userTypeEmailInput?.value || "").trim(),
        currentType: savedType
      });
      logUserTypeAdminDebug("save_success", [{ attempted_identifier: handle, saved_type: savedType }]);
      void refreshMainUserType();
    } catch (error) {
      renderUserTypeAdminState({
        statusText: error instanceof Error ? error.message : "Unable to save that user status right now.",
        showChoices: true,
        showInviteeButton: false,
        showEmailUpdate: true,
        authEmail: String(userTypeEmailInput?.value || "").trim(),
        currentType: selectedType
      });
      logUserTypeAdminDebug("save_error", [{
        attempted_identifier: handle,
        selected_type: selectedType,
        error: error instanceof Error ? error.message : String(error)
      }]);
    }
  }

  async function saveHandleUpdateAssignment() {
    const previousHandle = String(handleUpdateOldInput?.value || "").replace(/\s+/g, " ").trim();
    const newHandle = String(handleUpdateNewInput?.value || "").replace(/\s+/g, " ").trim();

    if (!isValidUniqueHandle(previousHandle)) {
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = "Current handle is invalid.";
      }
      return;
    }
    if (!isValidParticipantIdentifier(newHandle)) {
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = "New identifier is invalid.";
      }
      return;
    }

    if (handleUpdateStatus) {
      handleUpdateStatus.textContent = "Updating handle...";
    }

    try {
      const updateResult = await adminUpdateHandle(previousHandle, newHandle);
      propagateClaimedHandle(previousHandle, newHandle);
      if (handleUpdateOldInput) {
        handleUpdateOldInput.value = newHandle;
      }
      if (handleUpdateNewInput) {
        handleUpdateNewInput.value = newHandle;
      }
      await lookupHandleUpdateSummary();
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = String(updateResult?.message || "Handle successfully updated.");
      }
      if (!subscriptionsAdminView?.classList.contains("beginner-view-hidden")) {
        try {
          const subscriptionData = await launcherAdminApi("list_admin_subscriptions");
          launcherAdminState.subscription_summary = Array.isArray(subscriptionData?.subscription_summary) ? subscriptionData.subscription_summary : launcherAdminState.subscription_summary;
          launcherAdminState.subscription_summary_meta = subscriptionData?.subscription_summary_meta || launcherAdminState.subscription_summary_meta;
          renderAdminSubscriptionsView();
        } catch (error) {
          // Leave the rename success intact even if the subscription refresh fails.
        }
      }
      void refreshMainUserType();
      void refreshAdminView();
    } catch (error) {
      if (handleUpdateStatus) {
        handleUpdateStatus.textContent = error instanceof Error ? error.message : "Unable to update that handle right now.";
      }
    }
  }

  async function submitImagePairAdmin() {
    const fileA = imagePairFileInputA?.files?.[0] || null;
    const fileB = imagePairFileInputB?.files?.[0] || null;

    if (!fileA || !fileB) {
      if (imagePairStatus) {
        imagePairStatus.textContent = "Please choose both images before submitting.";
      }
      return;
    }

    if (imagePairSubmitButton) {
      imagePairSubmitButton.disabled = true;
    }
    if (imagePairStatus) {
      imagePairStatus.textContent = "Uploading image pair...";
    }

    try {
      const [dataUrlA, dataUrlB] = await Promise.all([
        readFileAsDataUrl(fileA),
        readFileAsDataUrl(fileB)
      ]);
      const response = await launcherAdminApi("add_image_pair", {
        image_a: {
          name: fileA.name,
          data_url: dataUrlA
        },
        image_b: {
          name: fileB.name,
          data_url: dataUrlB
        }
      });

      resetImagePairAdminView();
      if (imagePairStatus) {
        imagePairStatus.textContent = `Image pair ${String(response?.image_pair?.id || "").trim() || "saved"} added successfully.`;
      }
      void refreshAdminView();
    } catch (error) {
      if (imagePairStatus) {
        imagePairStatus.textContent = error instanceof Error ? error.message : "Unable to add that image pair right now.";
      }
    } finally {
      if (imagePairSubmitButton) {
        imagePairSubmitButton.disabled = false;
      }
    }
  }

