  async function saveSubscriptionEmailTemplate() {
    const templateKey = String(activeSubscriptionEmailTemplateKey || "").trim();
    if (!templateKey || templateKey === "email-log") {
      renderSubscriptionEmailAdminStatus("Choose a subscription email template before saving.");
      return;
    }

    const subject = String(subscriptionEmailSubjectInput?.value || "").trim();
    const body = String(subscriptionEmailBodyInput?.value || "").trim();
    if (!subject || !body) {
      renderSubscriptionEmailAdminStatus("Both subject and body are required.");
      return;
    }

    renderSubscriptionEmailAdminStatus("Saving subscription email template...");
    try {
      const data = await launcherAdminApi("save_subscription_email_template", {
        template_key: templateKey,
        subject,
        body
      });
      launcherAdminState.subscription_email_templates = data?.subscription_email_templates || launcherAdminState.subscription_email_templates;
      renderSubscriptionEmailTemplateSelection(templateKey);
      renderSubscriptionEmailAdminStatus("Subscription email template saved.");
    } catch (error) {
      renderSubscriptionEmailAdminStatus("Unable to save the subscription email template right now.");
    }
  }

  async function runSubscriptionReminderScan(testMode = false) {
    if (!hasLauncherAdminAccess()) {
      return;
    }

    if (adminStatus) {
      adminStatus.textContent = testMode
        ? "Sending annual reminder test..."
        : "Running annual reminder scan...";
    }

    try {
      const data = await launcherAdminApi("run_subscription_reminder_scan", {
        test_mode: !!testMode
      });
      launcherAdminState.subscription_email_log = data?.subscription_email_log || launcherAdminState.subscription_email_log;
      const summary = data?.reminder_scan || null;
      const sentCount = Number(summary?.sent || 0);
      const eligibleCount = Number(summary?.eligible || 0);
      const checkedCount = Number(summary?.checked || 0);
      if (adminStatus) {
        adminStatus.textContent = testMode
          ? `Annual reminder test completed. ${sentCount} reminder${sentCount === 1 ? "" : "s"} sent from ${eligibleCount} eligible annual subscription${eligibleCount === 1 ? "" : "s"} checked among ${checkedCount} record${checkedCount === 1 ? "" : "s"}.`
          : `Annual reminder scan completed. ${sentCount} reminder${sentCount === 1 ? "" : "s"} sent from ${eligibleCount} eligible annual subscription${eligibleCount === 1 ? "" : "s"} checked among ${checkedCount} record${checkedCount === 1 ? "" : "s"}.`;
      }
      renderAdminView();
      if (subscriptionEmailAdminView && !subscriptionEmailAdminView.classList.contains("beginner-view-hidden")) {
        renderSubscriptionEmailTemplateSelection(activeSubscriptionEmailTemplateKey || "welcome");
      }
    } catch (error) {
      if (adminStatus) {
        adminStatus.textContent = testMode
          ? "Unable to send the annual reminder test right now."
          : "Unable to run the annual reminder scan right now.";
      }
    }
  }

  async function applyLauncherOpenRequest() {
      let directOpenRevealHandled = false;
      try {
        consumeLauncherStateWriteLock();
        consumePendingFreshStartAnonymousReset();
        const params = new URLSearchParams(window.location.search);
        const requestedView = String(params.get("open") || "").trim().toLowerCase();
        const requestedDifficultyLevel = normalizeDifficultyLevel(params.get("difficulty_level") || "");
        const requestedOwnIdentifier = String(params.get("own_email") || "").trim();
        const requestedPartnerIdentifier = String(params.get("partner_email") || "").trim();
        const requestedVisitorDisplayName = String(params.get("visitor_display_name") || "").trim();
        const directOpen = params.get("direct_open") === "1";
      const stripeReturnState = String(params.get("stripe") || "").trim().toLowerCase();
      const requestedReportReceiver = String(params.get("report_receiver") || "").trim();
      const requestedReportSender = String(params.get("report_sender") || "").trim();
      const requestedReportSessionCode = String(params.get("report_session_code") || "").trim();
      const requestedReportSource = String(params.get("report_source") || "").trim().toLowerCase() === "simulation" ? "simulation" : "real";
      const messageOwner = String(params.get("message_owner") || "").trim();
        const messagePartner = String(params.get("message_partner") || "").trim();
        const messageFocus = params.get("message_focus") === "1";
        appendGuidedReturnTrace("launcher_apply_open_request_start", {
          page_instance_id: launcherPageInstanceId,
          requestedView,
          directOpen,
          href: String(window.location.href || "").trim()
        });
        logLauncherDirectOpenDebug("apply_request_start", {
          requestedView,
          directOpen,
          href: String(window.location.href || "").trim()
        });
        let launcherState = clearStaleDeviceTestModeArtifactsIfNeeded(readLauncherState());
        launcherState = await sanitizeRecognizedIdentityForLauncherEntry(launcherState);
        logLauncherUserTypeDebug("apply_launcher_open_request", {
          requestedView,
          recognizedIdentity: String(launcherState?.recognizedIdentity || "").trim(),
          entryMode: String(launcherState?.entryMode || "").trim(),
          deviceTestMode: cloneJsonValue(launcherState?.deviceTestMode || null, null),
          loadedInviteeIdentifier: String(launcherState?.loadedInviteeIdentity?.identifier || "").trim(),
          hasRestoreSnapshotKey: hasDeviceTestRestoreSnapshot()
        });
        if (
          requestedVisitorDisplayName &&
          ["sender", "receiver"].includes(requestedView) &&
          isVisitorLauncherEntry(launcherState)
        ) {
          launcherState.visitorDisplayNames = launcherState.visitorDisplayNames || {};
          launcherState.visitorDisplayNames[requestedView] = requestedVisitorDisplayName;
          writeLauncherState(launcherState);
        }
        if (requestedDifficultyLevel) {
          launcherState.difficultyLevel = requestedDifficultyLevel;
          launcherState.roleDifficultyLevels = launcherState.roleDifficultyLevels || {};
          launcherState.roleDifficultyLevels.sender = requestedDifficultyLevel;
          launcherState.roleDifficultyLevels.receiver = requestedDifficultyLevel;
          writeLauncherState(launcherState);
          if (
            ["sender", "receiver"].includes(requestedView) &&
            requestedOwnIdentifier &&
            isRobotSimulationIdentifier(requestedPartnerIdentifier)
          ) {
            const preferredVisitorName = getPreferredVisitorDisplayNameForRole(
              requestedView,
              launcherState,
              requestedVisitorDisplayName
            );
            persistRobotSimulationDifficulty(
              requestedView,
              preferredVisitorName || requestedOwnIdentifier,
              requestedDifficultyLevel
            );
          }
          ["sender", "receiver", "remote-viewer"].forEach((role) => {
            setRoleDifficultyLabel(role, requestedDifficultyLevel);
          });
        }
      if (requestedView === "launcher") {
        void enterWorkingHomeFromLanding("resume");
        return;
      }
      if (requestedView === "fresh-launcher") {
        void enterWorkingHomeFromLanding("fresh");
        return;
      }
      if (requestedView === "visitor-launcher") {
        if (!isVisitorLauncherEntry(launcherState)) {
          if (hasKnownLauncherIdentity(launcherState)) {
            void enterWorkingHomeFromLanding("resume");
            return;
          }
          launcherState = buildVisitorLauncherState(launcherState);
          writeLauncherState(launcherState);
        }
        void enterWorkingHomeFromLanding("visitor");
        return;
      }
      if (requestedView === "go-pro") {
        showGoProView();
        return;
      }
      if (requestedView === "public-trial") {
        showTemporaryHomePageView();
        openExploreProOverlay();
        return;
      }
      if (requestedView === "landing-preview") {
        showTemporaryHomePageView();
        return;
      }
      if (requestedView === "explore-entry") {
        void resolveLandingExploreEntry();
        return;
      }
      if (requestedView === "landing") {
        if (hasKnownLauncherIdentity(launcherState) && !isVisitorLauncherEntry(launcherState)) {
          void enterWorkingHomeFromLanding("resume");
          return;
        }
        showTemporaryHomePageView();
        return;
      }
      if (requestedView === "baseline-questions") {
        showBaselineQuestionsView({ view: "online-course" });
        return;
      }
      if (requestedView === "after-first-session-questions") {
        showAfterFirstSessionQuestionsView({ view: "online-course" });
        return;
      }
      if (stripeReturnState === "success") {
        scheduleMainUserTypeRefresh(0);
        return;
      }
      if (stripeReturnState === "cancel") {
        return;
      }
      if (!requestedView && hasKnownLauncherIdentity(launcherState) && !isVisitorLauncherEntry(launcherState)) {
        void enterWorkingHomeFromLanding("resume");
        return;
      }
      if (requestedView === "settings") {
        showSettingsView();
        return;
      }
      if (requestedView === "report-definition") {
        pendingOpenReportPair = requestedReportReceiver && requestedReportSender
          ? {
              receiverName: requestedReportReceiver,
              senderName: requestedReportSender,
              sessionCode: requestedReportSessionCode,
              source: requestedReportSource
            }
          : null;
        showReportDefinitionView();
        return;
      }
      if (["sender", "receiver", "remote-viewer"].includes(requestedView)) {
        if (requestedView === "remote-viewer") {
          showClairvoyanceViewingView();
          return;
        } else {
          showLauncherView();
        }
        const matchingCard = findRoleCard(requestedView);
        if (matchingCard) {
          if (requestedView !== "remote-viewer") {
            const form = matchingCard.querySelector("[data-role-form]");
            const ownInput = form?.elements?.ownName || null;
            const partnerInput = form?.elements?.partnerName || null;
            if (ownInput && partnerInput) {
              const latestState = readLauncherState();
              const visitorMode = isVisitorLauncherEntry(latestState);
              const visibleOwnIdentifier = visitorMode && requestedVisitorDisplayName
                ? requestedVisitorDisplayName
                : requestedOwnIdentifier;
              if (visibleOwnIdentifier) {
                ownInput.value = visibleOwnIdentifier;
              }
              if (requestedPartnerIdentifier) {
                partnerInput.value = requestedPartnerIdentifier;
              }
              applyVisitorOwnInputLock(ownInput, getVisitorLockedName(latestState), visitorMode);
              void syncRoleIdentifierPresentation(requestedView, form);
            }
          }
          if (messageOwner || messagePartner) {
            if (requestedView === "remote-viewer") {
              if (messageOwner && remoteViewerOwnInput) {
                remoteViewerOwnInput.value = messageOwner;
              }
              if (messagePartner && remoteViewerPartnerInput) {
                remoteViewerPartnerInput.value = messagePartner;
              }
              persistRemoteViewerCardState();
            } else {
              const form = matchingCard.querySelector("[data-role-form]");
              if (form) {
                if (messageOwner && form.elements?.ownName) {
                  form.elements.ownName.value = messageOwner;
                }
                if (messagePartner && form.elements?.partnerName) {
                  form.elements.partnerName.value = messagePartner;
                }
                void persistLauncherProfileForForm(requestedView, form);
              }
            }
          }
          if (directOpen) {
            suppressLauncherAutoCollapseUntil = Date.now() + 1200;
            lastLauncherPointerDownInsideActiveCard = true;
            pendingDirectLauncherOutsideClickIgnore = true;
            lastDirectLauncherOpenMeta = {
              role: requestedView,
              openedAt: Date.now(),
              ownIdentifier: requestedOwnIdentifier,
              partnerIdentifier: requestedPartnerIdentifier,
              visitorDisplayName: requestedVisitorDisplayName,
              difficultyLevel: requestedDifficultyLevel || ""
            };
            appendGuidedReturnTrace("launcher_apply_direct_open", lastDirectLauncherOpenMeta);
            logLauncherDirectOpenDebug("apply", lastDirectLauncherOpenMeta);
            window.scrollTo({ top: 0, left: 0, behavior: "auto" });
            ensureCardExpanded(matchingCard, { scrollIntoView: false });
            appendGuidedReturnTrace("launcher_direct_open_card_expanded", {
              role: requestedView,
              difficultyLevel: requestedDifficultyLevel || "",
              activeRole: activeLauncherRole
            });
            logLauncherDirectOpenDebug("card_expanded", {
              role: requestedView,
              difficultyLevel: requestedDifficultyLevel || "",
              activeRole: activeLauncherRole,
              href: String(window.location.href || "").trim()
            });
            window.requestAnimationFrame(() => {
              if (!matchingCard.classList.contains("active")) {
                return;
              }
              alignLauncherCardNearTop(matchingCard, 18);
              window.setTimeout(() => {
                if (matchingCard.classList.contains("active")) {
                  alignLauncherCardNearTop(matchingCard, 18);
                }
                if (!directOpenRevealHandled) {
                  directOpenRevealHandled = true;
                  appendGuidedReturnTrace("launcher_direct_open_reveal_after_align", {
                    role: requestedView,
                    difficultyLevel: requestedDifficultyLevel || ""
                  });
                  logLauncherDirectOpenDebug("reveal_after_align", {
                    role: requestedView,
                    difficultyLevel: requestedDifficultyLevel || "",
                    href: String(window.location.href || "").trim(),
                    scrollY: Number(window.scrollY || 0)
                  });
                  finishDirectLauncherOpen(0);
                }
              }, 80);
            });
          } else {
            ensureCardExpanded(matchingCard, { scrollIntoView: true });
          }
          if (messageFocus) {
            void openMessagesViewForRole(requestedView, {
              ownerIdentifier: messageOwner || "",
              partnerIdentifier: messagePartner || ""
            });
          }
        }
      }
    } catch (error) {
      appendGuidedReturnTrace("launcher_apply_open_request_error", {
        page_instance_id: launcherPageInstanceId,
        message: String(error?.message || error || "").trim()
      });
      logLauncherDirectOpenDebug("apply_request_error", {
        message: String(error?.message || error || "").trim()
      });
    } finally {
      const directOpenInfo = (function () {
        try {
          const params = new URLSearchParams(window.location.search);
          return {
            requested: params.get("direct_open") === "1",
            role: String(params.get("open") || "").trim().toLowerCase()
          };
        } catch (error) {
          return {
            requested: false,
            role: ""
          };
        }
      })();
      const directOpenDelayMs = directOpenRevealHandled
        ? 0
        : directOpenInfo.requested
        ? directOpenInfo.role === "sender"
          ? 700
          : 500
        : 0;
      appendGuidedReturnTrace("launcher_apply_open_request_finally", {
        page_instance_id: launcherPageInstanceId,
        directOpenRequested: !!directOpenInfo.requested,
        directOpenRole: String(directOpenInfo.role || "").trim(),
        directOpenRevealHandled: !!directOpenRevealHandled,
        directOpenDelayMs
      });
      logLauncherDirectOpenDebug("apply_request_finally", {
        directOpenRequested: !!directOpenInfo.requested,
        directOpenRole: String(directOpenInfo.role || "").trim(),
        directOpenRevealHandled: !!directOpenRevealHandled,
        directOpenDelayMs
      });
      finishDirectLauncherOpen(directOpenDelayMs);
    }
  }

  async function saveUserTypeAuthEmail() {
    const handle = currentUserTypeAdminHandle || String(userTypeHandleInput?.value || "").trim();
    const email = String(userTypeEmailInput?.value || "").trim();
    const selectedType = pendingUserTypeSelection || "standard";

    if (!isValidParticipantIdentifier(handle)) {
      renderUserTypeAdminState({
        statusText: "That identifier is invalid.",
        showChoices: false,
        showInviteeButton: false,
        showEmailUpdate: false,
        authEmail: "",
        currentType: "standard"
      });
      return;
    }

    renderUserTypeAdminState({
      statusText: "Updating authentication email...",
      showChoices: true,
      showInviteeButton: false,
      showEmailUpdate: true,
      authEmail: email,
      currentType: selectedType
    });

    try {
      const result = await updateUserAuthEmail(handle, email);
      currentUserTypeAdminHandle = handle;
      renderUserTypeAdminState({
        statusText: `Authentication email updated for ${handle}.`,
        showChoices: true,
        showInviteeButton: false,
        showEmailUpdate: true,
        authEmail: result.email,
        currentType: result.userType
      });
    } catch (error) {
      renderUserTypeAdminState({
        statusText: error instanceof Error ? error.message : "Unable to update that authentication email right now.",
        showChoices: true,
        showInviteeButton: false,
        showEmailUpdate: true,
        authEmail: email,
        currentType: selectedType
      });
    }
  }

