  function encodeCsvCell(value) {
    const text = value === null || value === undefined ? "" : String(value);
    return `"${text.replace(/"/g, "\"\"").replace(/\r?\n/g, " ")}"`;
  }

  function countWords(text) {
    const trimmed = String(text || "").trim();
    if (!trimmed) {
      return 0;
    }
    return trimmed.split(/\s+/).filter(Boolean).length;
  }

  function readFileAsDataUrl(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result || ""));
      reader.onerror = () => reject(new Error(`Unable to read ${file?.name || "the selected file"}.`));
      reader.readAsDataURL(file);
    });
  }

  function buildContactMessageMeta() {
    const pair = getCurrentPairParticipants();
    const ownNames = collectReportOwnNames();
    const location = readLauncherState().deviceLocation;
    return {
      pair,
      ownNames,
      location
    };
  }

  async function sendContactMessage(messageText, senderEmail) {
    const meta = buildContactMessageMeta();
    const cleanSenderEmail = assertValidEmailIdentifier(senderEmail, "Your email");
    const currentUserIdentifier = getCurrentContactIdentifier(meta);
    const response = await fetch("api.php", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        action: "send_contact_message",
        message: String(messageText || ""),
        metadata: {
          app: "Telepathy Beginner",
          build_version: launcherBuildVersion,
          sender_email: cleanSenderEmail,
          current_user_identifier: currentUserIdentifier,
          allow_display_on_comments_page: !!contactAllowDisplayCheckbox?.checked,
          own_names: meta.ownNames,
          pair: meta.pair,
          location: meta.location
        }
      })
    });

    return parseApiResponse(response, `Contact request failed with status ${response.status}`);
  }

  function renderContactWordCount() {
    if (!contactWordCount) {
      return;
    }
    const words = countWords(contactMessageInput?.value || "");
    contactWordCount.textContent = `${words} / 300 words`;
    contactWordCount.classList.toggle("is-over-limit", words > 300);
  }

  function getCurrentContactIdentifier(meta = buildContactMessageMeta()) {
    const state = readLauncherState();
    const activeRole = ["sender", "receiver", "remote-viewer"].includes(activeLauncherRole)
      ? activeLauncherRole
      : "";
    const activeOwnName = activeRole ? String(readVisibleRoleIdentifiers(activeRole).ownName || "").trim() : "";
    const ownNames = Array.isArray(meta?.ownNames) ? meta.ownNames : [];
    const preferred = uniqueNames([
      activeOwnName,
      ...getCurrentUserTypeCandidates(),
      ...ownNames,
      String(state.ownNames?.sender || "").trim(),
      String(state.ownNames?.receiver || "").trim(),
      String(state.ownNames?.["remote-viewer"] || "").trim()
    ])[0] || "";
    return preferred ? getPreferredIdentifier(preferred, state) : "";
  }

  function isAcceptedContactIdentifier(identifier, status = null) {
    const raw = String(identifier || "").trim();
    if (!raw) {
      return false;
    }
    if (isValidEmailAddress(raw)) {
      return true;
    }
    return isAcceptedUniqueHandleIdentifier(raw, status);
  }

  async function renderContactFromLine() {
    if (!contactFromLine) {
      return;
    }
    const requestToken = ++contactFromLineRequestToken;
    const identifier = String(getCurrentContactIdentifier() || "").trim();
    const hideLine = () => {
      contactFromLine.hidden = true;
      contactFromLine.textContent = "";
    };
    if (!identifier) {
      hideLine();
      return;
    }

    const cachedStatus = getCachedIdentifierStatus(identifier);
    if (isAcceptedContactIdentifier(identifier, cachedStatus)) {
      if (requestToken !== contactFromLineRequestToken) {
        return;
      }
      const displayIdentifier = String(cachedStatus.preferred_identifier || identifier).trim() || identifier;
      contactFromLine.hidden = false;
      contactFromLine.textContent = `Message from ${displayIdentifier}`;
      return;
    }

    hideLine();
    try {
      const status = await fetchIdentifierStatus(identifier);
      if (requestToken !== contactFromLineRequestToken) {
        return;
      }
      if (status) {
        rememberIdentifierStatus(identifier, status);
      }
      if (!isAcceptedContactIdentifier(identifier, status)) {
        hideLine();
        return;
      }
      const displayIdentifier = String(status.preferred_identifier || identifier).trim() || identifier;
      contactFromLine.hidden = false;
      contactFromLine.textContent = `Message from ${displayIdentifier}`;
    } catch (_error) {
      if (requestToken !== contactFromLineRequestToken) {
        return;
      }
      hideLine();
    }
  }

  function resetContactView(options = {}) {
    const clearMessage = options.clearMessage !== false;
    const clearEmail = options.clearEmail !== false;
    const clearStatus = options.clearStatus !== false;
    if (clearMessage && contactMessageInput) {
      contactMessageInput.value = "";
    }
    if (clearEmail && contactEmailInput) {
      contactEmailInput.value = "";
    }
    if (contactAllowDisplayCheckbox) {
      contactAllowDisplayCheckbox.checked = false;
    }
    if (clearStatus && contactStatus) {
      contactStatus.textContent = "";
    }
    if (contactSendButton) {
      contactSendButton.disabled = false;
    }
    renderContactFromLine();
    renderContactWordCount();
  }

  function getStoredReceiverTrialRecords() {
    try {
      const raw = localStorage.getItem("cones-local-trials-receiver");
      const parsed = raw ? JSON.parse(raw) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }

  async function downloadSettingsCsvData() {
    try {
      const desiredName = String(settingsImportFilenameInput?.value || "").trim();
      if (desiredName) {
        const matchedAdminSecret = await checkAdminSecret(desiredName);
        if (matchedAdminSecret) {
          launcherAdminSecret = desiredName;
          if (launcherAdminDevicePrefs.easy_admin_enabled || launcherAdminDevicePrefs.learn_more_save_enabled) {
            updateLauncherAdminDevicePrefs({
              cached_secret: desiredName
            });
          }
          writeRuntimeSettings("receiver", {
            import_csv_filename: ""
          });
          if (settingsImportFilenameInput) {
            settingsImportFilenameInput.value = "";
          }
          if (settingsStatus) {
            settingsStatus.textContent = "";
            settingsStatus.dataset.persistedMessage = "";
          }
          showAdminView();
          return;
        }
      }

      if (!desiredName) {
        if (hasLauncherAdminAccess()) {
          if (settingsStatus) {
            settingsStatus.textContent = "";
            settingsStatus.dataset.persistedMessage = "";
          }
          showAdminView();
          return;
        }
      }

      if (settingsStatus) {
        settingsStatus.textContent = "Preparing CSV download...";
        settingsStatus.dataset.persistedMessage = settingsStatus.textContent;
      }

      const csvResult = await fetchReportCsvData();
      const records = Array.isArray(csvResult.records) ? csvResult.records : [];
      if (!records.length) {
        if (settingsStatus) {
          settingsStatus.textContent = "No CSV records are available to download right now.";
          settingsStatus.dataset.persistedMessage = settingsStatus.textContent;
        }
        return;
      }

      if (!desiredName) {
        if (settingsStatus) {
          settingsStatus.textContent = "Please provide a CSV data filename.";
          settingsStatus.dataset.persistedMessage = settingsStatus.textContent;
        }
        settingsImportFilenameInput?.focus();
        return;
      }

      const locationHidden = isLocationPrivacyDisabled();
      const sanitizedRecords = locationHidden
        ? records.map((record) => {
            const next = { ...record };
            if (Object.prototype.hasOwnProperty.call(next, "rx location")) {
              next["rx location"] = "";
            }
            if (Object.prototype.hasOwnProperty.call(next, "tx location")) {
              next["tx location"] = "";
            }
            if (Object.prototype.hasOwnProperty.call(next, "dist")) {
              next.dist = "";
            }
            if (Object.prototype.hasOwnProperty.call(next, "distance")) {
              next.distance = "";
            }
            return next;
          })
        : records;

      const header = Object.keys(sanitizedRecords[0]);
      const lines = [
        header.map(encodeCsvCell).join(","),
        ...sanitizedRecords.map((record) => header.map((key) => encodeCsvCell(record[key])).join(","))
      ];
      const csv = `${lines.join("\n")}\n`;
      const fileName = desiredName
        ? (desiredName.toLowerCase().endsWith(".csv") ? desiredName : `${desiredName}.csv`)
        : "cones-trials-download.csv";
      const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.setTimeout(() => URL.revokeObjectURL(url), 1000);

      writeRuntimeSettings("receiver", {
        import_csv_filename: desiredName
      });

      if (settingsStatus) {
        settingsStatus.textContent = `CSV download started as ${fileName}.`;
        settingsStatus.dataset.persistedMessage = settingsStatus.textContent;
      }
    } catch (error) {
      if (settingsStatus) {
        settingsStatus.textContent = "Unable to prepare the CSV download right now.";
        settingsStatus.dataset.persistedMessage = settingsStatus.textContent;
      }
    }
  }

  async function handleContactSend() {
    const messageText = String(contactMessageInput?.value || "").trim();
    const senderEmail = String(contactEmailInput?.value || "").trim();
    const wordCount = countWords(messageText);

    if (contactStatus) {
      contactStatus.textContent = "";
    }

    if (!messageText) {
      if (contactStatus) {
        contactStatus.textContent = "Please write a message before sending.";
      }
      contactMessageInput?.focus();
      return;
    }

    if (!senderEmail) {
      if (contactStatus) {
        contactStatus.textContent = "Please provide your email address.";
      }
      contactEmailInput?.focus();
      return;
    }

    if (wordCount > 300) {
      if (contactStatus) {
        contactStatus.textContent = "Please reduce your message to 300 words or fewer.";
      }
      contactMessageInput?.focus();
      return;
    }

    if (contactSendButton) {
      contactSendButton.disabled = true;
    }
    if (contactStatus) {
      contactStatus.textContent = "Sending your message...";
    }

    try {
      await sendContactMessage(messageText, senderEmail);
      if (contactStatus) {
        contactStatus.textContent = "Thank you. Your messages was sent to ESP Gym, and a copy sent to you for your records.";
      }
      if (contactMessageInput) {
        contactMessageInput.value = "";
      }
      if (contactEmailInput) {
        contactEmailInput.value = "";
      }
      if (contactAllowDisplayCheckbox) {
        contactAllowDisplayCheckbox.checked = false;
      }
      renderContactWordCount();
    } catch (error) {
      if (contactStatus) {
        contactStatus.textContent = error instanceof Error
          ? error.message
          : "Unable to send your message right now.";
      }
    } finally {
      if (contactSendButton) {
        contactSendButton.disabled = false;
      }
    }
  }

  function showInstallFallback() {
    window.alert(
      "If your device supports app installation, use the browser's install or Add to Home Screen option to install Telepathy Beginner."
    );
  }

  function getBrowserShellMode() {
    return (
      window.matchMedia?.("(display-mode: standalone)").matches ||
      window.navigator.standalone === true
    ) ? "standalone-shell" : "browser-tab";
  }

  function isStandaloneShell() {
    return getBrowserShellMode() === "standalone-shell";
  }

  function getInstallConfirmationState(state = readLauncherState()) {
    const installState = getInstallState(state);
    if (installState.confirmed) {
      return "confirmed-installed";
    }
    if (isStandaloneShell()) {
      return "temporary-shell";
    }
    return "unknown";
  }

  function isDurablyInstalled(state = readLauncherState()) {
    return getInstallConfirmationState(state) === "confirmed-installed";
  }

  function recordInstalledConfirmation(source = "appinstalled-event") {
    const latest = readLauncherState();
    const installState = getInstallState(latest);
    installState.confirmed = true;
    installState.confirmedAt = Date.now();
    installState.confirmationSource = String(source || "appinstalled-event").trim() || "appinstalled-event";
    installState.lastShellMode = getBrowserShellMode();
    installState.lastSeenAt = Date.now();
    latest.installState = installState;
    writeLauncherState(latest);
    return latest;
  }

  function recordInstallGuidanceShown(platform = "") {
    const latest = readLauncherState();
    const installState = getInstallState(latest);
    installState.installGuidanceShownAt = Date.now();
    installState.installGuidancePlatform = String(platform || "").trim();
    installState.lastShellMode = getBrowserShellMode();
    installState.lastSeenAt = Date.now();
    latest.installState = installState;
    writeLauncherState(latest);
    return latest;
  }

  function clearInstalledConfirmation(source = "install-check") {
    const latest = readLauncherState();
    const installState = getInstallState(latest);
    let changed = false;
    if (installState.confirmed) {
      installState.confirmed = false;
      changed = true;
    }
    if (installState.confirmedAt !== 0) {
      installState.confirmedAt = 0;
      changed = true;
    }
    const nextSource = String(source || "install-check").trim() || "install-check";
    if (installState.confirmationSource !== nextSource) {
      installState.confirmationSource = nextSource;
      changed = true;
    }
    installState.lastShellMode = getBrowserShellMode();
    installState.lastSeenAt = Date.now();
    latest.installState = installState;
    if (changed) {
      writeLauncherState(latest);
    }
    return latest;
  }

  function refreshObservedInstallContext(state = readLauncherState()) {
    const latest = state && typeof state === "object" ? state : readLauncherState();
    const installState = getInstallState(latest);
    const browser = detectMobileBrowser();
    const shellMode = getBrowserShellMode();
    let changed = installState.lastShellMode !== shellMode;
    installState.lastShellMode = shellMode;
    const now = Date.now();
    if (installState.lastSeenAt !== now) {
      installState.lastSeenAt = now;
      changed = true;
    }
    if (
      !installState.confirmed &&
      browser.isSafariIOS &&
      shellMode === "standalone-shell" &&
      installState.installGuidanceShownAt > 0
    ) {
      installState.confirmed = true;
      installState.confirmedAt = now;
      installState.confirmationSource = "ios-standalone-return";
      changed = true;
    }
    if (
      !installState.confirmed &&
      shellMode === "standalone-shell" &&
      hasKnownLauncherIdentity(latest)
    ) {
      installState.confirmed = true;
      installState.confirmedAt = now;
      installState.confirmationSource = "standalone-recovery";
      changed = true;
    }
    latest.installState = installState;
    if (changed) {
      writeLauncherState(latest);
    }
    return latest;
  }

  function isRunningAsInstalledApp() {
    return isDurablyInstalled();
  }

  function updateInstallButtonLabel() {
    if (!installAppButton) {
      return;
    }

    const confirmationState = getInstallConfirmationState();
    if (confirmationState === "confirmed-installed") {
      installAppButton.textContent = "Uninstall Telepathy Beginner as an app on this device";
      installAppButton.title = "Telepathy Beginner appears to be installed on this device.";
      return;
    }

    if (confirmationState === "temporary-shell") {
      installAppButton.textContent = "Install Telepathy Beginner permanently on this device";
      installAppButton.title = "ESP GYM is open in app mode temporarily, but it has not yet been confirmed as permanently installed on this device.";
      return;
    }

    installAppButton.textContent = "Install Telepathy Beginner as an app on this device";
    installAppButton.title = "As an app, it does not work inside a browser tab, but acts just like a regular app with its own icon.";
  }

  function detectMobileBrowser() {
    const ua = navigator.userAgent || "";
    const vendor = navigator.vendor || "";
    const isIOS = /iPhone|iPad|iPod/i.test(ua);
    const isChromeIOS = /CriOS/i.test(ua);
    const isSafariIOS = isIOS && /Safari/i.test(ua) && /Apple/i.test(vendor) && !isChromeIOS;

    return {
      isIOS,
      isChromeIOS,
      isSafariIOS
    };
  }

  async function handleInstallRequest() {
    const browser = detectMobileBrowser();

    if (browser.isSafariIOS) {
      recordInstallGuidanceShown("ios-safari");
      window.alert(
        "On iPhone Safari, use Share and then Add to Home Screen to install Telepathy Beginner."
      );
      return;
    }

    if (browser.isChromeIOS) {
      recordInstallGuidanceShown("ios-chrome");
      window.alert(
        "Chrome on iPhone may not show Add to Home Screen reliably. If it is missing, open this page in Safari and use Share -> Add to Home Screen."
      );
      return;
    }

    if (!deferredInstallPrompt) {
      recordInstallGuidanceShown(browser.isIOS ? "ios" : "generic");
      showInstallFallback();
      return;
    }

    recordInstallGuidanceShown("beforeinstallprompt");
    deferredInstallPrompt.prompt();
    try {
      await deferredInstallPrompt.userChoice;
    } catch (error) {
      // Ignore prompt rejection and leave fallback to the browser UI.
    }
    deferredInstallPrompt = null;
  }

  roleCards.forEach((card) => {
    populateCard(card);
    const header = card.querySelector(".role-card-header");
    const toggle = card.querySelector(".role-card-toggle");
    const inlineBack = card.querySelector("[data-collapse-role-card]");
    const role = String(card.dataset.roleCard || "").trim();
    card.addEventListener("click", (event) => {
      event.stopPropagation();
    });
    toggle?.addEventListener("click", () => {
      activateCard(card);
    });
    toggle?.addEventListener("mouseenter", () => {
      if (role) {
        clearRoleLevelExplanation(role);
      }
    });
    toggle?.addEventListener("focusin", () => {
      if (role) {
        clearRoleLevelExplanation(role);
      }
    });
    header?.addEventListener("click", (event) => {
      if (isLauncherInteractiveTarget(event.target)) {
        return;
      }
      activateCard(card);
    });
    inlineBack?.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      collapseActiveLauncherCard();
    });
  });

